  LOG_ID         NUMBER,
  PHONE_NUMBER   VARCHAR2(20 BYTE),
  MESSAGE_TEXT   VARCHAR2(2000 BYTE),
  SEND_DATE      DATE                           DEFAULT SYSDATE,
  STATUS         VARCHAR2(50 BYTE),
  RESPONSE_TEXT  VARCHAR2(4000 BYTE)
)
TABLESPACE USERS
PCTUSED    0
PCTFREE    10
INITRANS   1
MAXTRANS   255
STORAGE    (
            INITIAL          64K
            MINEXTENTS       1
            MAXEXTENTS       UNLIMITED
            PCTINCREASE      0
            BUFFER_POOL      DEFAULT
           )
LOGGING 
NOCOMPRESS 
NOCACHE
NOPARALLEL
MONITORING;


DROP TABLE ACCOUNTS.GARD2026 CASCADE CONSTRAINTS PURGE;

CREATE TABLE ACCOUNTS.GARD2026
(
  SANF_NO       NUMBER,
  PART_NO       NUMBER,
  STYLE_NO      NUMBER,
  SANF_DNO      NUMBER,
  SANF_NAME     VARCHAR2(100 BYTE),
  CATEGORY      VARCHAR2(30 BYTE),
  UNIT          VARCHAR2(30 BYTE),
  CURRENCY      NUMBER,
  W_PRICE_R     NUMBER,
  W_PRICE_D     NUMBER,
  Q1            NUMBER,
  Q2            NUMBER,
  W_AMOUNT_H    NUMBER,
  AMOUNT        NUMBER,
  REFILL        NUMBER,
  PRICE         NUMBER,
  T_PRICE       NUMBER,
  ACTUAL_PRICE  NUMBER,
  T_PRICE_R     NUMBER,
  T_PRICE_D     NUMBER,
  NOTES         VARCHAR2(50 BYTE)
)
TABLESPACE USERS
PCTUSED    0
PCTFREE    10
INITRANS   1
MAXTRANS   255
STORAGE    (
            INITIAL          64K
            MINEXTENTS       1
            MAXEXTENTS       UNLIMITED
            PCTINCREASE      0
            BUFFER_POOL      DEFAULT
           )
LOGGING 
NOCOMPRESS 
NOCACHE
NOPARALLEL
MONITORING;


ALTER TABLE ACCOUNTS.BANK_BOX
 DROP PRIMARY KEY CASCADE;
DROP TABLE ACCOUNTS.BANK_BOX CASCADE CONSTRAINTS PURGE;

CREATE TABLE ACCOUNTS.BANK_BOX
(
  B_ID       NUMBER,
  B_TYPE     NUMBER,
  B_NAME     VARCHAR2(500 BYTE),
  NOTES      VARCHAR2(200 BYTE),
  ACC_ID     NUMBER,
  B_MAN      VARCHAR2(500 CHAR),
  COSTCN_ID  NUMBER,
  CURR_ID    NUMBER
)
TABLESPACE USERS
PCTUSED    0
PCTFREE    10
INITRANS   1
MAXTRANS   255
STORAGE    (
            INITIAL          64K
            MINEXTENTS       1
            MAXEXTENTS       UNLIMITED
            PCTINCREASE      0
            BUFFER_POOL      DEFAULT
           )
LOGGING 
NOCOMPRESS 
NOCACHE
NOPARALLEL
MONITORING;

