DROP PACKAGE BODY ACCOUNTS.CONVERT_NUMBER;

CREATE OR REPLACE PACKAGE BODY ACCOUNTS.convert_number
AS
  FUNCTION get_possion (i IN NUMBER)
     RETURN NUMBER
  IS
     p   NUMBER;
  BEGIN
     p := i MOD 3;

     IF p = 2
     THEN
        p := -1;
     END IF;

     RETURN p;
  END;

  FUNCTION get_text (num IN VARCHAR2)
     RETURN VARCHAR2
  IS
     n                VARCHAR2 (20);
     text             VARCHAR2 (20);
     number_in_text   VARCHAR2 (2000);
     CATEGORY         VARCHAR2 (20);
     follow           VARCHAR2 (2);
     t                VARCHAR2 (20);
     /* the number string in the new order */
     l                NUMBER;                    /* the length of number  */
     m                NUMBER          := 0;
     /* the addition number so l can be devided by 3 */
     loop_counter     NUMBER;
  BEGIN
     l := LENGTH (num);

     IF l MOD 3 = 1
     THEN
        m := 2;
     ELSIF l MOD 3 = 2
     THEN
        m := 1;
     END IF;

     n := LPAD (num, l + m, 0);

     FOR loop_counter IN 1 .. l + m
     LOOP
        t :=
           t || SUBSTR (n, loop_counter + get_possion (loop_counter - 1), 1);
     END LOOP;

     FOR loop_counter IN REVERSE 1 .. l + m
     LOOP
        IF SUBSTR (t, loop_counter, 1) <> '0'
        THEN
           IF get_possion (loop_counter) = -1
           THEN
              IF     SUBSTR (t, loop_counter, 1) = '1'
                 AND SUBSTR (t, loop_counter + 1, 1) = '1'
              THEN
                 text := 'ĹÍĎě ';
              ELSIF     SUBSTR (t, loop_counter, 1) = '1'
                    AND (l = 4 AND loop_counter <> 2)
              THEN
                 text := 'ćÇÍĎ ';
              ELSIF SUBSTR (t, loop_counter, 1) = '1' AND l <> 4
              THEN
                 text := 'ćÇÍĎ ';
              ELSIF     SUBSTR (t, loop_counter, 1) = '2'
                    AND SUBSTR (t, loop_counter + 1, 1) = '1'
              THEN
                 text := 'ÇËäÇ ';
              ELSIF     SUBSTR (t, loop_counter, 1) = '2'
                    AND (l = 4 AND loop_counter <> 2)
              THEN
                 text := 'ÇËäíä ';
              ELSIF SUBSTR (t, loop_counter, 1) = '2' AND l <> 4
              THEN
                 text := 'ÇËäíä ';
              ELSIF SUBSTR (t, loop_counter, 1) = '3'
              THEN
                 text := 'ËáÇËÉ ';
              ELSIF SUBSTR (t, loop_counter, 1) = '4'
              THEN
                 text := 'ÇŃČÚÉ ';
              ELSIF SUBSTR (t, loop_counter, 1) = '5'
              THEN
                 text := 'ÎăÓÉ ';
              ELSIF SUBSTR (t, loop_counter, 1) = '6'
              THEN
                 text := 'ÓĘÉ ';
              ELSIF SUBSTR (t, loop_counter, 1) = '7'
              THEN
                 text := 'ÓČÚÉ ';
              ELSIF SUBSTR (t, loop_counter, 1) = '8'
              THEN
                 text := 'ËăÇäíÉ ';
              ELSIF SUBSTR (t, loop_counter, 1) = '9'
              THEN
                 text := 'ĘÓÚÉ ';
              END IF;
           ELSIF get_possion (loop_counter) = 0
           THEN
              IF     SUBSTR (t, loop_counter, 1) = '1'
                 AND SUBSTR (t, loop_counter - 1, 1) = '0'
              THEN
                 text := 'ÚÔŃÉ ';
              ELSIF SUBSTR (t, loop_counter, 1) = '1'
              THEN
                 text := 'ÚÔŃ ';
              ELSIF SUBSTR (t, loop_counter, 1) = '2'
              THEN
                 text := 'ÚÔŃćä ';
              ELSIF SUBSTR (t, loop_counter, 1) = '3'
              THEN
                 text := 'ËáÇËćä ';
              ELSIF SUBSTR (t, loop_counter, 1) = '4'
              THEN
                 text := 'ÇŃČÚćä ';
              ELSIF SUBSTR (t, loop_counter, 1) = '5'
              THEN
                 text := 'ÎăÓćä ';
              ELSIF SUBSTR (t, loop_counter, 1) = '6'
              THEN
                 text := 'ÓĘćä ';
              ELSIF SUBSTR (t, loop_counter, 1) = '7'
              THEN
                 text := 'ÓČÚćä ';
              ELSIF SUBSTR (t, loop_counter, 1) = '8'
              THEN
                 text := 'ËăÇäćä ';
              ELSIF SUBSTR (t, loop_counter, 1) = '9'
              THEN
                 text := 'ĘÓÚćä ';
              END IF;
           ELSIF get_possion (loop_counter) = 1
           THEN
              IF SUBSTR (t, loop_counter, 1) = '1'
              THEN
                 text := 'ăÇĆÉ ';
              ELSIF SUBSTR (t, loop_counter, 1) = '2'
              THEN
                 text := 'ăÇĆĘíä ';
              ELSIF SUBSTR (t, loop_counter, 1) = '3'
              THEN
                 text := 'ËáÇËăÇĆÉ ';
              ELSIF SUBSTR (t, loop_counter, 1) = '4'
              THEN
                 text := 'ÇŃČÚăÇĆÉ ';
              ELSIF SUBSTR (t, loop_counter, 1) = '5'
              THEN
                 text := 'ÎăÓăÇĆÉ ';
              ELSIF SUBSTR (t, loop_counter, 1) = '6'
              THEN
                 text := 'ÓĘăÇĆÉ ';
              ELSIF SUBSTR (t, loop_counter, 1) = '7'
              THEN
                 text := 'ÓČÚăÇĆÉ ';
              ELSIF SUBSTR (t, loop_counter, 1) = '8'
              THEN
                 text := 'ËăÇäăÇĆÉ ';
              ELSIF SUBSTR (t, loop_counter, 1) = '9'
              THEN
                 text := 'ĘÓÚăÇĆÉ ';
              END IF;
           END IF;
        END IF;

        IF    loop_counter = 1
           OR (SUBSTR (t, loop_counter, 1) = '0')
           OR (loop_counter = 2 AND SUBSTR (t, loop_counter - 1, 1) = '0')
           OR (loop_counter = 3 AND SUBSTR (t, loop_counter - 2, 2) = '00')
           OR (    get_possion (loop_counter) = 0
               AND SUBSTR (n, loop_counter - 1, 1) = 1
              )
        THEN
           follow := '';
        ELSE
           follow := 'ć ';
        END IF;

        IF SUBSTR (n, loop_counter - 3, 3) <> '000'
        THEN
           IF (l + m - loop_counter = 11 AND l > 12)
           THEN
              CATEGORY := 'ČáíÇŃ ';
           ELSIF (l + m - loop_counter = 8 AND l > 9)
           THEN
              CATEGORY := 'Čáíćä ';
           ELSIF (l + m - loop_counter = 5 AND l > 6)
           THEN
              CATEGORY := 'ăáíćä ';
           ELSIF (l + m - loop_counter = 2 AND l = 4
                  AND SUBSTR (n, 3, 1) = '2'
                 )
           THEN
              CATEGORY := 'ÇáÝíä ';
           ELSIF (    l + m - loop_counter = 2
                  AND l = 4
                  AND SUBSTR (n, 3, 1) NOT IN ('1', '2')
                 )
           THEN
              CATEGORY := 'ÇáÇÝ ';
           ELSIF (l + m - loop_counter = 2 AND l = 5
                  AND SUBSTR (n, 2, 2) = '10'
                 )
           THEN
              CATEGORY := 'ÇáÇÝ ';
           ELSIF (l + m - loop_counter = 2 AND l > 3)
           THEN
              CATEGORY := ' ÇáÝ ';
           END IF;
        END IF;

        number_in_text := CATEGORY || follow || text || number_in_text;
        CATEGORY := '';
        text := '';
     END LOOP;

     RETURN number_in_text;
  END;

  FUNCTION to_text (num IN VARCHAR2)
     RETURN VARCHAR2
  IS
     str   VARCHAR2 (10000);
  BEGIN
     str := get_text (TRUNC (num));
     RETURN str;
  END;

  FUNCTION to_text (num IN VARCHAR2, cur IN VARCHAR2)
     RETURN VARCHAR2
  IS
     str            VARCHAR2 (10000);
     integer_v      NUMBER;
     integer_str    VARCHAR2 (10000);
     integer_cur    VARCHAR2 (10000);
     fraction_v     NUMBER;
     fraction_str   VARCHAR2 (10000);
     fraction_cur   VARCHAR2 (10000);
  BEGIN
     integer_v := TRUNC (num);
     fraction_v := (ROUND (num, 2) - TRUNC (num)) * 100;

select MAIN_CUR_NAME,SUB_CUR_NAME into integer_cur,fraction_cur from CUR_CODE where CODE=CUR ;


     IF integer_v = 0
     THEN
        integer_str := TO_CHAR (NULL);
     ELSE
        integer_str := get_text (integer_v) || integer_cur;
     END IF;

     IF fraction_v = 0
     THEN
        fraction_str := TO_CHAR (NULL);
     ELSE
        IF integer_v = 0
        THEN
           fraction_str := get_text (fraction_v) || fraction_cur;
        ELSE
           fraction_str := ' ć ' || get_text (fraction_v) || fraction_cur;
        END IF;
     END IF;

     str := integer_str || ' ' || fraction_str;
     RETURN str ;
  END;
END convert_number;
/

SHOW ERRORS;


DROP PACKAGE BODY ACCOUNTS.SERVICES_TAPI;

CREATE OR REPLACE PACKAGE BODY ACCOUNTS.SERVICES_TAPI IS

  PROCEDURE INS_SERVICES
    (
     P_SERVICE_ID   IN SERVICES.SERVICE_ID%TYPE
    ,P_SERVICE_TYPE IN SERVICES.SERVICE_TYPE%TYPE
    ,P_CREATED_AT   IN SERVICES.CREATED_AT%TYPE
    ,P_CREATED_BY   IN SERVICES.CREATED_BY%TYPE
    ,P_UPDATED_AT   IN SERVICES.UPDATED_AT%TYPE
    ,P_UPDATED_BY   IN SERVICES.UPDATED_BY%TYPE
    ,P_SERVICE_NAME IN SERVICES.SERVICE_NAME%TYPE
    ) IS
  BEGIN
    INSERT INTO SERVICES
      (
       SERVICE_ID
      ,SERVICE_TYPE
      ,CREATED_AT
      ,CREATED_BY
      ,UPDATED_AT
      ,UPDATED_BY
      ,SERVICE_NAME
      )
    VALUES
      (
       P_SERVICE_ID
      ,P_SERVICE_TYPE
      ,P_CREATED_AT
      ,P_CREATED_BY
      ,P_UPDATED_AT
      ,P_UPDATED_BY
      ,P_SERVICE_NAME
      );
  END INS_SERVICES;

  PROCEDURE MERGE_SERVICES
    (
     P_SERVICE_ID   IN SERVICES.SERVICE_ID%TYPE
    ,P_SERVICE_TYPE IN SERVICES.SERVICE_TYPE%TYPE
    ,P_CREATED_AT   IN SERVICES.CREATED_AT%TYPE
    ,P_CREATED_BY   IN SERVICES.CREATED_BY%TYPE
    ,P_UPDATED_AT   IN SERVICES.UPDATED_AT%TYPE
    ,P_UPDATED_BY   IN SERVICES.UPDATED_BY%TYPE
    ,P_SERVICE_NAME IN SERVICES.SERVICE_NAME%TYPE
    ) IS
  BEGIN
    MERGE INTO SERVICES A USING
      (SELECT
       P_SERVICE_ID as SERVICE_ID
      ,P_SERVICE_TYPE as SERVICE_TYPE
      ,P_CREATED_AT as CREATED_AT
      ,P_CREATED_BY as CREATED_BY
      ,P_UPDATED_AT as UPDATED_AT
      ,P_UPDATED_BY as UPDATED_BY
      ,P_SERVICE_NAME as SERVICE_NAME
      FROM DUAL) B
    ON (A.SERVICE_ID= B.SERVICE_ID)
    WHEN NOT MATCHED THEN
      INSERT (
       SERVICE_ID
      ,SERVICE_TYPE
      ,CREATED_AT
      ,CREATED_BY
      ,UPDATED_AT
      ,UPDATED_BY
      ,SERVICE_NAME)
      VALUES
      (P_SERVICE_ID
      ,P_SERVICE_TYPE
      ,P_CREATED_AT
      ,P_CREATED_BY
      ,P_UPDATED_AT
      ,P_UPDATED_BY
      ,P_SERVICE_NAME)
    WHEN MATCHED THEN
      UPDATE SET
         A.SERVICE_TYPE = B.SERVICE_TYPE
        ,A.CREATED_AT = B.CREATED_AT
        ,A.CREATED_BY = B.CREATED_BY
        ,A.UPDATED_AT = B.UPDATED_AT
        ,A.UPDATED_BY = B.UPDATED_BY
        ,A.SERVICE_NAME = B.SERVICE_NAME;
  END MERGE_SERVICES;

  PROCEDURE UPD_SERVICES
    (
     P_SERVICE_ID   IN SERVICES.SERVICE_ID%TYPE
    ,P_SERVICE_TYPE IN SERVICES.SERVICE_TYPE%TYPE
    ,P_CREATED_AT   IN SERVICES.CREATED_AT%TYPE
    ,P_CREATED_BY   IN SERVICES.CREATED_BY%TYPE
    ,P_UPDATED_AT   IN SERVICES.UPDATED_AT%TYPE
    ,P_UPDATED_BY   IN SERVICES.UPDATED_BY%TYPE
    ,P_SERVICE_NAME IN SERVICES.SERVICE_NAME%TYPE
    ) IS
  BEGIN
    UPDATE SERVICES
    SET 
        SERVICE_TYPE  = P_SERVICE_TYPE
       ,CREATED_AT    = P_CREATED_AT
       ,CREATED_BY    = P_CREATED_BY
       ,UPDATED_AT    = P_UPDATED_AT
       ,UPDATED_BY    = P_UPDATED_BY
       ,SERVICE_NAME  = P_SERVICE_NAME
    WHERE
        SERVICE_ID    = P_SERVICE_ID;
  END UPD_SERVICES;

  PROCEDURE DEL_SERVICES
    (
     P_SERVICE_ID   IN SERVICES.SERVICE_ID%TYPE
    ) IS
  BEGIN
    DELETE FROM SERVICES
    WHERE
        SERVICE_ID    = P_SERVICE_ID;
  END DEL_SERVICES;

END SERVICES_TAPI;
/

SHOW ERRORS;


