      ,P_CREATED_BY
      ,P_UPDATED_AT
      ,P_UPDATED_BY
      ,P_USER_NAME
      ,P_PASSWORD
      ,P_URL
      ,P_BODY
      ,P_TOKEN
      ,P_SEND_ATTEMPT_CNT)
    WHEN MATCHED THEN
      UPDATE SET
         A.PROVIDER_ID = B.PROVIDER_ID
        ,A.SERVICE_ID = B.SERVICE_ID
        ,A.STATUS = B.STATUS
        ,A.CREATED_AT = B.CREATED_AT
        ,A.CREATED_BY = B.CREATED_BY
        ,A.UPDATED_AT = B.UPDATED_AT
        ,A.UPDATED_BY = B.UPDATED_BY
        ,A.USER_NAME = B.USER_NAME
        ,A.PASSWORD = B.PASSWORD
        ,A.URL = B.URL
        ,A.BODY = B.BODY
        ,A.TOKEN = B.TOKEN
        ,A.SEND_ATTEMPT_CNT = B.SEND_ATTEMPT_CNT;
  END MERGE_PROVIDERS_DTL;

  PROCEDURE UPD_PROVIDERS_DTL
    (
     P_ID               IN PROVIDERS_DTL.ID%TYPE
    ,P_PROVIDER_ID      IN PROVIDERS_DTL.PROVIDER_ID%TYPE
    ,P_SERVICE_ID       IN PROVIDERS_DTL.SERVICE_ID%TYPE
    ,P_STATUS           IN PROVIDERS_DTL.STATUS%TYPE
    ,P_CREATED_AT       IN PROVIDERS_DTL.CREATED_AT%TYPE
    ,P_CREATED_BY       IN PROVIDERS_DTL.CREATED_BY%TYPE
    ,P_UPDATED_AT       IN PROVIDERS_DTL.UPDATED_AT%TYPE
    ,P_UPDATED_BY       IN PROVIDERS_DTL.UPDATED_BY%TYPE
    ,P_USER_NAME        IN PROVIDERS_DTL.USER_NAME%TYPE
    ,P_PASSWORD         IN PROVIDERS_DTL.PASSWORD%TYPE
    ,P_URL              IN PROVIDERS_DTL.URL%TYPE
    ,P_BODY             IN PROVIDERS_DTL.BODY%TYPE
    ,P_TOKEN            IN PROVIDERS_DTL.TOKEN%TYPE
    ,P_SEND_ATTEMPT_CNT IN PROVIDERS_DTL.SEND_ATTEMPT_CNT%TYPE
    ) IS
  BEGIN
    UPDATE PROVIDERS_DTL
    SET 
        PROVIDER_ID       = P_PROVIDER_ID
       ,SERVICE_ID        = P_SERVICE_ID
       ,STATUS            = P_STATUS
       ,CREATED_AT        = P_CREATED_AT
       ,CREATED_BY        = P_CREATED_BY
       ,UPDATED_AT        = P_UPDATED_AT
       ,UPDATED_BY        = P_UPDATED_BY
       ,USER_NAME         = P_USER_NAME
       ,PASSWORD          = P_PASSWORD
       ,URL               = P_URL
       ,BODY              = P_BODY
       ,TOKEN             = P_TOKEN
       ,SEND_ATTEMPT_CNT  = P_SEND_ATTEMPT_CNT
    WHERE
        ID                = P_ID;
  END UPD_PROVIDERS_DTL;

  PROCEDURE DEL_PROVIDERS_DTL
    (
     P_ID               IN PROVIDERS_DTL.ID%TYPE
    ) IS
  BEGIN
    DELETE FROM PROVIDERS_DTL
    WHERE
        ID                = P_ID;
  END DEL_PROVIDERS_DTL;

END PROVIDERS_DTL_TAPI;
