DROP PROCEDURE ACCOUNTS.RECOMBILE_ACCOUNTS;

CREATE OR REPLACE PROCEDURE ACCOUNTS.recombile_accounts   is


    -- Cursor to select all invalid objects in the ACCOUNTS schema
    CURSOR c_invalid_objects IS
        SELECT object_name, object_type
        FROM all_objects
        WHERE owner = 'ACCOUNTS'
        AND status = 'INVALID'
        -- Filter out common types that don't use ALTER ... COMPILE
        AND object_type IN ('VIEW', 'PACKAGE', 'PACKAGE BODY', 'FUNCTION', 'PROCEDURE', 'TRIGGER', 'TYPE', 'TYPE BODY');

    v_sql_statement VARCHAR2(500);
    v_object_name   VARCHAR2(128);
    v_object_type   VARCHAR2(30);
    v_count         NUMBER := 0;
    v_type_keyword  VARCHAR2(30);
BEGIN
    DBMS_OUTPUT.PUT_LINE('Starting recompilation of invalid objects in schema ACCOUNTS...');
    DBMS_OUTPUT.PUT_LINE('-------------------------------------------------------------');

    FOR rec IN c_invalid_objects LOOP
        v_object_name := rec.object_name;
        v_object_type := rec.object_type;
        
        -- Determine the correct keyword for the ALTER statement
        IF v_object_type = 'PACKAGE BODY' THEN
            v_type_keyword := 'PACKAGE BODY';
        ELSIF v_object_type = 'TYPE BODY' THEN
            v_type_keyword := 'TYPE BODY';
        ELSE
            v_type_keyword := v_object_type;
        END IF;

        -- Construct the ALTER statement
        v_sql_statement := 'ALTER ' || v_type_keyword || ' ACCOUNTS."' || v_object_name || '" COMPILE';

        BEGIN
            EXECUTE IMMEDIATE v_sql_statement;
            DBMS_OUTPUT.PUT_LINE('Successfully recompiled ' || v_object_type || ': ' || v_object_name);
            v_count := v_count + 1;
        EXCEPTION
            WHEN OTHERS THEN
                -- Log the error but continue with the next object
                DBMS_OUTPUT.PUT_LINE('Failed to recompile ' || v_object_type || ': ' || v_object_name || '. Error: ' || SQLERRM);
        END;
    END LOOP;

    DBMS_OUTPUT.PUT_LINE('-------------------------------------------------------------');
    DBMS_OUTPUT.PUT_LINE('Recompilation attempt complete.');
    DBMS_OUTPUT.PUT_LINE('Total objects recompiled: ' || v_count);
    
    -- Check for remaining invalid objects after recompilation
    DBMS_OUTPUT.PUT_LINE(CHR(10));
    DBMS_OUTPUT.PUT_LINE('Checking for remaining invalid objects in ACCOUNTS schema...');
    v_count := 0;
    FOR rec IN (SELECT object_name, object_type FROM all_objects WHERE owner = 'ACCOUNTS' AND status = 'INVALID') LOOP
        DBMS_OUTPUT.PUT_LINE('Still invalid: ' || rec.object_type || ' ' || rec.object_name);
        v_count := v_count + 1;
    END LOOP;
    
    IF v_count = 0 THEN
        DBMS_OUTPUT.PUT_LINE('SUCCESS: No invalid objects remain in the ACCOUNTS schema.');
    ELSE
        DBMS_OUTPUT.PUT_LINE('WARNING: ' || v_count || ' objects remain invalid. Check the errors above.');
    END IF;

END;
/

SHOW ERRORS;


