DROP FUNCTION ACCOUNTS.SEND_WHATSAPP_LOGGED;

CREATE OR REPLACE FUNCTION ACCOUNTS.send_whatsapp_logged(
    p_message IN VARCHAR2,
    p_number  IN VARCHAR2
) RETURN VARCHAR2
IS
    v_result VARCHAR2(4000);
    v_status VARCHAR2(50);
BEGIN
    -- Send message
    v_result := send_whatsapp(p_message, p_number);
    
    -- Determine status
    IF v_result LIKE 'ERROR:%' THEN
        v_status := 'FAILED';
    ELSE
        v_status := 'SUCCESS';
    END IF;
    
    -- Log the result
    INSERT INTO WHATSAPP_LOG (
        LOG_ID, PHONE_NUMBER, MESSAGE_TEXT, 
        STATUS, RESPONSE_TEXT
    ) VALUES (
        SEQ_WHATSAPP_LOG.NEXTVAL, p_number, p_message,
        v_status, v_result
    );
    
    COMMIT;
    RETURN v_result;
EXCEPTION
    WHEN OTHERS THEN
        RETURN 'ERROR: ' || SQLERRM;
END send_whatsapp_logged;
/

SHOW ERRORS;


DROP FUNCTION ACCOUNTS.SEND_WHATSAPP_HTTP;

CREATE OR REPLACE FUNCTION ACCOUNTS.send_whatsapp_http(
    p_message IN VARCHAR2,
    p_number  IN VARCHAR2
) RETURN VARCHAR2
IS
    v_token VARCHAR2(500) := 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJudW1iZXIiOiJBbENhcG9kaWUiLCJzZXJpYWwiOiI2NmRiOGNkZDhhZjMyZDciLCJpYXQiOjE3NzAxNDI5MzcsImV4cCI6MTg1NjU0MjkzN30._3fPH7Yb_A5NAREHoeNoX43OFxuKPe97DCyOsNt3PXI';
    v_req UTL_HTTP.REQ;
    v_resp UTL_HTTP.RESP;
    v_response VARCHAR2(4000);
    v_json VARCHAR2(1000);
BEGIN
    -- ČäÇÁ JSON
    v_json := '{"message":"' || p_message || '","number":"' || p_number || '"}';
    
    -- ĹÚĎÇĎ ÇáŘáČ
    v_req := UTL_HTTP.BEGIN_REQUEST('https://business.enjazatik.com/api/v1/send-message', 'POST');
    UTL_HTTP.SET_HEADER(v_req, 'Content-Type', 'application/json');
    UTL_HTTP.SET_HEADER(v_req, 'Authorization', 'Bearer ' || v_token);
    UTL_HTTP.SET_HEADER(v_req, 'Content-Length', LENGTH(v_json));
    
    -- ĹŃÓÇá ÇáČíÇäÇĘ
    UTL_HTTP.WRITE_TEXT(v_req, v_json);
    
    -- ÇÓĘáÇă ÇáŃĎ
    v_resp := UTL_HTTP.GET_RESPONSE(v_req);
    
    -- ŢŃÇÁÉ ÇáŃĎ
    UTL_HTTP.READ_TEXT(v_resp, v_response);
    
    UTL_HTTP.END_RESPONSE(v_resp);
    
    RETURN v_response;
EXCEPTION
    WHEN UTL_HTTP.END_OF_BODY THEN
        UTL_HTTP.END_RESPONSE(v_resp);
        RETURN v_response;
    WHEN OTHERS THEN
        RETURN 'ERROR: ' || SQLERRM;
END send_whatsapp_http;
