DROP JAVA SOURCE ACCOUNTS."SendWhatsapp";

CREATE OR REPLACE AND RESOLVE JAVA SOURCE NAMED ACCOUNTS."SendWhatsapp" as import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.io.OutputStream;
import java.net.HttpURLConnection;
import java.net.URL;

public class SendWhatsapp {
    public static String sendMessage(String message, String number, String authToken) {
        StringBuilder jsonResponse = new StringBuilder();
        HttpURLConnection connection = null;
        try {
            URL url = new URL("https://business.enjazatik.com/api/v1/send-message");
            connection = (HttpURLConnection) url.openConnection();
            connection.setRequestMethod("POST");
            connection.setRequestProperty("Content-Type", "application/json");
            connection.setRequestProperty("Accept", "application/json");
            connection.setRequestProperty("Authorization", "Bearer " + authToken);
            connection.setDoOutput(true);

            String jsonInputString = "{\"message\":\"" + message + "\", \"number\":\"" + number + "\"}";

            OutputStream os = connection.getOutputStream();
            os.write(jsonInputString.getBytes("UTF-8"));
            os.flush();
            os.close();

            int responseCode = connection.getResponseCode();
            if (responseCode == 200 || responseCode == 201) {
                BufferedReader in = new BufferedReader(new InputStreamReader(connection.getInputStream(), "UTF-8"));
                String inputLine;
                while ((inputLine = in.readLine()) != null) {
                    jsonResponse.append(inputLine);
                }
                in.close();
            } else {
                return "Error: HTTP " + responseCode;
            }
        } catch (Exception e) {
            return "Error: " + e.toString();
        } finally {
            if (connection != null) connection.disconnect();
        }
        return jsonResponse.toString();
    }
}
/

SHOW ERRORS;


