DROP VIEW ACCOUNTS.PREV_V;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.PREV_V
(OBJID, OBJNAME, ENTER_FLAG, PARNT, OBJLEVEL, 
 USRID, USER_NAME, SHORT, OBJHAS)
AS 
SELECT tbobjects.objid, tbobjects.objname, user_privileges.enter_flag,
          tbobjects.parnt, tbobjects.objlevel, user_privileges.usrid,
          tbusers_setup.usrnamear, short, objhas
     FROM tbobjects, user_privileges, tbusers_setup
    WHERE tbobjects.objid = user_privileges.objid
      AND user_privileges.enter_flag = 1
      AND tbusers_setup.usrid = user_privileges.usrid
   UNION
   SELECT DISTINCT (tbobjects.objid), tbobjects.objname,
                   user_privileges.enter_flag, tbobjects.parnt,
                   tbobjects.objlevel, user_privileges.usrid,
                   tbusers_setup.usrnamear, short, objhas
              FROM tbobjects, user_privileges, tbusers_setup
             WHERE tbobjects.objid = SUBSTR (user_privileges.objid, 1, 2)
               AND tbusers_setup.usrid = user_privileges.usrid
   UNION
   SELECT DISTINCT (tbobjects.objid), tbobjects.objname,
                   user_privileges.enter_flag, tbobjects.parnt,
                   tbobjects.objlevel, user_privileges.usrid,
                   tbusers_setup.usrnamear, short, objhas
              FROM tbobjects, user_privileges, tbusers_setup
             WHERE tbobjects.objid = SUBSTR (user_privileges.objid, 1, 3)
               AND tbusers_setup.usrid = user_privileges.usrid
   UNION
   SELECT DISTINCT (tbobjects.objid), tbobjects.objname,
                   user_privileges.enter_flag, tbobjects.parnt,
                   tbobjects.objlevel, user_privileges.usrid,
                   tbusers_setup.usrnamear, short, objhas
              FROM tbobjects, user_privileges, tbusers_setup
             WHERE tbobjects.objid = SUBSTR (user_privileges.objid, 1, 4)
               AND tbusers_setup.usrid = user_privileges.usrid
   UNION
   SELECT DISTINCT (tbobjects.objid), tbobjects.objname,
                   user_privileges.enter_flag, tbobjects.parnt,
                   tbobjects.objlevel, user_privileges.usrid,
                   tbusers_setup.usrnamear, short, objhas
              FROM tbobjects, user_privileges, tbusers_setup
             WHERE tbobjects.objid = SUBSTR (user_privileges.objid, 1, 5)
               AND tbusers_setup.usrid = user_privileges.usrid
   UNION
   SELECT DISTINCT (tbobjects.objid), tbobjects.objname,
                   user_privileges.enter_flag, tbobjects.parnt,
                   tbobjects.objlevel, user_privileges.usrid,
                   tbusers_setup.usrnamear, short, objhas
              FROM tbobjects, user_privileges, tbusers_setup
