            gl_categuary,
            items,
            main_cat
      WHERE NVL (tr_inv_m.flag_posted, 0) IN (1, 0)
        AND (tr_inv_m.tr_inv_m_id = tr_inv_d.tr_inv_m_id)
        AND (NVL (tr_inv_m.costcn_id, 1) = gl_cost_center.costcn_id)
        AND tr_inv_m.falg_cancel <> 1
        AND tr_inv_m.tr_inv_type_id IN (11)
        AND (tr_inv_d.item_id = items.item_id)
        AND (main_cat.main_id = items.main_cat_id)
        AND (main_cat.cr_account = gl_acc_setup.acc_id)
        --AND TR_INV_M.GLH_ID IS NOT NULL
        --AND (TR_INV_m.DEBIT_ACCOUNT = GL_ACC_SETUP.ACC_ID)
        AND (tr_inv_m.cat_id = gl_categuary.cat_id)
   GROUP BY tr_inv_m.tr_inv_m_id,
            tr_inv_m.trans_date,
            tr_inv_m.doc_no,
            main_cat.cr_account,
            gl_acc_setup.acc_name,
            description,
            gl_cost_center.costcn_name,
            tr_inv_m.cat_id,
            gl_categuary.cat_name,
            pt_id,
            tr_inv_m.curr_id,
            curr_price,
            tr_inv_m.costcn_id,
            flag_posted,
            falg_cancel;


DROP VIEW ACCOUNTS.DETAIL_PERIODS;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.DETAIL_PERIODS
(TYPE_OF_PERIODS, MONTH_PERIOD, FROM_DATE, TO_DATE, YEAR, 
 STATUS, FINAL_STATUS)
AS 
SELECT gl_period.pr_type, gl_period.pr_month, gl_period.pr_sdate,
          gl_period.pr_edate, gl_period.pr_year, gl_period.pr_open,
          gl_period.pr_close_end
     FROM gl_period;


DROP VIEW ACCOUNTS.DETAIL_JOURNAL_TOTT;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.DETAIL_JOURNAL_TOTT
(DOC_TYPE, JV_TYPE, DOC_NO, W_CODE, COST_CNTR_NO, 
 A_CODE, A_CY, DR_AMT, CR_AMT, DR_AMT_F, 
 CR_AMT_F, AMT, AMTC, AMT_F, MN_SB, 
 J_DATE, J_DESC, MNTH, YEAR, J_CLOSE, 
 CB_BEFORE, CB_AFTER, LC_NO, JV_SERIAL, C_V_CODE, 
 SOURCE_NAME, CAT_NAME, ACC_PARANT, ALEVEL)
AS 
SELECT NVL (glhtm.source_id, 1), NVL (glhtm.cat_id, 42),
          NVL (glhtm.doc_no, 0), NVL (glhtm.doc_no, 0),
          NVL (gldtm.costcn_id, 100),
          SUBSTR (TO_CHAR (gl_acc_setup.acc_id), 1, 5) a_code,
          NVL (glhtm.curr_id, 1), NVL (gldtm.debit, 0), NVL (gldtm.credit, 0),
          gldtm.debit_local, gldtm.credit_local,
          DECODE (gldtm.credit, 0, gldtm.debit, -1 * gldtm.credit),
          DECODE (gldtm.debit, 0, -1 * gldtm.credit, gldtm.debit),
          NVL (gldtm.debit_local, 0),
          DECODE (TO_CHAR (gldtm.acc_id),
                  TO_CHAR (gl_acc_setup.acc_id), 2,
                  1
                 ),
          glhtm.glh_date, NVL (gldtm.notes, 0),
          TO_NUMBER (TO_CHAR (glhtm.glh_date, 'mm')),
          TO_NUMBER (TO_CHAR (glhtm.glh_date, 'yyyy')),
          NVL (glhtm.post_tm, 0), NVL (gldtm.debit, 0), NVL (gldtm.credit, 0),
          NULL, glhtm.glh_id, gldtm.acc_id, gl_source.source_name,
          gl_categuary.cat_name, gl_acc_setup.acc_parant,
          gl_acc_setup.acc_level
     FROM glhtm, gldtm, gl_acc_setup, gl_source, gl_categuary
    WHERE (glhtm.glh_id = gldtm.glh_id)
      AND (gl_source.source_id = glhtm.source_id)
      AND (gl_categuary.cat_id = glhtm.cat_id)
      AND ((gl_acc_setup.acc_id = gldtm.acc_id)
---AND  (GLHTM.CAT_ID NOT IN (42))
           AND (glhtm.f_cancel <> 1));


