select entry_no,ENTRY_DATE,ENTRY_TYPE_NO from entry_main
union all select entry_no,ENTRY_DATE,12 from entry_main2;


DROP VIEW ACCOUNTS.CUTTER_PAL;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUTTER_PAL
(OHID, OHDID, CUTTER_NO, DEPTID, SANF_NO, 
 SANF_DNO, SIZE_FRM, SIZE_TO, PQTY)
AS 
SELECT   ohid, ohdid, cutter_no, deptid, sanf_no, sanf_dno, size_frm,
            size_to, SUM (pqty)
       FROM cuting_transd
      WHERE POST = 0
   GROUP BY ohid,
            ohdid,
            cutter_no,
            deptid,
            sanf_no,
            sanf_dno,
            size_frm,
            size_to
     HAVING SUM (pqty) > 0;


