(TR_INV_D_ID, TR_INV_M_ID, BILL_NO, YEAR, TYPENO, 
 CAT_ID, DDATE, GOVNO, STORENO, STORETO, 
 DETAILE, SANF_NO, SANF_DNO, SANF_COST, SANF_PRICE, 
 QTY, BOUNS, EXP_DATE, CAP, PCS, 
 SEQ, SHELF_NO, SIZE_FRM, SIZE_TO, COLOR_NO, 
 CATEGORY, COLOR_NO2, SEQ_NO, CAT_NO, STYLE_NO, 
 DIS_RATE1, DISCOUNT1, RCVDONE, CREATEBY, CREATEDATE, 
 UPDATEBY, UPDATEDATE, UNIT_NO, SUNIT_NO, SQTY, 
 STK_COST, TOTALD, OHID, OHDID, ORDSID, 
 DEPTID, CUTTER_NO, PQTY)
