          "DDATE", "GOVNO", "STORENO", "STORETO", "DETAILE", "SANF_NO",
          "SANF_DNO", "SANF_COST", "SANF_PRICE", "QTY", "BOUNS", "EXP_DATE",
          "CAP", "PCS", "SEQ", "SHELF_NO", "SIZE_FRM", "SIZE_TO", "COLOR_NO",
          "CATEGORY", "COLOR_NO2", "SEQ_NO", "CAT_NO", "STYLE_NO",
          "DIS_RATE1", "DISCOUNT1", "RCVDONE", "CREATEBY", "CREATEDATE",
          "UPDATEBY", "UPDATEDATE", "UNIT_NO", "SUNIT_NO", "SQTY", "STK_COST",
          "TOTALD", "OHID", "OHDID", "ORDSID", "DEPTID", "CUTTER_NO", "PQTY"
     FROM cuting_transd;


DROP VIEW ACCOUNTS.ENTRY_MAIN_MANUAL;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.ENTRY_MAIN_MANUAL
(ENT_SEQ, ENTRY_NO, DETAILS, ENTRY_DATE, ENT_YEAR, 
 ENTRY_TYPE_NO)
AS 
SELECT ROW_NUMBER() OVER (PARTITION BY TO_CHAR(ENTRY_MAIN.ENTRY_DATE,'YYYY') ORDER BY ENTRY_MAIN.ENTRY_NO),ENTRY_MAIN.entry_no, ENTRY_MAIN.DETAILS, ENTRY_MAIN.entry_date, 
   TO_CHAR(ENTRY_MAIN.ENTRY_DATE,'YYYY'), ENTRY_MAIN.entry_type_no
     FROM ACCOUNTS.ENTRY_MAIN
     WHERE entry_type_no = 1;


CREATE OR REPLACE TRIGGER ACCOUNTS.no_weekend_updates  

BEFORE UPDATE    ON ACCOUNTS.EMP 
DECLARE    day_of_week NUMBER(2) := TO_NUMBER(TO_CHAR(SYSDATE,'D'));    dummy CHAR(1); BEGIN    IF (day_of_week in (1,7))  /* Sunday,Saturday */    THEN       BEGIN          SELECT 'X'/* Check Exceptions Table */                 
  INTO dummy                    FROM WEEKEND_UPDATE_OK          WHERE USERID = USER;       EXCEPTION          WHEN NO_DATA_FOUND THEN /*Not Exception*/                   RAISE_APPLICATION_ERROR(-20011,                       'Try again on Monday!');     
 END;    END IF; END;
/
SHOW ERRORS;


DROP SYNONYM ACCOUNTS.SMP_JOB_ID;

CREATE SYNONYM ACCOUNTS.SMP_JOB_ID FOR ACCOUNTS.SMP_JOB_ID_;


DROP SYNONYM ACCOUNTS.SMP_JOB_EVENTLIST;

CREATE SYNONYM ACCOUNTS.SMP_JOB_EVENTLIST FOR ACCOUNTS.SMP_JOB_EVENTLIST_;


BEGIN
  SYS.DBMS_SCHEDULER.DROP_JOB
    (job_name  => 'ACCOUNTS.SEND_MSG');
END;
/

BEGIN
  SYS.DBMS_SCHEDULER.CREATE_JOB
    (
       job_name        => 'ACCOUNTS.SEND_MSG'
      ,start_date      => TO_TIMESTAMP_TZ('2024/01/21 17:29:30.279000 +03:00','yyyy/mm/dd hh24:mi:ss.ff tzh:tzm')
      ,repeat_interval => 'FREQ=SECONDLY;INTERVAL=3;BYDAY=SAT,MON,TUE,WED,THU,FRI,SUN'
      ,end_date        => NULL
      ,job_class       => 'DEFAULT_JOB_CLASS'
      ,job_type        => 'PLSQL_BLOCK'
      ,job_action      => 'begin
MSG_QUEUE_TAPI.PUSH_QUEUE;
end;'
      ,comments        => NULL
    );
  SYS.DBMS_SCHEDULER.SET_ATTRIBUTE
    ( name      => 'ACCOUNTS.SEND_MSG'
     ,attribute => 'RESTARTABLE'
     ,value     => FALSE);
  SYS.DBMS_SCHEDULER.SET_ATTRIBUTE
    ( name      => 'ACCOUNTS.SEND_MSG'
     ,attribute => 'LOGGING_LEVEL'
     ,value     => SYS.DBMS_SCHEDULER.LOGGING_RUNS);
  SYS.DBMS_SCHEDULER.SET_ATTRIBUTE_NULL
    ( name      => 'ACCOUNTS.SEND_MSG'
     ,attribute => 'MAX_FAILURES');
  SYS.DBMS_SCHEDULER.SET_ATTRIBUTE_NULL
    ( name      => 'ACCOUNTS.SEND_MSG'
     ,attribute => 'MAX_RUNS');
  BEGIN
    SYS.DBMS_SCHEDULER.SET_ATTRIBUTE
      ( name      => 'ACCOUNTS.SEND_MSG'
       ,attribute => 'STOP_ON_WINDOW_CLOSE'
       ,value     => FALSE);
  EXCEPTION
    -- could fail if program is of type EXECUTABLE...
    WHEN OTHERS THEN
      NULL;
  END;
  SYS.DBMS_SCHEDULER.SET_ATTRIBUTE
    ( name      => 'ACCOUNTS.SEND_MSG'
     ,attribute => 'JOB_PRIORITY'
     ,value     => 3);
  SYS.DBMS_SCHEDULER.SET_ATTRIBUTE_NULL
    ( name      => 'ACCOUNTS.SEND_MSG'
     ,attribute => 'SCHEDULE_LIMIT');
  SYS.DBMS_SCHEDULER.SET_ATTRIBUTE
    ( name      => 'ACCOUNTS.SEND_MSG'
     ,attribute => 'AUTO_DROP'
     ,value     => FALSE);

  SYS.DBMS_SCHEDULER.ENABLE
    (name                  => 'ACCOUNTS.SEND_MSG');
END;
/

