CREATE TABLE ACCOUNTS.ENTRY_SUB
(
  SEQ          NUMBER(20)                       NOT NULL,
  ENTRY_NO     NUMBER(11)                       NOT NULL,
  ACC_NO       NUMBER(15)                       NOT NULL,
  ENTRY_MNT    NUMBER(20,2)                     NOT NULL,
  BALANCE_S    NUMBER(20,2)                     NOT NULL,
  SEQ_PRICE    NUMBER(30),
  SUB_DETAILS  VARCHAR2(250 BYTE),
  INVOICE_NO   NUMBER(12),
  GIVING       NUMBER(20)
)
TABLESPACE SYSTEM
PCTUSED    40
PCTFREE    10
INITRANS   1
MAXTRANS   255
STORAGE    (
            INITIAL          26M
            MINEXTENTS       1
            MAXEXTENTS       UNLIMITED
            PCTINCREASE      0
            FREELISTS        1
            FREELIST GROUPS  1
            BUFFER_POOL      DEFAULT
           )
LOGGING 
NOCOMPRESS 
NOCACHE
NOPARALLEL
MONITORING;


