DROP PACKAGE ACCOUNTS.ACC;

CREATE OR REPLACE PACKAGE ACCOUNTS.ACC IS
  type acc_dname is record(
    ENTRY_NO 		number(10),
    DETAILS	varchar2(100),
    ENTRY_DATE	date,
    ENTRY_MNT		number(10,2),
    BALANCE_S		number(12,2),
    ACC_NO              number(8),
    ACC_NAME            varchar2(100));
  type acc_dname_ref is ref cursor return acc_dname;
  type acc_dname_tab is table of acc_dname index by binary_integer;
  procedure query  (resultset in out acc_dname_ref);
  procedure plock  (dmlset in out acc_dname_tab);
  procedure pinsert(dmlset in out acc_dname_tab);
  procedure pupdate(dmlset in out acc_dname_tab);
  procedure pdelete(dmlset in out acc_dname_tab);
END;
/

SHOW ERRORS;


DROP PACKAGE BODY ACCOUNTS.ACC;

CREATE OR REPLACE PACKAGE BODY ACCOUNTS.ACC IS
  procedure query(resultset in out ACC_dname_ref) is
  begin
    open resultset for
      SELECT ALL ACCOUNTS.ENTRY_MAIN.ENTRY_NO, 
        ACCOUNTS.ENTRY_MAIN.DETAILS, 
       ACCOUNTS.ENTRY_MAIN.ENTRY_DATE, 
        ACCOUNTS.ENTRY_SUB.ENTRY_MNT, 
       ACCOUNTS.ENTRY_SUB.BALANCE_S, ACCOUNTS.CHART_ACC.ACC_NO,
       ACCOUNTS.CHART_ACC.ACC_NAME FROM ACCOUNTS.ENTRY_MAIN, ACCOUNTS.ENTRY_SUB, ACCOUNTS.CHART_ACC
     WHERE (ACCOUNTS.ENTRY_MAIN.ENTRY_NO=ACCOUNTS.ENTRY_SUB.ENTRY_NO
   AND ACCOUNTS.CHART_ACC.ACC_NO=ACCOUNTS.ENTRY_SUB.ACC_NO)
   GROUP BY ACCOUNTS.CHART_ACC.ACC_NO, ACCOUNTS.CHART_ACC.ACC_NAME,
    
ACCOUNTS.CHART_ACC.ROWID, 
    ACCOUNTS.CHART_ACC.ROWid, ACCOUNTS.ENTRY_MAIN.ENTRY_NO, 
   ACCOUNTS.ENTRY_MAIN.DETAILS, ACCOUNTS.ENTRY_MAIN.ENTRY_DATE, 
   ACCOUNTS.ENTRY_SUB.ENTRY_MNT, ACCOUNTS.ENTRY_SUB.BALANCE_S
   ORDER BY ACCOUNTS.CHART_ACC.ACC_NAME ASC;
    
end;
  procedure plock(dmlset in out ACC_dname_tab) is
  begin
--lock the specified record
     null;
  end;
  procedure pinsert(dmlset in out ACC_dname_tab) is
   begin
--insert the records from the table of records
   NULL;
  end;
  procedure pupdate(dmlset in out ACC_dname_tab) is
  begin
--update the records from the table of records
     null;
  end;
  procedure pdelete(dmlset in out ACC_dname_tab) is
  begin
--delete  the records from the table of records
     null;
  end;
 
END;
/

SHOW ERRORS;


DROP VIEW ACCOUNTS.ENTRY_SUB_VIEW;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.ENTRY_SUB_VIEW
(SEQ, ENTRY_NO, ACC_NO, ENTRY_MNT, BALANCE_S, 
 ENTRY_DATE, SEQ_PRICE, SUB_DETAILS, INVOICE_NO, GIVING)
AS 
SELECT entry_sub.seq, entry_sub.entry_no, entry_sub.acc_no,
          entry_sub.entry_mnt, entry_sub.balance_s, entry_main.entry_date,
          entry_sub.seq_price, entry_sub.sub_details, entry_sub.invoice_no,
          entry_sub.giving
     FROM entry_main, entry_sub
    WHERE (entry_sub.entry_no = entry_main.entry_no);


DROP VIEW ACCOUNTS.ENTRY_SUB_VIEW2;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.ENTRY_SUB_VIEW2
(ACC_NO, INVOICE_NO, BALANCE)
AS 
SELECT   entry_sub.acc_no, entry_sub.invoice_no,
            SUM (entry_sub.entry_mnt) balance
       FROM entry_sub
     HAVING SUM (entry_sub.entry_mnt) <> 0
   GROUP BY entry_sub.acc_no, entry_sub.invoice_no;


DROP VIEW ACCOUNTS.ACCOUNTS;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.ACCOUNTS
(A_CODE, A_NAME, A_NAME_ENG, A_LEVEL, A_PARENT, 
 A_S_M, A_GROUPING, A_REPORT, AC_CLOSE, DR, 
 CURDIF_CODE, AD_U_ID, AD_DATE, MAINSUB, ACC_POSTED)
AS 
SELECT   TO_CHAR (gl_acc_setup.acc_no), gl_acc_setup.acc_name,
            gl_acc_setup.acc_name, 5 acc_level,
            SUBSTR (gl_acc_setup.acc_no, 1, 4)
--,decode (gl_acc_setup.ACC_LEVEL,1,1,2,2,3,3,4,decode (gl_acc_setup.ACC_POSTED,0,4,5),5,5)
            , 5 acc_level, NULL,
            
--decode (gl_acc_setup.ACC_LEVEL,1,1,2,1,3,1,4,0,5,0),
            DECODE (SUBSTR (gl_acc_setup.acc_no, 1, 1),
                    1, 1,
                    2, 1,
                    3, 2,
                    4, 2
                   ) a_report,
            0,
            DECODE (SUBSTR (gl_acc_setup.acc_no, 1, 1),
                    1, 1,
                    2, 0,
                    3, 1,
                    4, 0
                   ) a_report,
            NULL, NULL, NULL,
            DECODE (5,
                    1, 'ŃĆíÓí',
                    2, 'ÇÓĘÇĐ ÚÇă',
                    3, 'ÝŃÚí',
                    4, 'ÚÇă',
                    5, 'ĘÍáíáí',
                    6, 'ĘÍáíáí'
                   ),
            1 acc_posted
       FROM chart_acc gl_acc_setup
   ORDER BY gl_acc_setup.acc_no;


DROP VIEW ACCOUNTS.CUST_ALL_PAL_AMT;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUST_ALL_PAL_AMT
(ACC_NO, CUST_NO, CUST_NAME, PAL_AMT)
AS 
SELECT   chart_acc.acc_no, entry_sub.giving, chart_acc.acc_name,
            SUM (entry_sub.entry_mnt) pal_amt
       FROM chart_acc, entry_sub
      WHERE entry_sub.acc_no = chart_acc.acc_no
      AND SUBSTR(CHART_ACC.ACC_NO,1,3) = 123
   GROUP BY chart_acc.acc_no,
            chart_acc.acc_name,
            entry_sub.acc_no,
            entry_sub.giving
     HAVING SUM (entry_sub.entry_mnt) <> 0;


DROP VIEW ACCOUNTS.CUST_PAL_AMT;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUST_PAL_AMT
(ACC_NO, CUST_NAME, PAL_AMT)
AS 
SELECT   chart_acc.acc_no, chart_acc.acc_name,
            SUM (entry_sub.entry_mnt) pal_amt
       FROM chart_acc, entry_sub
      WHERE entry_sub.acc_no = chart_acc.acc_no
        AND SUBSTR (chart_acc.acc_no, 1, 3) = 123
   GROUP BY chart_acc.acc_no, chart_acc.acc_name, entry_sub.acc_no
     HAVING SUM (entry_sub.entry_mnt) <> 0;


DROP VIEW ACCOUNTS.UN;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.UN
(ENTRY_NO, PAL_AMT)
AS 
SELECT   entry_sub.entry_no, SUM (entry_sub.entry_mnt) pal_amt
       FROM accounts.entry_sub
      WHERE 1 = 1
   GROUP BY entry_sub.entry_no
     HAVING SUM (entry_sub.entry_mnt) <> 0;


DROP VIEW ACCOUNTS.UN2;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.UN2
(ENTRY_NO, PAL_AMT)
AS 
SELECT   entry_sub.entry_no, SUM (entry_sub.entry_mnt) pal_amt
       FROM accounts.entry_sub
      WHERE 1 = 1
   GROUP BY entry_sub.entry_no
     HAVING SUM (entry_sub.entry_mnt) = 0;


DROP VIEW ACCOUNTS.CUST_PAL_WNUL_AMT;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUST_PAL_WNUL_AMT
(ACC_NO, CUST_NAME, PAL_AMT)
AS 
SELECT   chart_acc.acc_no, chart_acc.acc_name,
            SUM (entry_sub.entry_mnt) pal_amt
       FROM chart_acc, entry_sub
      WHERE entry_sub.acc_no = chart_acc.acc_no
        AND SUBSTR (chart_acc.acc_no, 1, 3) = 123
   GROUP BY chart_acc.acc_no, chart_acc.acc_name, entry_sub.acc_no
     HAVING SUM (entry_sub.entry_mnt) < 10000000;


DROP VIEW ACCOUNTS.GL_TR;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.GL_TR
(ACC_NO, ACC_NAME, CUST_NO, ENTRY_NO, ENTRY_DATE, 
 BALANCE_S, ENTRY_MNT, DR, CR, SUB_DETAILS, 
 SEQ, DETAILS, SUB_ENTRY_NO, SEQ_PRICE, INVOICE_NO, 
 GIVING, ENTRY_TYPE_NAME, ENTRY_TYPE_NO, SOURCE_NAME, SOURCE_ID)
AS 
SELECT entry_sub.acc_no, chart_acc.acc_name,giving, entry_sub.entry_no,
          entry_main.entry_date, entry_sub.balance_s, entry_sub.entry_mnt,
          entry_sub.entry_mnt dr, 0 cr, entry_sub.sub_details, entry_sub.seq,
          entry_main.details,
             SUBSTR (entry_sub.entry_no, 1, 1)
          || SUBSTR (entry_sub.entry_no, 7, 4) sub_entry_no,
          seq_price, invoice_no, giving, entry_type.entry_type_name,
          entry_main.entry_type_no, entry_type.source_name,
          entry_type.source_id
     FROM entry_main, entry_sub, chart_acc, entry_type
    WHERE 
--ENTRY_SUB.ACC_NO=:p_4
-- AND ENTRY_MAIN.ENTRY_DATE BETWEEN :p_5 AND :p_6)
-- AND
          (entry_sub.entry_no = entry_main.entry_no)
      AND entry_sub.acc_no = chart_acc.acc_no
      AND entry_type.entry_type_no = entry_main.entry_type_no
      AND entry_sub.entry_mnt > 0
   UNION
   SELECT entry_sub.acc_no, chart_acc.acc_name,giving, entry_sub.entry_no,
          entry_main.entry_date, entry_sub.balance_s, entry_sub.entry_mnt,
          0 dr, entry_sub.entry_mnt * -1 cr, entry_sub.sub_details,
          entry_sub.seq, entry_main.details,
             SUBSTR (entry_sub.entry_no, 1, 1)
          || SUBSTR (entry_sub.entry_no, 7, 4) sub_entry_no,
          seq_price, invoice_no, giving, entry_type.entry_type_name,
          entry_main.entry_type_no, entry_type.source_name,
          entry_type.source_id
     FROM entry_main, entry_sub, chart_acc, entry_type
    WHERE 
--ENTRY_SUB.ACC_NO=:p_4
-- AND ENTRY_MAIN.ENTRY_DATE BETWEEN :p_5 AND :p_6)
-- AND
          (entry_sub.entry_no = entry_main.entry_no)
      AND entry_sub.acc_no = chart_acc.acc_no
      AND entry_type.entry_type_no = entry_main.entry_type_no
      AND entry_sub.entry_mnt < 0
--ORDER BY entry_date,ENTRY_SUB.SEQ;;;


DROP VIEW ACCOUNTS.GLTD;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.GLTD
(GLH_ID, TID, GLH_DATE, DOC_NO, ACC_ID, 
 ACC_NAME, CUST_NO, DEBIT, CREDIT, DEBIT_LOCAL, 
 CREDIT_LOCAL, BALANCE_S, ENTRY_MNT, NOTES, DESCRPTION, 
 COSTCN_NAME, SEQ, CAT_ID, CAT_NAME, SOURCE_NAME, 
 SOURCE_ID, CURR_ID, CURR_CODE, CURR_PRICE, CURRID, 
 CURRCODE, CURRPRICE, COSTCN_ID, POST_TM, F_CANCEL)
AS 
SELECT g.sub_entry_no, g.sub_entry_no, g.entry_date, g.invoice_no,
          g.acc_no, g.acc_name,cust_no, g.dr, g.cr, g.dr, g.cr, g.balance_s,
          g.entry_mnt, g.sub_details, g.details, NULL, g.seq, g.entry_type_no,
          g.entry_type_name, g.source_name, g.source_id, 1, 'yer', 1, 1,
          'yer', 1, 1, 1, 0
     FROM accounts.gl_tr g;


DROP VIEW ACCOUNTS.DETAIL_JOURNAL_TR;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.DETAIL_JOURNAL_TR
(DOC_TYPE, JV_TYPE, DOC_NO, W_CODE, COST_CNTR_NO, 
 A_CODE, A_CY, DR_AMT, CR_AMT, DR_AMT_F, 
 CR_AMT_F, AMT, AMTC, AMT_F, MN_SB, 
 J_DATE, J_DESC, MNTH, YEAR, J_CLOSE, 
 CB_BEFORE, CB_AFTER, LC_NO, JV_SERIAL, C_V_CODE, 
 SOURCE_NAME, CAT_NAME, ACC_PARANT, ALEVEL, A, 
 ACC_NAME, GLH_ID, GLH_NO, POST_TM)
AS 
SELECT NVL (source_id, 1), NVL (cat_id, 42), NVL (doc_no, 1),
          NVL (doc_no, 0), 1, TO_CHAR (gl_acc_setup.a_code) a_code,
          NVL (gl_td.currid, 1), NVL (debit, 0), NVL (credit, 0), debit_local,
          credit_local, DECODE (credit, 0, debit, -1 * credit),
          DECODE (debit, 0, -1 * credit, debit), NVL (debit_local, 0),
          DECODE (TO_CHAR (gl_acc_setup.a_code),
                  TO_CHAR (gl_acc_setup.a_code), 2,
                  1
                 ),
          glh_date, gl_td.notes, TO_NUMBER (TO_CHAR (glh_date, 'mm')),
          TO_NUMBER (TO_CHAR (glh_date, 'yyyy')), 0 post_tm, NVL (debit, 0),
          NVL (credit, 0), NULL, doc_no, gl_acc_setup.a_code, source_name,
          cat_name, gl_acc_setup.a_parent, gl_acc_setup.a_level, 5 iscont,
          gl_acc_setup.a_name, gl_td.glh_id, doc_no, 0 post_tm
     FROM gltd gl_td, accounts gl_acc_setup
    WHERE
          --(glh_id = glh_id)
            --AND
          gl_td.acc_id = gl_acc_setup.a_code AND gl_acc_setup.acc_posted = 1;


DROP VIEW ACCOUNTS.GL_J_TR_TM;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.GL_J_TR_TM
(GLH_ID, TID, GLH_DATE, DOC_NO, ACC_ID, 
 ACC_NAME, CUST_NO, DEBIT, CREDIT, DEBIT_LOCAL, 
 CREDIT_LOCAL, BALANCE_S, ENTRY_MNT, NOTES, DESCRPTION, 
 COSTCN_NAME, SEQ, CAT_ID, CAT_NAME, SOURCE_NAME, 
 SOURCE_ID, CURR_ID, CURR_CODE, CURR_PRICE, CURRID, 
 CURRCODE, CURRPRICE, COSTCN_ID, POST_TM, F_CANCEL, 
 ACC_PARNT)
AS 
SELECT g.glh_id, g.tid, g.glh_date, g.doc_no, g.acc_id,
          g.acc_name, g.cust_no, g.debit, g.credit, g.debit_local, g.credit_local,
          g.balance_s, g.entry_mnt, g.notes, g.descrption, g.costcn_name,
          g.seq, g.cat_id, g.cat_name, g.source_name, g.source_id, g.curr_id,
          g.curr_code, g.curr_price, g.currid, g.currcode, g.currprice,
          g.costcn_id, g.post_tm, g.f_cancel, SUBSTR (acc_id, 1, 3) acc_parnt
     FROM accounts.gltd g;


DROP VIEW ACCOUNTS.ENTRY_SUB_VIEW_CASH_AND_BANK;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.ENTRY_SUB_VIEW_CASH_AND_BANK
(SEQ, ENTRY_NO, ACC_NO, ACC_NAME, CUR_NO, 
 CUR_NAME, ENTRY_MNT, BALANCE_S, ENTRY_DATE, SEQ_PRICE, 
 DETAILS, INVOICE_NO, GIVING)
AS 
SELECT   entry_sub.seq, entry_sub.entry_no, entry_sub.acc_no,
            chart_acc.acc_name, SUBSTR (chart_acc.acc_no, 4, 1),
            currency.cur_name, entry_sub.entry_mnt, entry_sub.balance_s,
            entry_main.entry_date, entry_sub.seq_price, NVL(entry_sub.sub_details,ENTRY_MAIN.DETAILS),
            entry_sub.invoice_no, entry_sub.giving
       FROM entry_main, entry_sub, chart_acc, currency
      WHERE (    entry_sub.entry_no = entry_main.entry_no
             AND entry_sub.acc_no = chart_acc.acc_no
             AND currency.cur_no = SUBSTR (chart_acc.acc_no, 4, 1)
             AND currency.cur_no = SUBSTR (entry_sub.acc_no, 4, 1)
             AND SUBSTR (entry_sub.acc_no, 1, 3) IN (121, 122)
            )
   ORDER BY entry_main.entry_date DESC;


DROP VIEW ACCOUNTS.ENTRY_SUB_VIEW_BANK;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.ENTRY_SUB_VIEW_BANK
(SEQ, ENTRY_NO, ACC_NO, ACC_NAME, CUR_NO, 
 CUR_NAME, ENTRY_MNT, BALANCE_S, ENTRY_DATE, SEQ_PRICE, 
 DETAILS, INVOICE_NO, GIVING)
AS 
SELECT   entry_sub.seq, entry_sub.entry_no, entry_sub.acc_no,
            chart_acc.acc_name, SUBSTR (chart_acc.acc_no, 4, 1),
            currency.cur_name, entry_sub.entry_mnt, entry_sub.balance_s,
            entry_main.entry_date, entry_sub.seq_price,
            NVL (entry_sub.sub_details, entry_main.details),
            entry_sub.invoice_no, entry_sub.giving
       FROM entry_main, entry_sub, chart_acc, currency
      WHERE (    entry_sub.entry_no = entry_main.entry_no
             AND entry_sub.acc_no = chart_acc.acc_no
             AND currency.cur_no = SUBSTR (chart_acc.acc_no, 4, 1)
             AND currency.cur_no = SUBSTR (entry_sub.acc_no, 4, 1)
             AND SUBSTR (entry_sub.acc_no, 1, 3) IN (122)
            )
   ORDER BY entry_main.entry_date DESC;


