ALTER TABLE ACCOUNTS.ADVERTISEMENT_COMPANY
 DROP PRIMARY KEY CASCADE;
DROP TABLE ACCOUNTS.ADVERTISEMENT_COMPANY CASCADE CONSTRAINTS PURGE;

CREATE TABLE ACCOUNTS.ADVERTISEMENT_COMPANY
(
  COMP_NO                NUMBER(8),
  COMP_NAME              VARCHAR2(80 BYTE)      NOT NULL,
  CONTRACT_NO            NUMBER(8)              NOT NULL,
  CONTRACT_AMOUNT        NUMBER(12,2)           NOT NULL,
  ADVERTISE_CARD_NUMBER  NUMBER(4)              NOT NULL,
  CONTRACT_DATE          DATE                   NOT NULL,
  ACC_NO                 NUMBER(8),
  END_DATE               DATE                   NOT NULL,
  ENTRY_NO               NUMBER(11)
)
TABLESPACE SYSTEM
PCTUSED    40
PCTFREE    10
INITRANS   1
MAXTRANS   255
STORAGE    (
            INITIAL          64K
            MINEXTENTS       1
            MAXEXTENTS       UNLIMITED
            PCTINCREASE      0
            FREELISTS        1
            FREELIST GROUPS  1
            BUFFER_POOL      DEFAULT
           )
LOGGING 
NOCOMPRESS 
NOCACHE
