DROP VIEW ACCOUNTS.L_W_DEFF;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.L_W_DEFF
(SANF_NO, SANF_DNO, SANF_NAME, STYL_NO, SHAPE_STYLE_NO, 
 STYLE_NAME, FROM_L, LEN, TO_L, FROM_W, 
 WID, TO_W)
AS 
SELECT ALL sanfs_d.sanf_no, sanfs_d.sanf_dno, sanfs_d.sanf_name,
              sanfs_d.styl_no, style.shape_style_no, style.style_name,
              style.from_l, sanfs_d.len, style.to_l, style.from_w,
              sanfs_d.wid, style.to_w
         FROM style, sanfs_d
        WHERE (sanfs_d.styl_no = style.shape_style_no)
          AND (   sanfs_d.len NOT BETWEEN style.from_l AND style.to_l
               OR sanfs_d.wid NOT BETWEEN style.from_w AND style.to_w
              );


DROP VIEW ACCOUNTS.CUST_PAL_AMT_N;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUST_PAL_AMT_N
(CUST_NO, CUST_NAME, PAL_AMT)
AS 
SELECT   cust.cust_no, cust.cust_name, SUM (entry_sub.entry_mnt) pal_amt
       FROM cust, entry_sub
      WHERE entry_sub.giving = cust.cust_no 
      AND CUST.ACC_NO = ENTRY_SUB.ACC_NO
   GROUP BY cust.cust_no, cust.cust_name
     HAVING SUM (entry_sub.entry_mnt) <> 0;


DROP VIEW ACCOUNTS.SALES_BILL_UN_ENTERY;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.SALES_BILL_UN_ENTERY
(BILL_NO, YEAR, BILL_TYPE, DAT, CUST_NO, 
 TOTAL, SANF_NUMS, DETAILES, CUR_NO, CUR_PRICE, 
 STORE_NO, ENTRY_NO, CUST_NAME, DIS_RATE, DISCOUNT, 
 NET, CUR_NO1, CUR_PRICE1, SEQ_PRICE, SEQ_PRICE1, 
 SELECT1, ACC_NO, ACC_NO1, MANUAL_BILL_NO, AMOUNT_PAID, 
 IS_GIVING, GIVING_DATE, HANDING_DATE, IS_UNIFORM, TEL_NO1, 
 TEL_NO2, ADDRESS, IS_READY, BENEFICIARY_NAME, POST, 
 THE_TIME, REF_NO, PERMANENT_CUST, GIVING_TIME, AM_PM, 
 URGENT, HOURSE, PRINT_TIMES, CUR_PRICE$, CUR_PRICE_SR, 
 EQUIVALENT_CURRENCY, CUTTING_OR_SLAES, HANDING_TIME, PAYMENT_METHOD, OTHERS_PAYMENTS, 
 VOUCHER_NO, TRANSFER_TO_ACC_NO, TRANSFER_TO_ACC_NAME, GUARANTEE_ACC_NO, GUARANTEE_ACC_NAME, 
 HANDING_DONE, ACC_NO2, FIRST_TRANSFER, TRANSFER_THROUGH, BILLS_KINDS, 
 CUST_KNOWN, BRANCH_NO, CREATED_ON, CREATED_BY, LAST_UPDATED_ON, 
 LAST_UPDATED_BY, CREATED_BY_NAME, LAST_UPDATED_BY_NAME, MAIN_BILL, GROUP_NO, 
 HAND_SALER_DATE, HAND_SALER_ENTRY_NO, HAND_SALER_DETAILES, HAND_MANUAL_C_NO, SEND_DONE, 
 TEL_NO, SEND_MESSAGE, LAST_UPDATE_TIME, OHID, ORDSID, 
 TR_INV_M_ID)
AS 
select "BILL_NO","YEAR","BILL_TYPE","DAT","CUST_NO","TOTAL","SANF_NUMS","DETAILES","CUR_NO","CUR_PRICE","STORE_NO","ENTRY_NO","CUST_NAME","DIS_RATE","DISCOUNT","NET","CUR_NO1","CUR_PRICE1","SEQ_PRICE","SEQ_PRICE1","SELECT1","ACC_NO","ACC_NO1","MANUAL_BILL_NO","AMOUNT_PAID","IS_GIVING","GIVING_DATE","HANDING_DATE","IS_UNIFORM","TEL_NO1","TEL_NO2","ADDRESS","IS_READY","BENEFICIARY_NAME","POST","THE_TIME","REF_NO","PERMANENT_CUST","GIVING_TIME","AM_PM","URGENT","HOURSE","PRINT_TIMES","CUR_PRICE$","CUR_PRICE_SR","EQUIVALENT_CURRENCY","CUTTING_OR_SLAES","HANDING_TIME","PAYMENT_METHOD","OTHERS_PAYMENTS","VOUCHER_NO","TRANSFER_TO_ACC_NO","TRANSFER_TO_ACC_NAME","GUARANTEE_ACC_NO","GUARANTEE_ACC_NAME","HANDING_DONE","ACC_NO2","FIRST_TRANSFER","TRANSFER_THROUGH","BILLS_KINDS","CUST_KNOWN","BRANCH_NO","CREATED_ON","CREATED_BY","LAST_UPDATED_ON","LAST_UPDATED_BY","CREATED_BY_NAME","LAST_UPDATED_BY_NAME","MAIN_BILL","GROUP_NO","HAND_SALER_DATE","HAND_SALER_ENTRY_NO","HAND_SALER_DETAILES","HAND_MANUAL_C_NO","SEND_DONE","TEL_NO","SEND_MESSAGE","LAST_UPDATE_TIME","OHID","ORDSID","TR_INV_M_ID" from sales_bill where
ENTRY_NO not in (select
   ENTRY_NO  from ENTRY_SUB
)
and  BILLS_KINDS in (1,4);


CREATE OR REPLACE TRIGGER ACCOUNTS.SEQ_BILL_TRG
BEFORE INSERT  
ON ACCOUNTS.SALES_BILL 
REFERENCING NEW AS New 
FOR EACH ROW
BEGIN 
  IF :NEW.OHID IS NULL THEN
--UPDATE ACCOUNTS.SALES_BILL
--SET
 :NEW.OHID :=SUBSTR(:NEW.YEAR,3,2)||:NEW.BILL_TYPE||:NEW.CUTTING_OR_SLAES||:NEW.MANUAL_BILL_NO;
--COMMIT;
END IF;
END;
/
SHOW ERRORS;


DROP PUBLIC SYNONYM CUST_PAL_AMT_N;

CREATE PUBLIC SYNONYM CUST_PAL_AMT_N FOR ACCOUNTS.CUST_PAL_AMT_N;


ALTER TABLE ACCOUNTS.CASH_RECEIVE
 DROP PRIMARY KEY CASCADE;
DROP TABLE ACCOUNTS.CASH_RECEIVE CASCADE CONSTRAINTS PURGE;

CREATE TABLE ACCOUNTS.CASH_RECEIVE
(
  C_NO                  NUMBER(8),
  ACC_NO                NUMBER(14)              NOT NULL,
  ACC_NAME              VARCHAR2(150 BYTE)      NOT NULL,
  AMOUNT                NUMBER(15,2)            NOT NULL,
  C_DATE                DATE                    NOT NULL,
  YEAR                  NUMBER(4),
  DETAILES              VARCHAR2(250 BYTE)      NOT NULL,
  TYPE                  VARCHAR2(250 BYTE)      NOT NULL,
  ENTRY_NO              NUMBER(11)              NOT NULL,
  CUR_NO                NUMBER(2)               NOT NULL,
  INVOICE_NO            NUMBER(12),
  PRE_ACC_NAME          VARCHAR2(150 BYTE),
  BILL_NO               NUMBER(10),
  BILL_YEAR             NUMBER(4),
  CREATED_ON            DATE,
  CREATED_BY            NUMBER(3),
  LAST_UPDATED_ON       DATE,
  LAST_UPDATED_BY       NUMBER(3),
  CREATED_BY_NAME       VARCHAR2(100 BYTE),
  LAST_UPDATED_BY_NAME  VARCHAR2(100 BYTE),
  CREATED_TIME          VARCHAR2(20 BYTE),
  UPDATE_TIME           VARCHAR2(20 BYTE),
  TEL_NO                NUMBER(9),
  SEND_MESSAGE          NUMBER(1),
  BRANCH_NO             NUMBER(5),
  MANUAL_C_NO           NUMBER(20),
  CUST_NO               NUMBER,
  CUR_PRICE             NUMBER                  DEFAULT 1,
  ACC_NO1               NUMBER
)
TABLESPACE SYSTEM
PCTUSED    40
PCTFREE    10
INITRANS   1
MAXTRANS   255
STORAGE    (
            INITIAL          2M
            MINEXTENTS       1
            MAXEXTENTS       UNLIMITED
            PCTINCREASE      0
            FREELISTS        1
            FREELIST GROUPS  1
            BUFFER_POOL      DEFAULT
           )
LOGGING 
NOCOMPRESS 
NOCACHE
NOPARALLEL
MONITORING;

COMMENT ON COLUMN ACCOUNTS.CASH_RECEIVE.TYPE IS 'amount in char';


