DROP PACKAGE ACCOUNTS.GET_DATE_PKG;

CREATE OR REPLACE PACKAGE ACCOUNTS.GET_DATE_PKG
AS
  FUNCTION START_DATE_QID
     RETURN DATE;
  FUNCTION START_DATE_CASH_RECEIVE
     RETURN DATE;
FUNCTION START_DATE_CASH_SARF
     RETURN DATE;
FUNCTION START_DATE_BANK_RECEIVE
     RETURN DATE;
FUNCTION START_DATE_BANK_SARF
     RETURN DATE;
FUNCTION START_DATE_STORE(NO IN NUMBER)
     RETURN DATE;

  FUNCTION CLOSED_MONTHS_FUN
     RETURN DATE;

  PROCEDURE OPEN_CLOSE_YEAR( START_DATE_VAR OUT DATE, END_DATE_VAR OUT DATE);

END GET_DATE_PKG;
/

SHOW ERRORS;


DROP PACKAGE BODY ACCOUNTS.GET_DATE_PKG;

CREATE OR REPLACE PACKAGE BODY ACCOUNTS.GET_DATE_PKG
AS

  FUNCTION START_DATE_QID
     RETURN DATE
  IS

X DATE;
Y DATE;
YEAR1 VARCHAR2(20);
MONTH1 VARCHAR2(20);
DATE1 DATE;

BEGIN

SELECT NVL(MAX(YEAR),'2000')INTO YEAR1 FROM ACCOUNTS.CLOSED_MONTHS;
SELECT NVL(MAX(MONTH),'1') INTO MONTH1 FROM ACCOUNTS.CLOSED_MONTHS WHERE YEAR=YEAR1;

select mon_name into MONTH1 from ACCOUNTS.date_acc where mon_no=MONTH1;


DATE1:=LAST_DAY(1||'-'||MONTH1||'-'||YEAR1);


  SELECT NVL(MAX(ENTRY_DATE),DATE1+1) INTO X FROM ACCOUNTS.ENTRY_MAIN2;
  SELECT NVL(MAX(ENTRY_DATE),DATE1+1) INTO Y FROM ACCOUNTS.ENTRY_MAIN;
IF X>Y THEN
IF X>DATE1 THEN
  RETURN X;
ELSE
  RETURN DATE1+1;
END IF;

ELSE

IF Y>DATE1 THEN
  RETURN Y;
ELSE
  RETURN DATE1+1;
END IF;

END IF;

END;


  FUNCTION START_DATE_CASH_SARF
     RETURN DATE
  IS

X DATE;
Y DATE;
YEAR1 VARCHAR2(20);
MONTH1 VARCHAR2(20);
DATE1 DATE;

BEGIN

SELECT NVL(MAX(YEAR),'2000')INTO YEAR1 FROM ACCOUNTS.CLOSED_MONTHS;
SELECT NVL(MAX(MONTH),'1') INTO MONTH1 FROM ACCOUNTS.CLOSED_MONTHS WHERE YEAR=YEAR1;

select mon_name into MONTH1 from ACCOUNTS.date_acc where mon_no=MONTH1;


DATE1:=LAST_DAY(1||'-'||MONTH1||'-'||YEAR1);


  SELECT NVL(MAX(C_DATE),DATE1+1) INTO X FROM ACCOUNTS.CASH_SARF;

IF X>DATE1 THEN
  RETURN X;
ELSE
  RETURN DATE1+1;
END IF;


END;


FUNCTION START_DATE_CASH_RECEIVE
     RETURN DATE
  IS

X DATE;
Y DATE;
YEAR1 VARCHAR2(20);
MONTH1 VARCHAR2(20);
DATE1 DATE;

BEGIN

SELECT NVL(MAX(YEAR),'2000')INTO YEAR1 FROM ACCOUNTS.CLOSED_MONTHS;
SELECT NVL(MAX(MONTH),'1') INTO MONTH1 FROM ACCOUNTS.CLOSED_MONTHS WHERE YEAR=YEAR1;

select mon_name into MONTH1 from ACCOUNTS.date_acc where mon_no=MONTH1;


DATE1:=LAST_DAY(1||'-'||MONTH1||'-'||YEAR1);


  SELECT NVL(MAX(C_DATE),DATE1+1) INTO X FROM ACCOUNTS.CASH_RECEIVE;

IF X>DATE1 THEN
  RETURN X;
ELSE
  RETURN DATE1+1;
END IF;


END;


FUNCTION START_DATE_BANK_RECEIVE
     RETURN DATE
  IS

X DATE;
Y DATE;
YEAR1 VARCHAR2(20);
MONTH1 VARCHAR2(20);
DATE1 DATE;

BEGIN

SELECT NVL(MAX(YEAR),'2000')INTO YEAR1 FROM ACCOUNTS.CLOSED_MONTHS;
SELECT NVL(MAX(MONTH),'1') INTO MONTH1 FROM ACCOUNTS.CLOSED_MONTHS WHERE YEAR=YEAR1;

select mon_name into MONTH1 from ACCOUNTS.date_acc where mon_no=MONTH1;


DATE1:=LAST_DAY(1||'-'||MONTH1||'-'||YEAR1);


  SELECT NVL(MAX(B_DATE),DATE1+1) INTO X FROM ACCOUNTS.BANK_RECEIVE;

IF X>DATE1 THEN
  RETURN X;
ELSE
  RETURN DATE1+1;
END IF;


END;


FUNCTION START_DATE_BANK_SARF
     RETURN DATE
  IS

X DATE;
Y DATE;
YEAR1 VARCHAR2(20);
MONTH1 VARCHAR2(20);
DATE1 DATE;

BEGIN

SELECT NVL(MAX(YEAR),'2000')INTO YEAR1 FROM ACCOUNTS.CLOSED_MONTHS;
SELECT NVL(MAX(MONTH),'1') INTO MONTH1 FROM ACCOUNTS.CLOSED_MONTHS WHERE YEAR=YEAR1;

select mon_name into MONTH1 from ACCOUNTS.date_acc where mon_no=MONTH1;


DATE1:=LAST_DAY(1||'-'||MONTH1||'-'||YEAR1);


  SELECT NVL(MAX(B_DATE),DATE1+1) INTO X FROM ACCOUNTS.BANK_SARF;

IF X>DATE1 THEN
  RETURN X;
ELSE
  RETURN DATE1+1;
END IF;


END;

FUNCTION START_DATE_STORE(NO IN NUMBER)
     RETURN DATE
  IS

X DATE;
Y DATE;
YEAR1 VARCHAR2(20);
MONTH1 VARCHAR2(20);
DATE1 DATE;

BEGIN

SELECT NVL(MAX(YEAR),'2000')INTO YEAR1 FROM ACCOUNTS.CLOSED_MONTHS;
SELECT NVL(MAX(MONTH),'1') INTO MONTH1 FROM ACCOUNTS.CLOSED_MONTHS WHERE YEAR=YEAR1;

select mon_name into MONTH1 from ACCOUNTS.date_acc where mon_no=MONTH1;


DATE1:=LAST_DAY(1||'-'||MONTH1||'-'||YEAR1);

IF NO=0 THEN

  SELECT NVL(MAX(DAT),DATE1+1) INTO X FROM ACCOUNTS.BUY_BILL;
ELSIF NO=1 THEN
  SELECT NVL(MAX(RET_DATE),DATE1+1) INTO X FROM ACCOUNTS.RETURN_SALES;
ELSIF NO=2 THEN
  SELECT NVL(MAX(DAT),DATE1+1) INTO X FROM ACCOUNTS.SALES_BILL;
ELSIF NO=3 THEN
  SELECT NVL(MAX(RET_DATE),DATE1+1) INTO X FROM ACCOUNTS.RETURN_BUY;
ELSIF NO=4 OR NO=5 THEN
  SELECT NVL(MAX(MOVE_DATE),DATE1+1) INTO X FROM ACCOUNTS.MOVE_STORE;
ELSIF NO=6 THEN
  SELECT NVL(MAX(GARD_DATE),DATE1+1) INTO X FROM ACCOUNTS.GARD;
ELSIF NO=10 THEN
  SELECT NVL(MAX(TASWYA_DATE),DATE1+1) INTO X FROM ACCOUNTS.DEBIT_TASWYA_QTY;
ELSIF NO=11 THEN
  SELECT NVL(MAX(TASWYA_DATE),DATE1+1) INTO X FROM ACCOUNTS.CREDIT_TASWYA_QTY;
ELSIF NO=12 THEN
  SELECT NVL(MAX(DAT),DATE1+1) INTO X FROM ACCOUNTS.INVENTORY_RECEIVE;
ELSIF NO=13 THEN
  SELECT NVL(MAX(DAT),DATE1+1) INTO X FROM ACCOUNTS.INVENTORY_SARF;
ELSIF NO=50 THEN
  SELECT NVL(MAX(EXP_DATE),DATE1+1) INTO X FROM ACCOUNTS.BUY_EXP;

END IF;

IF X>DATE1 THEN
  RETURN X;
ELSE
  RETURN DATE1+1;
END IF;


END;



  FUNCTION CLOSED_MONTHS_FUN
     RETURN DATE
  IS

YEAR1 VARCHAR2(20);
MONTH1 VARCHAR2(20);
DATE1 DATE;

BEGIN

SELECT NVL(MAX(YEAR),'2000')INTO YEAR1 FROM ACCOUNTS.CLOSED_MONTHS;
SELECT NVL(MAX(MONTH),'1') INTO MONTH1 FROM ACCOUNTS.CLOSED_MONTHS WHERE YEAR=YEAR1;

select mon_name into MONTH1 from ACCOUNTS.date_acc where mon_no=MONTH1;


DATE1:=LAST_DAY(1||'-'||MONTH1||'-'||YEAR1);

RETURN DATE1;

END;


 PROCEDURE OPEN_CLOSE_YEAR( START_DATE_VAR OUT DATE, END_DATE_VAR OUT DATE)
  IS

SEQ_VAR NUMBER(20);

BEGIN

SELECT NVL(MAX(SEQ),0)INTO SEQ_VAR FROM ACCOUNTS.OPEN_CLOSE_YEAR;

SELECT START_DATE,END_DATE INTO START_DATE_VAR,END_DATE_VAR FROM ACCOUNTS.OPEN_CLOSE_YEAR
 WHERE SEQ=SEQ_VAR;

EXCEPTION WHEN NO_DATA_FOUND THEN
	START_DATE_VAR:='01/01/2000';
	END_DATE_VAR:='31/12/2000';
END;

END GET_DATE_PKG;
/

SHOW ERRORS;


