DROP VIEW ACCOUNTS.CUST_NOT_HANDING_AMOUNT_D;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUST_NOT_HANDING_AMOUNT_D
(ACC_NO, CUST_NO, CUST_NAME, MAX_INVIOCE, BILLNO, 
 MAXHAINDIG, QTY, QHANDING, PAL, TOTAL, 
 DISCOUNT, NET, AMOUNT_PAID, UNPAID)
AS 
SELECT   chart_acc.acc_no, NVL (sales_bill.cust_no, chart_acc.acc_no),
            chart_acc.acc_name cust_name, MAX (sales_bill.dat) max_invioce,
            sales_bill.YEAR || sales_bill.bill_no,
            MAX (sales_bill.handing_date) maxhaindig, SUM (qty),
            SUM (NVL (handing_done1, 0)),
            SUM (NVL (qty, 1)) - SUM (NVL (handing_done1, 0)) pal,
            SUM (total) total, SUM (discount) discount, SUM (net) net,
            SUM (NVL (amount_paid, 0)) amount_paid,
            SUM (NVL (net, 0)) - SUM (NVL (amount_paid, 0)) unpaid
       FROM sales_bill, multi_cloths, chart_acc
      WHERE sales_bill.bill_no = multi_cloths.bill_no
--AND  SALES_BILL.DAT BETWEEN '01/03/2025' AND '05/05/2025'
        AND sales_bill.YEAR = multi_cloths.YEAR
        AND chart_acc.acc_no = sales_bill.acc_no
        AND NVL (sales_bill.bills_kinds, 1) NOT IN (2, 3, 4)
   -- AND entry_sub.acc_no = chart_acc.acc_no
   GROUP BY chart_acc.acc_no,
            sales_bill.YEAR || sales_bill.bill_no,
            chart_acc.acc_name,
            NVL (sales_bill.cust_no, chart_acc.acc_no)
     HAVING SUM (NVL (qty, 1)) - SUM (NVL (handing_done1, 0)) <> 0;


DROP VIEW ACCOUNTS.CUST_NOT_HANDING_AMOUNT_B;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUST_NOT_HANDING_AMOUNT_B
(ACC_NO, CUST_NO, CUST_NAME, MAX_INVIOCE, BILLNO, 
 MANUAL_BILL_NO, MAXHAINDIG, QTY, QHANDING, PAL, 
 TOTAL, DISCOUNT, NET, AMOUNT_PAID, UNPAID, 
 BALANCE)
AS 
SELECT   chart_acc.acc_no, NVL (sales_bill.cust_no, chart_acc.acc_no),
            chart_acc.acc_name cust_name, MAX (sales_bill.dat) max_invioce,
            sales_bill.YEAR || sales_bill.bill_no, sales_bill.manual_bill_no,
            MAX (sales_bill.handing_date) maxhaindig, SUM (qty),
            DECODE (NVL (MAX (handing_done1), 0), 1, SUM (NVL (qty, 1)), 0),
              SUM (NVL (qty, 1))
            - DECODE (NVL (MAX (handing_done1), 0), 1, SUM (NVL (qty, 1)), 0)
                                                                          pal,
            MAX (total) total, MAX (discount) discount, MAX (net) net,
            MAX (NVL (amount_paid, 0)) amount_paid,
            MAX (NVL (net, 0)) - MAX (NVL (amount_paid, 0)) unpaid,
            MAX (balance) balance
       FROM sales_bill, multi_cloths, chart_acc
      WHERE sales_bill.bill_no = multi_cloths.bill_no
--AND  SALES_BILL.DAT BETWEEN '01/03/2025' AND '05/05/2025'
        AND sales_bill.YEAR = multi_cloths.YEAR
        AND chart_acc.acc_no = sales_bill.acc_no
        AND NVL (sales_bill.bills_kinds, 1) NOT IN (2, 3, 4)
   -- AND entry_sub.acc_no = chart_acc.acc_no
   GROUP BY chart_acc.acc_no,
            sales_bill.YEAR || sales_bill.bill_no,
            sales_bill.manual_bill_no,
            chart_acc.acc_name,
            NVL (sales_bill.cust_no, chart_acc.acc_no)
     HAVING   SUM (NVL (qty, 1))
            - DECODE (NVL (MAX (handing_done1), 0), 1, SUM (NVL (qty, 1)), 0) <>
                                                                             0;


