DROP VIEW ACCOUNTS.SANF_D_TR;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.SANF_D_TR
(SANF_NO, SANF_NAME, SANF_CODE, SANFCODE, STYL_NO, 
 PART_NO, NOTES, SIZE_FRM, SIZE_TO, COLOR_NO, 
 CAT, CO)
AS 
SELECT   sanfs.sanf_no, sanfs.sanf_name, sanf_code, sanfcode,
            sanfs.styl_no, sanfs.part_no, sanfs.notes, size_frm, size_to,
            trans_detailes.color_no, sanfs.CATEGORY, COUNT (*) co
       FROM trans_detailes, sanfs
      WHERE sanfs.sanf_no = trans_detailes.sanf_no AND active = 1
     HAVING COUNT (*) > 1
   GROUP BY sanfs.sanf_no,
            sanfs.sanf_name,
            sanf_code,
            sanfcode,
            sanfs.styl_no,
            sanfs.part_no,
            sanfs.notes,
            size_frm,
            size_to,
            trans_detailes.color_no,
            sanfs.CATEGORY
   ORDER BY part_no, trans_detailes.color_no, size_frm, size_to;


