          sales_bill.cutting_or_slaes, sales_bill.bills_kinds,
          sales_bill.acc_no, giving_date, beneficiary_name, tel_no1,
          sales_bill.total, discount, group_no, sales_detailes_shapes.l1,
          sales_detailes_shapes.l5, 0 sanf_price, sales_bill.handing_date,
          cust_name, sales_bill.net, multi_cloths.cut_created_by,
          multi_cloths.cut_transfer_no, multi_cloths.cut_transfer_date,
