DROP VIEW ACCOUNTS.CUTTER_TO_QTY;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUTTER_TO_QTY
(CUTTER_NO, CUTTER_NAME, DDATE, STYLE_NAME, SQTY, 
 AMT)
AS 
SELECT   cutter_no1, cutter_name, ddate, style_name,
            SUM (cutting_bill_in_cut.qty) sqty,
            (SUM (  cutting_bill_in_cut.cutter_pcs_price1
                  * cutting_bill_in_cut.qty
                 )
            ) amt
       FROM cutting_bill_in_cut
      WHERE
-- AND TO_CHAR(CUTING_TRANSD.DDATE,'DD/MM/YYYY')=:DDATE
      --  AND multi_cloths.ohid = cutting_bill_in_cut.ohid
            ordsid = 2
   GROUP BY cutter_no1, cutter_name, ddate, style_name;


DROP VIEW ACCOUNTS.CUTTER_FROM_QTY;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUTTER_FROM_QTY
(CUTTER_NO, CUTTER_NAME, DDATE, CUTTING_DATE, STYLE_NAME, 
 SQTY, POST, UN, AMT)
AS 
SELECT   cutter_no1, cutter_name,  (ddate) ddate, NVL(MAX(cutting_date),MAX(ddate)),
            style_name, SUM (cutting_bill_in_cut.qty) sqty, SUM (POST) POST,
            SUM (cutting_bill_in_cut.qty) - SUM (POST) un,
            (SUM (cutting_bill_in_cut.cutter_pcs_price1 * POST)) amt
       FROM cutting_bill_in_cut
      WHERE 
      --ordsid = 2
      1=1
   -- AND TO_CHAR(CUTING_TRANSD.DDATE,'DD/MM/YYYY')=:DDATE
    --  AND multi_cloths.ohid = cutting_bill_in_cut.ohid

   --  AND POST=1
   GROUP BY cutter_no1, cutter_name,ddate, style_name;


DROP VIEW ACCOUNTS.CUTTER_FROM_CALC;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUTTER_FROM_CALC
(CUTTER_NO, CUTTER_NAME, DDATE, CUTTING_DATE, STYLE_NAME, 
 SQTY, POST, UN, AMT)
AS 
SELECT   cutter_no1, cutter_name, MAX (ddate) ddate, cutting_date,
            style_name, SUM (cutting_bill_in_cut.qty) sqty, SUM (POST) POST,
            SUM (cutting_bill_in_cut.qty) - SUM (POST) un,
            (SUM (cutting_bill_in_cut.cutter_pcs_price1 * POST)) amt
       FROM cutting_bill_in_cut
      WHERE
-- AND TO_CHAR(CUTING_TRANSD.DDATE,'DD/MM/YYYY')=:DDATE
      --  AND multi_cloths.ohid = cutting_bill_in_cut.ohid
            ordsid = 2 AND calc_cutter = 1
   --  AND POST=1
   GROUP BY cutter_no1, cutter_name, cutting_date, style_name;


DROP VIEW ACCOUNTS.CUTTING_BILL_IN_TAILOR;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUTTING_BILL_IN_TAILOR
(OHID, OHDID, SEQ_NO1, BILL_NO, MANUAL_BILL_NO, 
 TR_INV_M_ID, TR_INV_D_ID, YEAR, DAT, DDATE, 
 ORDSTAT_NAME, ORDSID, POST, CALC_CUTTER, CALC_TAILOR, 
 SANF_NO, SANF_DNO, CLOTH_TYPE, CONSUMED_CLOTH_QTY_HINSH, CONSUMED_CLOTH_QTY_YARDS, 
 SEQ_NO, CLOTH_FRM_LOCAL_STORE, QTY, SHAPE_STYLE_NO, CLOTH_NAME, 
 CLOTHS_COLOR, CUTTING_DATE, CUTTING_DONE, CUTTER_NO1, CUTTER_NAME, 
 CUTTER_PCS_PRICE1, TAILOR_DATE, TAILOR_DONE, TAILOR_NO1, TAILOR_NAME1, 
 TAILOR_PCS_PRICE1, BUTTON_TYPE1, GERAMA_DONE, GERAMA_NO, GERAMA_NAME, 
 GERAMA_PCS_PRICE, KAWYA_DONE, KAWYA_NO, KAWYA_NAME, KAWYA_PCS_PRICE, 
 HANDING_DONE1, HANDING_DATE1, TIME1, FIXED_FLEXED, SHELF_NO, 
 CLOTHS_OUR_SELECTION, STYLE_NAME, BATCH_NO_PRINT, CLOTHS_COLOR2, BILL_TYPE, 
 HANDING_DONE, CUTTING_OR_SLAES, BILLS_KINDS, ACC_NO, GIVING_DATE, 
 BENEFICIARY_NAME, TEL_NO1, TOTAL, DISCOUNT, GROUP_NO, 
 SIZE_FRM, SIZE_TO, SANF_PRICE, HANDING_DATE, CUST_NAME, 
 NET, CUT_CREATED_BY, CUT_TRANSFER_NO, CUT_TRANSFER_DATE, TAILOR_CREATED_BY, 
 TAILOR_TRANSFER_NO, TAILOR_TRANSFER_DATE, CREATED_BY_NAME, UPDATED_BY_NAME, GABZOR_HAND, 
 ADDCOST1, ADDCOST2, ADDCOST3)
AS 
SELECT multi_cloths.ohid, multi_cloths.ohdid, multi_cloths.seq_no1,
          multi_cloths.bill_no, sales_bill.manual_bill_no,
          cuting_transd.tr_inv_m_id, tr_inv_d_id, multi_cloths.YEAR,
          sales_bill.dat, ddate,
                                -- TO_DATE (TO_CHAR ( 'DD-Mon-YYYY')) ddate,
                                ordstate.ordsname, cuting_transd.ordsid,
          cuting_transd.POST, calc_cutter, calc_tailor, multi_cloths.sanf_no,
          multi_cloths.sanf_dno, multi_cloths.cloth_type,
          multi_cloths.consumed_cloth_qty_hinsh,
          multi_cloths.consumed_cloth_qty_yards, multi_cloths.seq_no,
          multi_cloths.cloth_frm_local_store, multi_cloths.qty,
          multi_cloths.shape_style_no, multi_cloths.cloth_name,
          multi_cloths.cloths_color, multi_cloths.cutting_date,
          multi_cloths.cutting_done, multi_cloths.cutter_no1,
          cutter.cutter_name, multi_cloths.cutter_pcs_price1, tailor_date,
          multi_cloths.tailor_done, multi_cloths.tailor_no1,
          tailor.tailor_name, multi_cloths.tailor_pcs_price1,
          multi_cloths.button_type1, multi_cloths.gerama_done,
          multi_cloths.gerama_no, multi_cloths.gerama_name,
          multi_cloths.gerama_pcs_price, multi_cloths.kawya_done,
          multi_cloths.kawya_no, multi_cloths.kawya_name,
          multi_cloths.kawya_pcs_price, multi_cloths.handing_done1,
          multi_cloths.handing_date1, multi_cloths.time1,
          multi_cloths.fixed_flexed, multi_cloths.shelf_no,
          multi_cloths.cloths_our_selection, TYPES.type_name,
          multi_cloths.batch_no_print, multi_cloths.cloths_color2,
          sales_bill.bill_type, sales_bill.handing_done,
          sales_bill.cutting_or_slaes, sales_bill.bills_kinds,
          sales_bill.acc_no, giving_date, beneficiary_name, tel_no1,
          sales_bill.total, discount, TYPES.group_no,
          sales_detailes_shapes.l1, sales_detailes_shapes.l5, 0 sanf_price,
          sales_bill.handing_date, cust_name, sales_bill.net,
          multi_cloths.cut_created_by, multi_cloths.cut_transfer_no,
          multi_cloths.cut_transfer_date, multi_cloths.tailor_created_by,
          multi_cloths.tailor_transfer_no, multi_cloths.tailor_transfer_date,
          cuting_transd.created_by_name, cuting_transd.updated_by_name, 
          NVL(multi_cloths.GABZOR_HAND,0), NVL(multi_cloths.ADDCOST1,0), 
          NVL(multi_cloths.ADDCOST2,0), NVL(multi_cloths.ADDCOST3,0)
     FROM sales_bill,
          ordstate,
          sales_detailes_shapes,
          multi_cloths,
          cuting_transd,
          cutter,
          TYPES,
          tailor
    WHERE (multi_cloths.bill_no = sales_bill.bill_no)
      AND cuting_transd.ordsid = ordstate.ordsid
      AND (multi_cloths.YEAR = sales_bill.YEAR)
      AND multi_cloths.cutter_no1 = cutter.cutter_no
      AND multi_cloths.tailor_no1 = tailor.tailor_no
      AND (multi_cloths.ohid = sales_bill.ohid)
      AND (multi_cloths.ohid = sales_detailes_shapes.ohid)
      AND (sales_detailes_shapes.bill_no = sales_bill.bill_no)
      AND (sales_detailes_shapes.YEAR = sales_bill.YEAR)
      AND (sales_detailes_shapes.ohid = sales_bill.ohid)
      AND (sales_detailes_shapes.seq_no = multi_cloths.seq_no)
      AND (DECODE (NVL (sales_detailes_shapes.shape_style_no, 1),
                   1, 301,
                   2, 302,
                   3, 303,
                   4, 304,
                   5, 305,
                   6, 306,
                   7, 307,
                   8, 308,
                   9, 309,
                   10, 310,
                   11, 311,
                   301
                  ) = TYPES.type_no
          )
      --AND (30 || NVL (sales_detailes_shapes.shape_style_no, 1) = TYPES.type_no)
      AND (multi_cloths.ohid = cuting_transd.ohid)
      AND (multi_cloths.ohdid = cuting_transd.ohdid)
      AND (sales_bill.ohid = cuting_transd.ohid)
      --AND (sales_detailes_shapes.ohdid = cuting_transd.ohdid)
      AND (sales_detailes_shapes.ohid = cuting_transd.ohid)
      AND seq_no1 = cuting_transd.seq_no
      AND cuting_transd.ordsid = 6
      AND CANCEL <> 1
      AND NVL (sales_bill.handing_done, 0) IN (1, 0)
      AND sales_bill.bills_kinds NOT IN (2, 3, 4)
      --AND NVL (multi_cloths.cutting_done, 0) <> 1
     -- AND multi_cloths.cutter_no1 IS NOT NULL
-- and multi_cloths.FIXED_FLEXED is null;;;;;;;;;;;;;;;;;;;;;;;;;;;;;


