    WHERE (multi_cloths.bill_no = sales_bill.bill_no)
      AND cuting_transd.ordsid = ordstate.ordsid
      AND (multi_cloths.YEAR = sales_bill.YEAR)
      AND multi_cloths.cutter_no1 = cutter.cutter_no
      AND multi_cloths.tailor_no1 = tailor.tailor_no
      AND (multi_cloths.ohid = sales_bill.ohid)
      AND (multi_cloths.ohid = sales_detailes_shapes.ohid)
      AND (sales_detailes_shapes.bill_no = sales_bill.bill_no)
      AND (sales_detailes_shapes.YEAR = sales_bill.YEAR)
      AND (sales_detailes_shapes.ohid = sales_bill.ohid)
      AND (sales_detailes_shapes.seq_no = multi_cloths.seq_no)
      AND (multi_cloths.ohid = cuting_transd.ohid)
      AND (multi_cloths.ohdid = cuting_transd.ohdid)
      AND (sales_bill.ohid = cuting_transd.ohid)
      AND (sales_detailes_shapes.ohdid = cuting_transd.ohdid)
      AND (sales_detailes_shapes.ohid = cuting_transd.ohid)
      AND seq_no1 = cuting_transd.seq_no
      AND cuting_transd.ordsid = 9
      AND NVL (sales_bill.handing_done, 0) <> 1
      AND sales_bill.bills_kinds NOT IN (2, 3, 4)
      and nvl(multi_cloths.F_CANCEL,0)=0
      --AND NVL (multi_cloths.cutting_done, 0) <> 1
     -- AND multi_cloths.cutter_no1 IS NOT NULL
-- and multi_cloths.FIXED_FLEXED is null;;;;;;;;;;;;;;;;;;;;;;;;;


DROP VIEW ACCOUNTS.TAILOR_TO_QTY;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.TAILOR_TO_QTY
(TAILOR_NO, TAILOR_NAME, DDATE, TAILOR_DATE, STYLE_NAME, 
 SQTY, POST, UN, AMT)
AS 
SELECT   tailor_no1, tailor_name1, MAX (ddate) ddate, ddate tailor_date,
            style_name, SUM (cutting_bill_in_tailor.qty) sqty, SUM (POST)
                                                                         POST,
            SUM (cutting_bill_in_tailor.qty) - SUM (POST) un,
            NVL ((SUM (cutting_bill_in_tailor.tailor_pcs_price1 * POST)),
                 0
                ) amt
       FROM cutting_bill_in_tailor
      WHERE
-- AND TO_CHAR(CUTING_TRANSD.DDATE,'DD/MM/YYYY')=:DDATE
      --  AND multi_cloths.ohid = cutting_bill_in_cut.ohid
            ordsid = 6
   --  AND POST=1
   GROUP BY tailor_no1, tailor_name1, ddate, style_name;


DROP VIEW ACCOUNTS.TAILOR_FROM_QTY;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.TAILOR_FROM_QTY
(TAILOR_NO, TAILOR_NAME, DDATE, TAILOR_DATE, STYLE_NAME, 
 SQTY, POST, UN, AMT)
AS 
SELECT   tailor_no1, tailor_name1, MAX (ddate) ddate,
            NVL (tailor_date, MAX (ddate)), style_name,
            SUM (cutting_bill_in_tailor.qty) sqty,
            DECODE (POST, 0, 0, SUM (cutting_bill_in_tailor.qty)) POST,
              SUM (cutting_bill_in_tailor.qty)
            - DECODE (POST, 0, 0, SUM (cutting_bill_in_tailor.qty)) un,
            (SUM (cutting_bill_in_tailor.tailor_pcs_price1 * POST)) amt
       FROM cutting_bill_in_tailor
      WHERE
-- AND TO_CHAR(CUTING_TRANSD.DDATE,'DD/MM/YYYY')=:DDATE
      --  AND multi_cloths.ohid = cutting_bill_in_cut.ohid
            ordsid = 6
   --  AND POST=1
   GROUP BY tailor_no1, tailor_name1, tailor_date, style_name, POST;


