CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUTTING_IN_DEPT
(OHID, OHDID, SEQ_NO1, BILL_NO, TR_INV_M_ID, 
 TR_INV_D_ID, YEAR, DAT, DDATE, ORDSTAT_NAME, 
 ORDSID, POST, SANF_NO, SANF_DNO, CLOTH_TYPE, 
 CONSUMED_CLOTH_QTY_HINSH, CONSUMED_CLOTH_QTY_YARDS, SEQ_NO, CLOTH_FRM_LOCAL_STORE, QTY, 
 SHAPE_STYLE_NO, CLOTH_NAME, CLOTHS_COLOR, CUTTING_DATE, CUTTING_DONE, 
 CUTTER_NO1, CUTTER_NAME, CUTTER_PCS_PRICE1, TAILOR_DONE, TAILOR_NO1, 
 TAILOR_NAME, TAILOR_PCS_PRICE1, BUTTON_TYPE1, GERAMA_DONE, GERAMA_NO, 
 GERAMA_NAME, GERAMA_PCS_PRICE, KAWYA_DONE, KAWYA_NO, KAWYA_NAME, 
 KAWYA_PCS_PRICE, HANDING_DONE1, HANDING_DATE1, TIME1, FIXED_FLEXED, 
 SHELF_NO, CLOTHS_OUR_SELECTION, STYLE_NAME, BATCH_NO_PRINT, CLOTHS_COLOR2, 
 BILL_TYPE, HANDING_DONE, CUTTING_OR_SLAES, BILLS_KINDS, ACC_NO, 
 MANUAL_BILL_NO, GIVING_DATE, BENEFICIARY_NAME, TEL_NO1, TOTAL, 
 DISCOUNT, GROUP_NO, SIZE_FRM, SIZE_TO, SANF_PRICE, 
 HANDING_DATE, CUST_NAME, NET, CUT_CREATED_BY, CUT_TRANSFER_NO, 
 CUT_TRANSFER_DATE, TAILOR_CREATED_BY, TAILOR_TRANSFER_NO, TAILOR_TRANSFER_DATE)
AS 
SELECT multi_cloths.ohid, multi_cloths.ohdid, multi_cloths.seq_no1,
          multi_cloths.bill_no, cuting_transd.tr_inv_m_id, tr_inv_d_id,
          multi_cloths.YEAR, sales_bill.dat,
          TO_CHAR (ddate, 'DD/MM/YYYY') ddate, ordstate.ordsname,
          cuting_transd.ordsid, cuting_transd.POST, multi_cloths.sanf_no,
          multi_cloths.sanf_dno, multi_cloths.cloth_type,
          multi_cloths.consumed_cloth_qty_hinsh,
          multi_cloths.consumed_cloth_qty_yards, multi_cloths.seq_no,
          multi_cloths.cloth_frm_local_store, multi_cloths.qty,
          multi_cloths.shape_style_no, multi_cloths.cloth_name,
          multi_cloths.cloths_color, multi_cloths.cutting_date,
          multi_cloths.cutting_done, multi_cloths.cutter_no1, cutter_name,
          multi_cloths.cutter_pcs_price1, multi_cloths.tailor_done,
          multi_cloths.tailor_no1, tailor_name,
          multi_cloths.tailor_pcs_price1, multi_cloths.button_type1,
          multi_cloths.gerama_done, multi_cloths.gerama_no,
          multi_cloths.gerama_name, multi_cloths.gerama_pcs_price,
          multi_cloths.kawya_done, multi_cloths.kawya_no,
          multi_cloths.kawya_name, multi_cloths.kawya_pcs_price,
          multi_cloths.handing_done1, multi_cloths.handing_date1,
          multi_cloths.time1, multi_cloths.fixed_flexed,
          multi_cloths.shelf_no, multi_cloths.cloths_our_selection,
          sales_detailes_shapes.style_name, multi_cloths.batch_no_print,
          multi_cloths.cloths_color2, sales_bill.bill_type,
          sales_bill.handing_done, sales_bill.cutting_or_slaes,
          sales_bill.bills_kinds, sales_bill.acc_no, manual_bill_no,
          giving_date, beneficiary_name, tel_no1, sales_bill.total, discount,
          group_no, sales_detailes_shapes.l1, sales_detailes_shapes.l5,
          0 sanf_price, sales_bill.handing_date, cust_name, sales_bill.net,
          multi_cloths.cut_created_by, multi_cloths.cut_transfer_no,
          multi_cloths.cut_transfer_date, multi_cloths.tailor_created_by,
          multi_cloths.tailor_transfer_no, multi_cloths.tailor_transfer_date
     FROM sales_bill,
          sales_detailes_shapes,
          multi_cloths,
          cuting_transd,
          tailor,
          cutter,
          ordstate
    WHERE (multi_cloths.bill_no = sales_bill.bill_no)
      AND (multi_cloths.YEAR = sales_bill.YEAR)
      AND multi_cloths.cutter_no1 = cutter.cutter_no
      AND NVL(multi_cloths.tailor_no1,0) = tailor.tailor_no
      AND (multi_cloths.ohid = sales_bill.ohid)
      AND (multi_cloths.ohid = sales_detailes_shapes.ohid)
      AND (sales_detailes_shapes.bill_no = sales_bill.bill_no)
      AND (sales_detailes_shapes.YEAR = sales_bill.YEAR)
      AND (sales_detailes_shapes.ohid = sales_bill.ohid)
      AND (sales_detailes_shapes.seq_no = multi_cloths.seq_no)
      AND (multi_cloths.ohid = cuting_transd.ohid)
      AND (multi_cloths.ohdid = cuting_transd.ohdid)
      AND (sales_bill.ohid = cuting_transd.ohid)
      AND (sales_detailes_shapes.ohdid = cuting_transd.ohdid)
      AND (sales_detailes_shapes.ohid = cuting_transd.ohid)
      AND seq_no1 = cuting_transd.seq_no
      -- AND cuting_transd.ordsid = 2
      AND cuting_transd.ordsid = ordstate.ordsid
      AND cuting_transd.POST = 0
      AND NVL (sales_bill.handing_done, 0) <> 1
      --AND NVL (multi_cloths.cutting_done, 0) <> 1
     -- AND multi_cloths.cutter_no1 IS NOT NULL
-- and multi_cloths.FIXED_FLEXED is null;;;;;;;;;;;;;;;;


DROP VIEW ACCOUNTS.CUTTING_VIEW;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUTTING_VIEW
(TR_INV_D_ID, TR_INV_M_ID, OHID, OHDID, POST, 
 BILL_NO, YEAR, TYPENO, DDATE, STORENO, 
 DETAILE, ORDSNAME, STYLE_NO, STYLE_NAME, DEPTID, 
 ORDSID, DEPTNAME, CUTTER_NAME, SANF_DNO, SANF_DNAME, 
 WID, LEN, SIZE_FRM, SIZE_TO, PQTY, 
 POSTED, STK_COST, ACC_NO, SEQ_NO, TAILOR_NAME, 
 TAILOR_ACCNO, SQTY, STYLENAME, TAILOR_PCS_PRICE1, CUTTER_PCS_PRICE1, 
 QTY, CUST_NAME, MULTIBILL_NO, INVICE_DATE, DETAILES, 
 MANUAL_BILL_NO, BILLS_KINDS, CUTTING_OR_SLAES, NET, TOTAL, 
 AMOUNT_PAID)
AS 
SELECT DISTINCT tr_inv_d_id, cuting_transd.tr_inv_m_id, multi_cloths.ohid,
                   multi_cloths.ohdid, cuting_transd.POST,
                   cuting_transd.bill_no, cuting_transd.YEAR,
                   cuting_transd.typeno, cuting_transd.ddate,
                   cuting_transd.storeno, cuting_transd.detaile,
                   ordstate.ordsname, cuting_transd.style_no,
                   style.style_name, ordstate.deptid, cuting_transd.ordsid,
                   depts.deptname, cutter.cutter_name, cuting_transd.sanf_dno,
                   sanfs_d.sanf_dname, sanfs_d.wid, sanfs_d.len,
                   cuting_transd.size_frm, cuting_transd.size_to,
                   cuting_transd.pqty, sales_bill.POST posted,
                   cuting_transd.stk_cost, cutter.acc_no,
                   cuting_transd.seq_no, tailor.tailor_name,
                   tailor.acc_no tailor_accno, cuting_transd.sqty,
                   multi_cloths.style_name stylename,
                   multi_cloths.tailor_pcs_price1,
                   multi_cloths.cutter_pcs_price1, multi_cloths.qty,
                   cust.cust_name, multi_cloths.bill_no multibill_no,
                   sales_bill.dat invice_date, sales_bill.detailes,
                   sales_bill.manual_bill_no, sales_bill.bills_kinds,
                   sales_bill.cutting_or_slaes, sales_bill.net,
                   sales_bill.total, sales_bill.amount_paid
              FROM cuting_transd,
                   cutter,
                   depts,
                   sanfs_d,
                   ordstate,
                   style,
                   tailor,
                   cust,
                   multi_cloths,
                   sales_detailes_shapes,
                   sales_bill
             WHERE (    (sales_detailes_shapes.styl_no = style.shape_style_no
                        )
                    AND (cuting_transd.ordsid = ordstate.ordsid)
                    AND (ordstate.deptid = depts.deptid)
                    AND (NVL (multi_cloths.sanf_dno, 1000000001) =
                                                              sanfs_d.sanf_dno
                        )
                    AND (cuting_transd.seq_no = multi_cloths.seq_no1)
                    AND (    NVL (multi_cloths.cutter_no1, 0) =
                                                              cutter.cutter_no
                         AND NVL (multi_cloths.tailor_no1, 0) =
                                                              tailor.tailor_no
                        )
                    AND (multi_cloths.ohdid = cuting_transd.ohdid)
                    AND (sales_bill.ohid = cuting_transd.ohid)
                    AND (cust.cust_no = sales_bill.cust_no)
                    AND (multi_cloths.seq_no = sales_detailes_shapes.seq_no)
                    AND (sales_bill.bill_no = multi_cloths.bill_no)
                    AND (sales_bill.YEAR = multi_cloths.YEAR)
                    AND cutting_or_slaes = 1
                    AND bills_kinds = 1
                   );


DROP VIEW ACCOUNTS.CUTTING_BILL_ALL;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUTTING_BILL_ALL
(OHID, OHDID, SEQ_NO1, BILL_NO, MANUAL_BILL_NO, 
 TR_INV_M_ID, TR_INV_D_ID, YEAR, DAT, DDATE, 
 ORDSTAT_NAME, ORDSID, POST, CALC_CUTTER, CALC_TAILOR, 
 SANF_NO, SANF_DNO, CLOTH_TYPE, CONSUMED_CLOTH_QTY_HINSH, CONSUMED_CLOTH_QTY_YARDS, 
 SEQ_NO, CLOTH_FRM_LOCAL_STORE, QTY, SHAPE_STYLE_NO, CLOTH_NAME, 
 CLOTHS_COLOR, CUTTING_DATE, CUTTING_DONE, CUTTER_NO1, CUTTER_NAME, 
 CUTTER_PCS_PRICE1, TAILOR_DATE, TAILOR_DONE, TAILOR_NO1, TAILOR_NAME1, 
 TAILOR_PCS_PRICE1, BUTTON_TYPE1, GERAMA_DONE, GERAMA_NO, GERAMA_NAME, 
 GERAMA_PCS_PRICE, KAWYA_DONE, KAWYA_NO, KAWYA_NAME, KAWYA_PCS_PRICE, 
 HANDING_DONE1, HANDING_DATE1, TIME1, FIXED_FLEXED, SHELF_NO, 
 CLOTHS_OUR_SELECTION, STYLE_NAME, BATCH_NO_PRINT, CLOTHS_COLOR2, BILL_TYPE, 
 HANDING_DONE, CUTTING_OR_SLAES, BILLS_KINDS, ACC_NO, GIVING_DATE, 
 BENEFICIARY_NAME, TEL_NO1, TOTAL, DISCOUNT, GROUP_NO, 
 SIZE_FRM, SIZE_TO, SANF_PRICE, HANDING_DATE, CUST_NAME, 
 NET, CUT_CREATED_BY, CUT_TRANSFER_NO, CUT_TRANSFER_DATE, TAILOR_CREATED_BY, 
 TAILOR_TRANSFER_NO, TAILOR_TRANSFER_DATE, CREATED_BY_NAME, UPDATED_BY_NAME)
AS 
SELECT multi_cloths.ohid, multi_cloths.ohdid, multi_cloths.seq_no1,
          multi_cloths.bill_no, sales_bill.manual_bill_no,
          cuting_transd.tr_inv_m_id, tr_inv_d_id, multi_cloths.YEAR,
          sales_bill.dat, ddate,
                                -- TO_DATE (TO_CHAR ( 'DD-Mon-YYYY')) ddate,
                                ordstate.ordsname, cuting_transd.ordsid,
          cuting_transd.POST, calc_cutter, calc_tailor, multi_cloths.sanf_no,
          multi_cloths.sanf_dno, multi_cloths.cloth_type,
          multi_cloths.consumed_cloth_qty_hinsh,
          multi_cloths.consumed_cloth_qty_yards, multi_cloths.seq_no,
          multi_cloths.cloth_frm_local_store, multi_cloths.qty,
          multi_cloths.shape_style_no, multi_cloths.cloth_name,
          multi_cloths.cloths_color, multi_cloths.cutting_date,
          multi_cloths.cutting_done, multi_cloths.cutter_no1,
          cutter.cutter_name, multi_cloths.cutter_pcs_price1, tailor_date,
          multi_cloths.tailor_done, multi_cloths.tailor_no1,
          NVL(tailor.tailor_name,0), multi_cloths.tailor_pcs_price1,
          multi_cloths.button_type1, multi_cloths.gerama_done,
          multi_cloths.gerama_no, multi_cloths.gerama_name,
          multi_cloths.gerama_pcs_price, multi_cloths.kawya_done,
          multi_cloths.kawya_no, multi_cloths.kawya_name,
          multi_cloths.kawya_pcs_price, multi_cloths.handing_done1,
          multi_cloths.handing_date1, multi_cloths.time1,
          multi_cloths.fixed_flexed, multi_cloths.shelf_no,
          multi_cloths.cloths_our_selection, TYPES.type_name,
          multi_cloths.batch_no_print, multi_cloths.cloths_color2,
          sales_bill.bill_type, sales_bill.handing_done,
          sales_bill.cutting_or_slaes, sales_bill.bills_kinds,
          sales_bill.acc_no, giving_date, beneficiary_name, tel_no1,
          sales_bill.total, discount, TYPES.group_no,
          sales_detailes_shapes.l1, sales_detailes_shapes.l5, 0 sanf_price,
          sales_bill.handing_date, cust_name, sales_bill.net,
          multi_cloths.cut_created_by, multi_cloths.cut_transfer_no,
          multi_cloths.cut_transfer_date, multi_cloths.tailor_created_by,
          multi_cloths.tailor_transfer_no, multi_cloths.tailor_transfer_date,
          cuting_transd.created_by_name, cuting_transd.updated_by_name
     FROM sales_bill,
          ordstate,
          sales_detailes_shapes,
          multi_cloths,
          cuting_transd,
          cutter,
          TYPES,
          tailor
    WHERE (multi_cloths.bill_no = sales_bill.bill_no)
      AND cuting_transd.ordsid = ordstate.ordsid
      AND (multi_cloths.YEAR = sales_bill.YEAR)
      AND NVL (multi_cloths.cutter_no1, 0) = cutter.cutter_no
      AND NVL (multi_cloths.tailor_no1, 0) = tailor.tailor_no 
      AND (multi_cloths.ohid = sales_bill.ohid)
      AND (multi_cloths.ohid = sales_detailes_shapes.ohid)
      AND (sales_detailes_shapes.bill_no = sales_bill.bill_no)
      AND (sales_detailes_shapes.YEAR = sales_bill.YEAR)
      AND (sales_detailes_shapes.ohid = sales_bill.ohid)
      AND (sales_detailes_shapes.seq_no = multi_cloths.seq_no)
      AND (SUBSTR (NVL (sales_detailes_shapes.styl_no, 301), 1, 3) =
                                                                 TYPES.type_no
          )
      AND (multi_cloths.ohid = cuting_transd.ohid)
      AND (multi_cloths.ohdid = cuting_transd.ohdid)
      AND (sales_bill.ohid = cuting_transd.ohid)
      --AND (sales_detailes_shapes.ohdid = cuting_transd.ohdid)
      AND (sales_detailes_shapes.ohid = cuting_transd.ohid)
      AND seq_no1 = cuting_transd.seq_no
      AND cuting_transd.ordsid <> 10
      AND cuting_transd.CANCEL <> 1
   UNION ALL
   SELECT multi_cloths.ohid, multi_cloths.ohdid, multi_cloths.seq_no1,
          multi_cloths.bill_no, sales_bill.manual_bill_no,
          cuting_transd.tr_inv_m_id, tr_inv_d_id, multi_cloths.YEAR,
          sales_bill.dat, ddate,
                                -- TO_DATE (TO_CHAR ( 'DD-Mon-YYYY')) ddate,
                                ordstate.ordsname, cuting_transd.ordsid,
          cuting_transd.POST, calc_cutter, calc_tailor, multi_cloths.sanf_no,
          multi_cloths.sanf_dno, multi_cloths.cloth_type,
          multi_cloths.consumed_cloth_qty_hinsh,
          multi_cloths.consumed_cloth_qty_yards, multi_cloths.seq_no,
          multi_cloths.cloth_frm_local_store, multi_cloths.qty,
          multi_cloths.shape_style_no, multi_cloths.cloth_name,
          multi_cloths.cloths_color, multi_cloths.cutting_date,
          multi_cloths.cutting_done, multi_cloths.cutter_no1,
          cutter.cutter_name, multi_cloths.cutter_pcs_price1, tailor_date,
          multi_cloths.tailor_done, multi_cloths.tailor_no1,
          tailor.tailor_name, multi_cloths.tailor_pcs_price1,
          multi_cloths.button_type1, multi_cloths.gerama_done,
          multi_cloths.gerama_no, multi_cloths.gerama_name,
          multi_cloths.gerama_pcs_price, multi_cloths.kawya_done,
          multi_cloths.kawya_no, multi_cloths.kawya_name,
          multi_cloths.kawya_pcs_price, multi_cloths.handing_done1,
          multi_cloths.handing_date1, multi_cloths.time1,
          multi_cloths.fixed_flexed, multi_cloths.shelf_no,
          multi_cloths.cloths_our_selection, TYPES.type_name,
          multi_cloths.batch_no_print, multi_cloths.cloths_color2,
          sales_bill.bill_type, sales_bill.handing_done,
          sales_bill.cutting_or_slaes, sales_bill.bills_kinds,
          sales_bill.acc_no, giving_date, beneficiary_name, tel_no1,
          sales_bill.total, discount, TYPES.group_no,
          sales_detailes_shapes.l1, sales_detailes_shapes.l5, 0 sanf_price,
          sales_bill.handing_date, cust_name, sales_bill.net,
          multi_cloths.cut_created_by, multi_cloths.cut_transfer_no,
          multi_cloths.cut_transfer_date, multi_cloths.tailor_created_by,
          multi_cloths.tailor_transfer_no, multi_cloths.tailor_transfer_date,
          cuting_transd.created_by_name, cuting_transd.updated_by_name
     FROM sales_bill,
          ordstate,
          sales_detailes_shapes,
          multi_cloths,
          cuting_transd,
          cutter,
          TYPES,
          tailor
    WHERE (multi_cloths.bill_no = sales_bill.bill_no)
      AND cuting_transd.ordsid = ordstate.ordsid
      AND (multi_cloths.YEAR = sales_bill.YEAR)
      AND NVL (multi_cloths.cutter_no1, 0) = cutter.cutter_no
      AND NVL (multi_cloths.tailor_no1, 0) = tailor.tailor_no 
      AND (multi_cloths.ohid = sales_bill.ohid)
      AND (multi_cloths.ohid = sales_detailes_shapes.ohid)
      AND (sales_detailes_shapes.bill_no = sales_bill.bill_no)
      AND (sales_detailes_shapes.YEAR = sales_bill.YEAR)
      AND (sales_detailes_shapes.ohid = sales_bill.ohid)
      AND (sales_detailes_shapes.seq_no = multi_cloths.seq_no)
      AND (SUBSTR (NVL (sales_detailes_shapes.styl_no, 301), 1, 3) =
                                                                 TYPES.type_no
          )
      AND (multi_cloths.ohid = cuting_transd.ohid)
      AND (multi_cloths.ohdid = cuting_transd.ohdid)
      AND (sales_bill.ohid = cuting_transd.ohid)
      --AND (sales_detailes_shapes.ohdid = cuting_transd.ohdid)
      AND (sales_detailes_shapes.ohid = cuting_transd.ohid)
      AND seq_no1 = cuting_transd.seq_no
      AND cuting_transd.ordsid = 10
      AND cuting_transd.CANCEL <> 1;


DROP VIEW ACCOUNTS.TAILOR_FROM_CALC_GABZOR;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.TAILOR_FROM_CALC_GABZOR
(TAILOR_NO, TAILOR_NAME, TAILOR_ACC, TAILOR_DATE, G_POST, 
 G_AMT)
AS 
SELECT   tailor_no1, cutting_bill_in_tailor.tailor_name1, tailor.acc_no,
            tailor_date, SUM (GABZOR_HAND) G_POST,
            (SUM (cutting_bill_in_tailor.ADDCOST1 * GABZOR_HAND)) G_amt
       FROM cutting_bill_in_tailor, tailor
      WHERE ordsid = 6
        AND calc_tailor = 1
        AND cutting_bill_in_tailor.tailor_no1 = tailor.tailor_no
       -- AND NVL(ADDCOST1,0) > 0 
   GROUP BY tailor_no1,
            cutting_bill_in_tailor.tailor_name1,
            tailor_date,
            tailor.acc_no;


DROP VIEW ACCOUNTS.CUST_ALL_AMOUNT_LAST_2026;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUST_ALL_AMOUNT_LAST_2026
(CUST_NO, CUST_NAME, MAX_INVIOCE, MAXHAINDIG, QTY, 
 QHANDING, PAL, TOTAL, DISCOUNT, NET, 
 AMOUNT_PAID, UNPAID, BALANCE)
AS 
SELECT DISTINCT sales_bill.cust_no, cust.cust_name cust_name,
            MAX (sales_bill.dat) max_invioce,
            MAX (sales_bill.handing_date) maxhaindig, SUM (NVL (qty, 1)),
            DECODE (NVL (MAX (handing_done1), 0), 1, SUM (NVL (qty, 1)), 0),
              SUM (NVL (qty, 1))
            - DECODE (NVL (MAX (handing_done1), 0), 1, SUM (NVL (qty, 1)), 0)
                                                                          pal,
            MAX (NVL (total, 0)) total, MAX (NVL (discount, 0)) discount,
            MAX (NVL (net, 0)) net, MAX (NVL (amount_paid, 0)) amount_paid,
            MAX (NVL (net, 0)) - MAX (NVL (amount_paid, 0)) unpaid,
            MAX (pal_amt)
       FROM sales_bill, multi_cloths, cust, accounts.cust_all_pal_amt
      WHERE sales_bill.bill_no = multi_cloths.bill_no
        AND sales_bill.cust_no = cust_all_pal_amt.cust_no
        AND SUBSTR (cust_all_pal_amt.acc_no, 1, 3) = 123
        AND cust.cust_no = cust_all_pal_amt.cust_no
        --  AND CHART_ACC.acc_no = CUST_ALL_PAL_AMT.acc_no
        AND sales_bill.cust_no = cust.cust_no
--AND  SALES_BILL.DAT BETWEEN '01/03/2025' AND '05/05/2025'
        AND sales_bill.YEAR = multi_cloths.YEAR
        --  AND chart_acc.acc_no = sales_bill.acc_no
        AND NVL (sales_bill.bills_kinds, 1) NOT IN (2, 3, 4)
   -- AND entry_sub.acc_no = chart_acc.acc_no
   GROUP BY cust.cust_name,
            sales_bill.cust_no
       /*
HAVING   SUM (NVL (qty, 1))
       - DECODE (NVL (MAX (handing_done1), 0), 1, SUM (NVL (qty, 1)), 0) <>
                                                                        0*/;


DROP VIEW ACCOUNTS.CUST_ALL_AMOUNT_L_2026;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUST_ALL_AMOUNT_L_2026
(CUST_NO, CUST_NAME, QTY, QHANDING, PAL, 
 NET, AMOUNT_PAID, UNPAID, BALANCE)
AS 
SELECT DISTINCT sales_bill.cust_no, cust.cust_name cust_name,
            SUM (NVL (qty, 1)),
            DECODE (NVL (MAX (handing_done1), 0), 1, SUM (NVL (qty, 1)), 0),
              SUM (NVL (qty, 1))
            - DECODE (NVL (MAX (handing_done1), 0), 1, SUM (NVL (qty, 1)), 0)
                                                                          pal,
                                                                          
                                                                          
            (DECODE (NVL (MAX (handing_done1), 0), 0, SUM (NET) , 0))/DECODE((SUM (NVL (qty, 1))
            - DECODE (NVL (MAX (handing_done1), 0), 1, SUM (NVL (qty, 1)), 0)),0,1,(SUM (NVL (qty, 1))
            - DECODE (NVL (MAX (handing_done1), 0), 1, SUM (NVL (qty, 1)), 0))) NET, 
            
            
            (DECODE (NVL (MAX (handing_done1), 0), 0, SUM (NVL (amount_paid, 0)) , 0))/DECODE((SUM (NVL (qty, 1))
            - DECODE (NVL (MAX (handing_done1), 0), 1, SUM (NVL (qty, 1)), 0)),0,1,(SUM (NVL (qty, 1))
            - DECODE (NVL (MAX (handing_done1), 0), 1, SUM (NVL (qty, 1)), 0))) amount_paid,
            
            
            (DECODE (NVL (MAX (handing_done1), 0), 0, SUM (NET) , 0) -
            DECODE (NVL (MAX (handing_done1), 0), 0, SUM (NVL (amount_paid, 0)) , 0))/DECODE((SUM (NVL (qty, 1))
            - DECODE (NVL (MAX (handing_done1), 0), 1, SUM (NVL (qty, 1)), 0)),0,1,(SUM (NVL (qty, 1))
            - DECODE (NVL (MAX (handing_done1), 0), 1, SUM (NVL (qty, 1)), 0))) unpaid,
            
            
--            MAX (NVL (total, 0)) total, 
--            MAX (NVL (discount, 0)) discount,
--            MAX (NVL (net, 0)) net, 
--            MAX (NVL (amount_paid, 0)) amount_paid,
--            MAX (NVL (net, 0)) - MAX (NVL (amount_paid, 0)) unpaid,
            MAX (pal_amt)
       FROM sales_bill, multi_cloths, cust, accounts.cust_all_pal_amt
      WHERE sales_bill.bill_no = multi_cloths.bill_no
        AND sales_bill.cust_no = cust_all_pal_amt.cust_no
        AND SUBSTR (cust_all_pal_amt.acc_no, 1, 3) = 123
        AND cust.cust_no = cust_all_pal_amt.cust_no
        --  AND CHART_ACC.acc_no = CUST_ALL_PAL_AMT.acc_no
        AND sales_bill.cust_no = cust.cust_no
--AND  SALES_BILL.DAT BETWEEN '01/03/2025' AND '05/05/2025'
        AND sales_bill.YEAR = multi_cloths.YEAR
        --  AND chart_acc.acc_no = sales_bill.acc_no
        AND NVL (sales_bill.bills_kinds, 1) NOT IN (2, 3, 4)
   -- AND entry_sub.acc_no = chart_acc.acc_no
   GROUP BY cust.cust_name,
            sales_bill.cust_no
       /*
HAVING   SUM (NVL (qty, 1))
       - DECODE (NVL (MAX (handing_done1), 0), 1, SUM (NVL (qty, 1)), 0) <>
                                                                        0*/;


DROP VIEW ACCOUNTS.CUST_CLOTHS_NOT_HANDING_AMOUNT;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUST_CLOTHS_NOT_HANDING_AMOUNT
(CUST_NO, CUST_NAME, C_BALANCE, PHONE_NUM)
AS 
SELECT   cust_no, cust_name,
            DECODE (NVL (handing_done1, 0), 0, SUM (NVL (sanfprice, 0)), 0),
            MAX (sales_bill.tel_no1)
       FROM sales_bill, multi_cloths
      WHERE multi_cloths.ohid = sales_bill.ohid
        AND sales_bill.bill_type = 2
        AND sales_bill.bills_kinds = 1
        AND sales_bill.cutting_or_slaes = 1
   -- AND NVL (handing_done1, 0) = 0
   GROUP BY cust_no, cust_name, NVL (handing_done1, 0);


DROP VIEW ACCOUNTS.CUST_PAL_HANDING_AMT_LAST_CUST;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUST_PAL_HANDING_AMT_LAST_CUST
(CUST_NO, CUST_NAME, PAL_AMT)
AS 
SELECT   CUST.CUST_no, CUST.CUST_name,
            SUM (entry_sub.entry_mnt) pal_amt
       FROM CUST, entry_sub
      WHERE entry_sub.GIVING = CUST.CUST_no
        AND SUBSTR (ENTRY_SUB.acc_no, 1, 3) = 123
        AND cUST.CUST_no NOT IN (SELECT DISTINCT CUST_no
                                                FROM CUST_NOT_HANDING_AMOUNT000)
   GROUP BY CUST.CUST_no, CUST.CUST_name
     HAVING SUM(entry_sub.entry_mnt) <> 0;


DROP VIEW ACCOUNTS.TAILOR_GABZOR;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.TAILOR_GABZOR
(SEQ, TAILOR_NO, TAILOR_NAME, TAILOR_ACC, TAILOR_DATE, 
 G_POST, G_AMT)
AS 
SELECT seq_no1, tailor_no1, cutting_bill_in_tailor.tailor_name1,
          tailor.acc_no, tailor_date,
          DECODE (SIGN (addcost1), 1, gabzor_hand, 0) g_post,
          (cutting_bill_in_tailor.addcost1 * gabzor_hand) g_amt
     FROM cutting_bill_in_tailor, tailor
    WHERE ordsid = 6
      AND NVL (calc_tailor, 0) = 0
      AND cutting_bill_in_tailor.tailor_no1 = tailor.tailor_no;


DROP VIEW ACCOUNTS.CUTTING_BILL_READY_X;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUTTING_BILL_READY_X
(OHID, OHDID, SEQ_NO1, BILL_NO, MANUAL_BILL_NO, 
 TR_INV_M_ID, TR_INV_D_ID, YEAR, DAT, DDATE, 
 ORDSTAT_NAME, ORDSID, POST, CALC_CUTTER, SANF_NO, 
 SANF_DNO, CLOTH_TYPE, CONSUMED_CLOTH_QTY_HINSH, CONSUMED_CLOTH_QTY_YARDS, SEQ_NO, 
 CLOTH_FRM_LOCAL_STORE, QTY, SHAPE_STYLE_NO, CLOTH_NAME, CLOTHS_COLOR, 
 CUTTING_DATE, CUTTING_DONE, CUTTER_NO1, CUTTER_NAME, CUTTER_PCS_PRICE1, 
 TAILOR_DONE, TAILOR_NO1, CUTTER_NAME1, TAILOR_PCS_PRICE1, BUTTON_TYPE1, 
 GERAMA_DONE, GERAMA_NO, GERAMA_NAME, GERAMA_PCS_PRICE, KAWYA_DONE, 
 KAWYA_NO, KAWYA_NAME, KAWYA_PCS_PRICE, HANDING_DONE1, HANDING_DATE1, 
 TIME1, FIXED_FLEXED, SHELF_NO, CLOTHS_OUR_SELECTION, STYLE_NAME, 
 BATCH_NO_PRINT, CLOTHS_COLOR2, BILL_TYPE, HANDING_DONE, CUTTING_OR_SLAES, 
 BILLS_KINDS, ACC_NO, GIVING_DATE, BENEFICIARY_NAME, TEL_NO1, 
 TOTAL, DISCOUNT, GROUP_NO, SIZE_FRM, SIZE_TO, 
 SANF_PRICE, HANDING_DATE, CUST_NAME, NET, CUT_CREATED_BY, 
 CUT_TRANSFER_NO, CUT_TRANSFER_DATE, TAILOR_CREATED_BY, TAILOR_TRANSFER_NO, TAILOR_TRANSFER_DATE, 
 CREATED_BY_NAME, UPDATED_BY_NAME)
AS 
SELECT multi_cloths.ohid, multi_cloths.ohdid, multi_cloths.seq_no1,
          multi_cloths.bill_no, sales_bill.manual_bill_no,
          cuting_transd.tr_inv_m_id, tr_inv_d_id, multi_cloths.YEAR,
          sales_bill.dat, ddate,
                                -- TO_DATE (TO_CHAR ( 'DD-Mon-YYYY')) ddate,
                                ordstate.ordsname, cuting_transd.ordsid,
          cuting_transd.POST, calc_cutter, multi_cloths.sanf_no,
          multi_cloths.sanf_dno, multi_cloths.cloth_type,
          multi_cloths.consumed_cloth_qty_hinsh,
          multi_cloths.consumed_cloth_qty_yards, multi_cloths.seq_no,
          multi_cloths.cloth_frm_local_store, multi_cloths.qty,
          multi_cloths.shape_style_no, multi_cloths.cloth_name,
          multi_cloths.cloths_color, multi_cloths.cutting_date,
          multi_cloths.cutting_done, multi_cloths.cutter_no1,
          cutter.cutter_name, multi_cloths.cutter_pcs_price1,
          multi_cloths.tailor_done, multi_cloths.tailor_no1, cutter_name,
          multi_cloths.tailor_pcs_price1, multi_cloths.button_type1,
          multi_cloths.gerama_done, multi_cloths.gerama_no,
          multi_cloths.gerama_name, multi_cloths.gerama_pcs_price,
          multi_cloths.kawya_done, multi_cloths.kawya_no,
          multi_cloths.kawya_name, multi_cloths.kawya_pcs_price,
          multi_cloths.handing_done1, multi_cloths.handing_date1,
          multi_cloths.time1, multi_cloths.fixed_flexed,
          multi_cloths.shelf_no, multi_cloths.cloths_our_selection,
          sales_detailes_shapes.style_name, multi_cloths.batch_no_print,
          multi_cloths.cloths_color2, sales_bill.bill_type,
          sales_bill.handing_done, sales_bill.cutting_or_slaes,
          sales_bill.bills_kinds, sales_bill.acc_no, giving_date,
          beneficiary_name, tel_no1, sales_bill.total, discount, group_no,
          sales_detailes_shapes.l1, sales_detailes_shapes.l5, 0 sanf_price,
          sales_bill.handing_date, cust_name, sales_bill.net,
          multi_cloths.cut_created_by, multi_cloths.cut_transfer_no,
          multi_cloths.cut_transfer_date, multi_cloths.tailor_created_by,
          multi_cloths.tailor_transfer_no, multi_cloths.tailor_transfer_date,
          cuting_transd.created_by_name, cuting_transd.updated_by_name
     FROM sales_bill,
          ordstate,
          sales_detailes_shapes,
          multi_cloths,
          cuting_transd,
          cutter
    WHERE (multi_cloths.bill_no = sales_bill.bill_no)
      AND cuting_transd.ordsid = ordstate.ordsid
      AND (multi_cloths.YEAR = sales_bill.YEAR)
      AND multi_cloths.cutter_no1 = cutter.cutter_no
      AND (multi_cloths.ohid = sales_bill.ohid)
      AND (multi_cloths.ohid = sales_detailes_shapes.ohid)
      AND (sales_detailes_shapes.bill_no = sales_bill.bill_no)
      AND (sales_detailes_shapes.YEAR = sales_bill.YEAR)
      AND (sales_detailes_shapes.ohid = sales_bill.ohid)
      AND (sales_detailes_shapes.seq_no = multi_cloths.seq_no)
      AND (multi_cloths.ohid = cuting_transd.ohid)
      AND (multi_cloths.ohdid = cuting_transd.ohdid)
      AND (sales_bill.ohid = cuting_transd.ohid)
      -- AND (sales_detailes_shapes.ohdid = cuting_transd.ohdid)
      AND (sales_detailes_shapes.ohid = cuting_transd.ohid)
      AND seq_no1 = cuting_transd.seq_no
      AND CANCEL <> 1
      AND cuting_transd.ordsid = 4
     -- AND NVL (sales_bill.handing_done, 0) <> 1
      AND sales_bill.bills_kinds NOT IN (2, 3, 4)
      --AND NVL (multi_cloths.cutting_done, 0) <> 1
     -- AND multi_cloths.cutter_no1 IS NOT NULL
-- and multi_cloths.FIXED_FLEXED is null;;;;;;;;;;;;;;;;;;;;;;;;;;


DROP VIEW ACCOUNTS.CUTTING_DIFF;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUTTING_DIFF
(OHID, OHDID, DTID, SEQ_NO1, BILL_NO, 
 MANUAL_BILL_NO, X, TR_INV_D_ID, DAT, DDATE, 
 ORDSDID, ORDSNAME, ORSCUT_ID, CUTSTATE_NAME)
AS 
SELECT multi_cloths.ohid,  multi_cloths.ohdid  ohdid, cuting_transd.ohdid dtid ,  multi_cloths.seq_no1,
          multi_cloths.bill_no, sales_bill.manual_bill_no,
          cuting_transd.tr_inv_m_id  x, tr_inv_d_id  tr_inv_d_id , 
          sales_bill.dat, ddate,                          
                              (multi_cloths.ORDSDID) ORDSDID,  stats.ordsname, cuting_transd.ordsid  orscut_id ,ordstate.ORDSNAME cutstate_name
                              
                                    
     FROM  sales_bill,
          ordstate,
          ordstate stats,
          multi_cloths,
          cuting_transd
           
          
           
    WHERE (multi_cloths.bill_no = sales_bill.bill_no)
      AND multi_cloths.ordsdid = stats.ordsid
         AND cuting_transd.ordsid = ordstate.ordsid
      AND (multi_cloths.YEAR = sales_bill.YEAR)
       AND (multi_cloths.ohid = cuting_transd.ohid)
      AND (multi_cloths.ohdid = cuting_transd.ohdid)
      AND seq_no1 = cuting_transd.seq_no
      and  cuting_transd.CANCEL =0
      and cuting_transd.post=0
      /*group by
      multi_cloths.ohid,  multi_cloths.seq_no1,stats.ordsname,
          multi_cloths.bill_no, sales_bill.manual_bill_no,
           multi_cloths.ohdid ,cuting_transd.ordsid,cuting_transd.ohdid,
          sales_bill.dat, ddate, multi_cloths.ORDSDID ,multi_cloths.ohdid*/
          and  (multi_cloths.ORDSDID)  <>  cuting_transd.ordsid     
      order by  dat;


DROP VIEW ACCOUNTS.READY_FROM_QTY;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.READY_FROM_QTY
(TAILOR_NO, TAILOR_NAME, DDATE, TAILOR_DATE, STYLE_NAME, 
 SQTY, POST, UN, AMT)
AS 
SELECT   tailor_no1, tailor_name1, MAX (ddate) ddate,
            NVL (Ddate, MAX (ddate)), style_name,
            SUM (cutting_bill_ready_2.qty) sqty,
            DECODE (POST, 0, 0, SUM (cutting_bill_ready_2.qty)) POST,
              SUM (cutting_bill_ready_2.qty)
            - DECODE (POST, 0, 0, SUM (cutting_bill_ready_2.qty)) un,
            (SUM (cutting_bill_ready_2.tailor_pcs_price1 * POST)) amt
       FROM cutting_bill_ready_2
      WHERE
-- AND TO_CHAR(CUTING_TRANSD.DDATE,'DD/MM/YYYY')=:DDATE
      --  AND multi_cloths.ohid = cutting_bill_in_cut.ohid
            ordsid = 8
   --  AND POST=1
   GROUP BY tailor_no1, tailor_name1, Ddate, style_name, POST;


DROP VIEW ACCOUNTS.TAILOR_FROM_UNCALC;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.TAILOR_FROM_UNCALC
(TAILOR_NO, TAILOR_NAME, TAILOR_ACC, DDATE, TAILOR_DATE, 
 STYLE_NO, STYLE_NAME, SQTY, POST, UN, 
 AMT, ADDCOST2, ADDCOST3, AMT_ALL)
AS 
SELECT   tailor_no1, cutting_bill_in_tailor.tailor_name1, tailor.acc_no,
            MAX (ddate) ddate, tailor_date, shape_style_no, style_name,
            SUM (cutting_bill_in_tailor.qty) sqty, SUM (POST) POST,
            SUM (cutting_bill_in_tailor.qty) - SUM (POST) un,
            (SUM (cutting_bill_in_tailor.tailor_pcs_price1 * POST)) amt,
            sum(nvl(addcost2,0)), sum(nvl(addcost3,0)),
            (SUM (cutting_bill_in_tailor.tailor_pcs_price1 * POST)+sum(nvl(addcost2,0))+sum(nvl(addcost3,0))) amt_all
       FROM cutting_bill_in_tailor, tailor
      WHERE ordsid = 6
        AND calc_tailor = 0
        AND cutting_bill_in_tailor.tailor_no1 = tailor.tailor_no
   GROUP BY tailor_no1,
            cutting_bill_in_tailor.tailor_name1,
            tailor_date,
            style_name,
            tailor.acc_no,
            shape_style_no;


DROP VIEW ACCOUNTS.TAILOR_FROM_CALC;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.TAILOR_FROM_CALC
(TAILOR_NO, TAILOR_NAME, TAILOR_ACC, DDATE, TAILOR_DATE, 
 STYLE_NO, STYLE_NAME, SQTY, POST, UN, 
 AMT, ADDCOST2, ADDCOST3, AMT_ALL)
AS 
SELECT   tailor_no1, cutting_bill_in_tailor.tailor_name1, tailor.acc_no,
            MAX (ddate) ddate, tailor_date, shape_style_no, style_name,
            SUM (cutting_bill_in_tailor.qty) sqty, SUM (POST) POST,
            SUM (cutting_bill_in_tailor.qty) - SUM (POST) un,
            (SUM (cutting_bill_in_tailor.tailor_pcs_price1 * POST)) amt,
            SUM (NVL (addcost2, 0)), SUM (NVL (addcost3, 0)),
            (  SUM (cutting_bill_in_tailor.tailor_pcs_price1 * POST)
             + SUM (NVL (addcost2, 0))
             + SUM (NVL (addcost3, 0))
            ) amt_all
       FROM cutting_bill_in_tailor, tailor
      WHERE ordsid = 6
        AND calc_tailor = 1
        AND cutting_bill_in_tailor.tailor_no1 = tailor.tailor_no
   GROUP BY tailor_no1,
            cutting_bill_in_tailor.tailor_name1,
            tailor_date,
            style_name,
            tailor.acc_no,
            shape_style_no;


