(OHID, OHDID, SEQ_NO1, BILL_NO, MANUAL_BILL_NO, 
 TR_INV_M_ID, TR_INV_D_ID, YEAR, DAT, DDATE, 
 ORDSTAT_NAME, ORDSID, POST, CALC_CUTTER, CALC_TAILOR, 
 SANF_NO, SANF_DNO, CLOTH_TYPE, CONSUMED_CLOTH_QTY_HINSH, CONSUMED_CLOTH_QTY_YARDS, 
