CREATE OR REPLACE TRIGGER ACCOUNTS.TOT_CAL
BEFORE INSERT OR UPDATE
ON ACCOUNTS.INVENTORY_RECEIVE_DETAILES 
REFERENCING NEW AS NEW OLD AS OLD
FOR EACH ROW
BEGIN
  -- your code here 
  -- (Trigger template "Default" could not be loaded.)       
  UPDATE ACCOUNTS.INVENTORY_RECEIVE_DETAILES
 SET  TOTAL=:NEW.QTY*:OLD.SANF_PRICE
 WHERE :OLD.BILL_NO=:OLD.BILL_NO
 AND :OLD.YEAR=:OLD.YEAR AND :OLD.SANF_NO=:OLD.SANF_NO ;
 COMMIT;
END;
/
SHOW ERRORS;

ALTER TRIGGER ACCOUNTS.TOT_CAL DISABLE;


