DROP TABLE ACCOUNTS.RETURN_SALES_DETAILES CASCADE CONSTRAINTS PURGE;

CREATE TABLE ACCOUNTS.RETURN_SALES_DETAILES
(
  RETURN_NO      NUMBER(5)                      NOT NULL,
  YEAR           NUMBER(5)                      NOT NULL,
  SANF_NO        NUMBER(8)                      NOT NULL,
  RET_QTY        NUMBER(12,3)                   NOT NULL,
  CAP            NUMBER(8,2),
  PCS            NUMBER(16,3)                   NOT NULL,
  SANF_PRICE     NUMBER(10,2)                   NOT NULL,
  BOUNS          NUMBER(8,2),
  EXP_DATE       DATE,
  TOTAL          NUMBER(20,2)                   NOT NULL,
  SEQ            NUMBER(30)                     NOT NULL,
  DISCOUNT_RATE  NUMBER(5,2),
  DISCOUNT1      NUMBER(12,2),
  SIZE_FRM       NUMBER(2),
  SIZE_TO        NUMBER(2),
  COLOR_NO       NUMBER(3),
  CATEGORY       VARCHAR2(30 BYTE),
  COLOR_NO2      VARCHAR2(30 BYTE),
  SANF_DNO       NUMBER                         NOT NULL,
  CAT_NO         NUMBER,
  STYLE_NO       NUMBER,
  SEQ_SALES      NUMBER(20),
  SEQ_NO         NUMBER(20),
  STK_COST       NUMBER,
  SANF_COST      NUMBER
)
TABLESPACE SYSTEM
PCTUSED    40
PCTFREE    10
INITRANS   1
MAXTRANS   255
STORAGE    (
            INITIAL          64K
            MINEXTENTS       1
            MAXEXTENTS       UNLIMITED
            PCTINCREASE      0
            FREELISTS        1
            FREELIST GROUPS  1
            BUFFER_POOL      DEFAULT
           )
LOGGING 
NOCOMPRESS 
NOCACHE
NOPARALLEL
MONITORING;


