DROP VIEW ACCOUNTS.SALES_DETAILES_VIEW;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.SALES_DETAILES_VIEW
(BILL_NO, YEAR, ACC_NO, BENEFICIARY_NAME, BILL_TYPE, 
 SANF_NO, SANF_PRICE, QTY, CAP, PCS, 
 TOTAL, SEQ, BOUNS, EXP_DATE, DISCOUNT_RATE, 
 DISCOUNT1, L1, L2, L3, L4, 
 L5, L6, L7, REMARKS, STEPS, 
 IS_GIVING, GIVING_DATE, HANDING_DATE, IS_READY, DAT, 
 MANUAL_BILL_NO, CUTTING, TAFSEEL, TAILORING, GERAMA, 
 KAWYA, READY, GIVING, AC1, AC2, 
 AC3, AC4, AC5, MNT1, MNT2, 
 MNT3, MNT4, MNT5)
AS 
SELECT sales_detailes.bill_no, sales_detailes.YEAR, acc_no,
          beneficiary_name, bill_type, sales_detailes.sanf_no,
          sales_detailes.sanf_price, sales_detailes.qty, sales_detailes.cap,
          sales_detailes.pcs, sales_detailes.total, sales_detailes.seq,
          sales_detailes.bouns, sales_detailes.exp_date,
          sales_detailes.discount_rate, sales_detailes.discount1,
          sales_detailes.l1, sales_detailes.l2, sales_detailes.l3,
          sales_detailes.l4, sales_detailes.l5, sales_detailes.l6,
          sales_detailes.l7, sales_detailes.remarks, sales_detailes.steps,
          sales_bill.is_giving, sales_bill.giving_date,
          sales_bill.handing_date, sales_bill.is_ready, sales_bill.dat,
          manual_bill_no, cutting, tafseel, tailoring, gerama, kawya, ready,
          giving, ac1, ac2, ac3, ac4, ac5, mnt1, mnt2, mnt3, mnt4, mnt5
     FROM sales_bill, sales_detailes
    WHERE (    (sales_detailes.bill_no = sales_bill.bill_no)
           AND (sales_detailes.YEAR = sales_bill.YEAR)
          );


DROP VIEW ACCOUNTS.SALES_BILL_VIEW;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.SALES_BILL_VIEW
(SEQ_NO1, SANF_NO, CLOTH_TYPE, CONSUMED_CLOTH_QTY_HINSH, CONSUMED_CLOTH_QTY_YARDS, 
 SEQ_NO, CLOTH_FRM_LOCAL_STORE, QTY, SHAPE_STYLE_NO, CLOTH_NAME, 
 CLOTHS_COLOR, CUTTING_DATE, CUTTING_DONE, CUTTER_NO1, CUTTER_PCS_PRICE1, 
 TAILOR_DONE, TAILOR_NO1, TAILOR_PCS_PRICE1, BUTTON_TYPE1, GERAMA_DONE, 
 GERAMA_NO, GERAMA_NAME, GERAMA_PCS_PRICE, KAWYA_DONE, KAWYA_NO, 
 KAWYA_NAME, KAWYA_PCS_PRICE, HANDING_DONE1, HANDING_DATE1, TIME1, 
 FIXED_FLEXED, SHELF_NO, CLOTHS_OUR_SELECTION, STYLE_NAME, BATCH_NO_PRINT, 
 CLOTHS_COLOR2, BILL_NO, YEAR, DAT, BILL_TYPE, 
 HANDING_DONE, CUTTING_OR_SLAES, BILLS_KINDS, ACC_NO, MANUAL_BILL_NO, 
 GIVING_DATE, BENEFICIARY_NAME, TEL_NO1, TOTAL, DISCOUNT, 
 GROUP_NO, SIZE_FRM, SIZE_TO, SANF_PRICE, HANDING_DATE, 
 CUST_NAME, NET, CUT_CREATED_BY, CUT_TRANSFER_NO, CUT_TRANSFER_DATE, 
 TAILOR_CREATED_BY, TAILOR_TRANSFER_NO, TAILOR_TRANSFER_DATE)
AS 
SELECT multi_cloths.seq_no1, multi_cloths.sanf_no, multi_cloths.cloth_type,
          multi_cloths.consumed_cloth_qty_hinsh,
          multi_cloths.consumed_cloth_qty_yards, multi_cloths.seq_no,
          multi_cloths.cloth_frm_local_store, multi_cloths.qty,
          multi_cloths.shape_style_no, multi_cloths.cloth_name,
          multi_cloths.cloths_color, multi_cloths.cutting_date,
          multi_cloths.cutting_done, multi_cloths.cutter_no1,
          multi_cloths.cutter_pcs_price1, multi_cloths.tailor_done,
          multi_cloths.tailor_no1, multi_cloths.tailor_pcs_price1,
          multi_cloths.button_type1, multi_cloths.gerama_done,
          multi_cloths.gerama_no, multi_cloths.gerama_name,
          multi_cloths.gerama_pcs_price, multi_cloths.kawya_done,
          multi_cloths.kawya_no, multi_cloths.kawya_name,
          multi_cloths.kawya_pcs_price, multi_cloths.handing_done1,
          multi_cloths.handing_date1, multi_cloths.time1,
          multi_cloths.fixed_flexed, multi_cloths.shelf_no,
          multi_cloths.cloths_our_selection, multi_cloths.style_name,
          multi_cloths.batch_no_print, multi_cloths.cloths_color2,
          multi_cloths.bill_no, multi_cloths.YEAR, sales_bill.dat,
          sales_bill.bill_type, sales_bill.handing_done,
          sales_bill.cutting_or_slaes, sales_bill.bills_kinds,
          sales_bill.acc_no, manual_bill_no, giving_date, beneficiary_name,
          tel_no1, sales_bill.total, discount, group_no,
          sales_detailes.size_frm, sales_detailes.size_to,
          sales_detailes.sanf_price, sales_bill.handing_date, cust_name,
          sales_bill.net, multi_cloths.cut_created_by,
          multi_cloths.cut_transfer_no, multi_cloths.cut_transfer_date,
          multi_cloths.tailor_created_by, multi_cloths.tailor_transfer_no,
          multi_cloths.tailor_transfer_date
     FROM sales_bill, multi_cloths, sales_detailes
    WHERE (    (multi_cloths.bill_no = sales_bill.bill_no)
           AND (multi_cloths.YEAR = sales_bill.YEAR)
          )
      AND (    (sales_detailes.bill_no = sales_bill.bill_no)
           AND (sales_detailes.YEAR = sales_bill.YEAR)
          );


DROP VIEW ACCOUNTS.CUST_PAL_HANDING_AMT_2025;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUST_PAL_HANDING_AMT_2025
(ACC_NO, CUST_NAME, PAL_AMT)
AS 
SELECT   chart_acc.acc_no, chart_acc.acc_name,
            SUM (entry_sub.entry_mnt) pal_amt
       FROM chart_acc, entry_sub
      WHERE entry_sub.acc_no = chart_acc.acc_no
        AND SUBSTR (chart_acc.acc_no, 1, 3) = 123
        AND chart_acc.acc_no NOT IN (SELECT DISTINCT acc_no
                                                FROM cust_not_handing)
        AND entry_sub.entry_no NOT IN (SELECT DISTINCT entry_no
                                                  FROM sales_bill
                                                 WHERE handing_done = 0)
   GROUP BY chart_acc.acc_no, chart_acc.acc_name, entry_sub.acc_no
     HAVING SUM (entry_sub.entry_mnt) <> 0;


DROP VIEW ACCOUNTS.ITEM_MOVE_D;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.ITEM_MOVE_D
(BSEQ, BILL_NO, MANUAL_BILL_NO, BILL_TYPE, TR_TYPE_ID, 
 TYPENO, TR_TYPE_NAME, TOTAL, YEAR, DAT, 
 CUST_NO, CUST_NAME, PROV_NO, PROV_NAME, BOX_ACC_NO, 
 BOX_ACC_NAME, DR_ACC_NO, DR_ACC_NAME, DISCOUNT_ACC_NO, DISCOUNT_ACC_NAME, 
 CR_ACC_NO, CR_ACC_NAME, INV_ACC_NO, INV_ACC_NAME, COST_ACC_NO, 
 COST_ACC_NAME, DETAILES, STORE_NO, STORE_NAME, NET, 
 DISCOUNT, SANF_NO, SANF_D_NO, SANF_NAME, PART_NO, 
 UNIT_NAME, CAP, QTY, P_QTY, PSC, 
 SANF_PRICE, SANF_COST, CATEGORY, LEN, WID, 
 SAIZE, COLOR_NO, NOTES, STYL_NO, TYPE_NO, 
 GROUPNO, CAT_NO, SOURCE_NAME, INOUT)
AS 
(SELECT sales_bill.YEAR || sales_bill.bill_no bseq, sales_bill.bill_no,
           sales_bill.manual_bill_no,
           DECODE (bill_type, 1, '???', 2, '???', '') bill_type,
           trans_type.tr_type_id, trans_type.type_no, trans_type.type_name,
           sales_detailes.total, sales_bill.YEAR, sales_bill.dat dat,
           sales_bill.cust_no, sales_bill.cust_name, NULL prov_no,
           NULL prov_name, DECODE (bill_type, 1, acc_no, NULL) box_acc_no,
           DECODE (bill_type,
                   1, (SELECT DISTINCT acc_name
                                  FROM chart_acc
                                 WHERE acc_no = sales_bill.acc_no
                                   AND sales_bill.acc_no IS NOT NULL),
                   NULL
                  ) box_acc_name,
           DECODE (bill_type, 1, NULL, acc_no) dr_acc_no,
           DECODE (bill_type,
                   1, NULL,
                   (SELECT DISTINCT acc_name
                               FROM chart_acc
                              WHERE acc_no = sales_bill.acc_no)
                  ) dr_acc_name,
           DECODE (NVL (discount, 0),
                   0, NULL,
                   (SELECT DISTINCT discount_acc
                               FROM stores
                              WHERE store_no = sales_bill.store_no)
                  ) discount_acc_no,
           DECODE
              (NVL (discount, 0),
               0, NULL,
               (SELECT DISTINCT acc_name
                           FROM chart_acc
                          WHERE acc_no IN (
                                          SELECT DISTINCT discount_acc
                                                     FROM stores
                                                    WHERE store_no =
                                                             sales_bill.store_no))
              ) discount_acc_name,
           acc_no1 cr_acc_no, (SELECT DISTINCT acc_name
                                          FROM chart_acc
                                         WHERE acc_no =
                                                  sales_bill.acc_no1)
                                                                  cr_acc_name,
           (SELECT DISTINCT inv_acc_no
                       FROM stores
                      WHERE store_no = sales_bill.store_no) inv_acc_no,
           (SELECT DISTINCT acc_name
                       FROM chart_acc
                      WHERE acc_no IN (
                               SELECT DISTINCT inv_acc_no
                                          FROM stores
                                         WHERE store_no =
                                                  sales_bill.store_no))
                                                                 inv_acc_name,
           (SELECT DISTINCT cost_acc_no
                       FROM stores
                      WHERE store_no = sales_bill.store_no) cost_acc_no,
           (SELECT DISTINCT acc_name
                       FROM chart_acc
                      WHERE acc_no IN (
                               SELECT DISTINCT cost_acc_no
                                          FROM stores
                                         WHERE store_no =
                                                  sales_bill.store_no))
                                                                cost_acc_name,
           sales_bill.detailes, sales_bill.store_no, stores.store_name,
           (sales_detailes.total - NVL (sales_detailes.discount1, 0)) net,
           sales_detailes.discount1, sales_detailes.sanf_no,
           sales_detailes.sanf_dno, sanfs.sanf_name, sanfs.part_no, unit_name,
           sanfs.cap, sales_detailes.qty, sales_detailes.qty * -1 p_qty,
           sales_detailes.pcs, sales_detailes.sanf_price,
           DECODE
              (stk_cost,
               0, (SELECT MAX (buy_detailes.sanf_price)
                     FROM buy_detailes
                    WHERE buy_detailes.sanf_dno = sanfs_d.sanf_dno
                      AND sales_detailes.sanf_dno = sanfs_d.sanf_dno
                      AND sales_detailes.sanf_dno = buy_detailes.sanf_dno
                      AND dat IN (
                             SELECT MAX (dat)
                               FROM buy_detailes
                              WHERE buy_detailes.sanf_dno = sanfs_d.sanf_dno
                                AND sales_detailes.sanf_dno = sanfs_d.sanf_dno
                                AND sales_detailes.sanf_dno =
                                                         buy_detailes.sanf_dno)),
               stk_cost
              ) stk_cost,
           sanfs.CATEGORY, sanfs_d.len, sanfs_d.wid,
           sanfs_d.wid || '*' || sanfs_d.len sa, sanfs_d.color_no,
           sanfs.notes, sanfs.styl_no, sanfs.type_no, sanfs.groupno,
           sanfs.cat_no, 'sales', inout
      FROM sales_bill,
           stores,
           sales_detailes,
           sanfs,
           units,
           sanfs_d,
           trans_type
