DROP VIEW ACCOUNTS.CUST_PAL_HANDING_AMT_2025_Z;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUST_PAL_HANDING_AMT_2025_Z
(ACC_NO, CUST_NAME, PAL_AMT)
AS 
SELECT   chart_acc.acc_no, chart_acc.acc_name,
            SUM (entry_sub.entry_mnt) pal_amt
       FROM chart_acc, entry_sub
      WHERE entry_sub.acc_no = chart_acc.acc_no
        AND SUBSTR (chart_acc.acc_no, 1, 3) = 123
        AND chart_acc.acc_no NOT IN (SELECT DISTINCT acc_no
                                                FROM cust_not_handing)
   --  AND entry_sub.entry_no NOT IN (SELECT DISTINCT entry_no
         --                                      FROM sales_bill
                --                              WHERE handing_done = 0)
   GROUP BY chart_acc.acc_no, chart_acc.acc_name, entry_sub.acc_no
     HAVING SUM (entry_sub.entry_mnt) <> 0;


DROP VIEW ACCOUNTS.ITEM_MOVE_M;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.ITEM_MOVE_M
(BSEQ, BILL_NO, MANUAL_BILL_NO, BILL_TYPE, TR_TYPE_ID, 
 TYPENO, TR_TYPE_NAME, TOTAL, YEAR, DAT, 
 CUST_NO, CUST_NAME, PROV_NO, PROV_NAME, BOX_ACC_NO, 
 BOX_ACC_NAME, DR_ACC_NO, DR_ACC_NAME, DISCOUNT_ACC_NO, DISCOUNT_ACC_NAME, 
 CR_ACC_NO, CR_ACC_NAME, INV_ACC_NO, INV_ACC_NAME, COST_ACC_NO, 
 COST_ACC_NAME, DETAILES, STORE_NO, STORE_NAME, NET, 
 DISCOUNT, SANF_NO, SANF_D_NO, SANF_NAME, PART_NO, 
 UNIT_NAME, CAP, QTY, P_QTY, PSC, 
 SANF_PRICE, SANF_COST, STK_COST, CATEGORY, LEN, 
 WID, SAIZE, COLOR_NO, NOTES, STYL_NO, 
 TYPE_NO, GROUPNO, CAT_NO, SOURCE_NAME, INOUT)
AS 
(SELECT sales_bill.YEAR || sales_bill.bill_no bseq, sales_bill.bill_no,
           sales_bill.manual_bill_no,
           DECODE (bill_type, 1, '???', 2, '???', '') bill_type,
           trans_type.tr_type_id, trans_type.type_no, trans_type.type_name,
           sales_bill.total, sales_bill.YEAR, sales_bill.dat dat,
           sales_bill.cust_no, sales_bill.cust_name, NULL prov_no,
           NULL prov_name, DECODE (bill_type, 1, acc_no, NULL) box_acc_no,
           DECODE (bill_type,
                   1, (SELECT DISTINCT acc_name
                                  FROM chart_acc
                                 WHERE acc_no = sales_bill.acc_no
                                   AND sales_bill.acc_no IS NOT NULL),
                   NULL
                  ) box_acc_name,
           DECODE (bill_type, 1, NULL, acc_no) dr_acc_no,
           DECODE (bill_type,
                   1, NULL,
                   (SELECT DISTINCT acc_name
                               FROM chart_acc
                              WHERE acc_no = sales_bill.acc_no)
                  ) dr_acc_name,
           DECODE (NVL (discount, 0),
                   0, NULL,
                   (SELECT DISTINCT discount_acc
                               FROM stores
                              WHERE store_no = sales_bill.store_no)
                  ) discount_acc_no,
           DECODE
              (NVL (discount, 0),
               0, NULL,
               (SELECT DISTINCT acc_name
                           FROM chart_acc
                          WHERE acc_no IN (
                                          SELECT DISTINCT discount_acc
                                                     FROM stores
                                                    WHERE store_no =
                                                             sales_bill.store_no))
              ) discount_acc_name,
           acc_no1 cr_acc_no, (SELECT DISTINCT acc_name
                                          FROM chart_acc
                                         WHERE acc_no =
                                                  sales_bill.acc_no1)
                                                                  cr_acc_name,
           (SELECT DISTINCT inv_acc_no
                       FROM stores
                      WHERE store_no = sales_bill.store_no) inv_acc_no,
           (SELECT DISTINCT acc_name
                       FROM chart_acc
                      WHERE acc_no IN (
                               SELECT DISTINCT inv_acc_no
                                          FROM stores
                                         WHERE store_no =
                                                  sales_bill.store_no))
                                                                 inv_acc_name,
           (SELECT DISTINCT cost_acc_no
                       FROM stores
                      WHERE store_no = sales_bill.store_no) cost_acc_no,
           (SELECT DISTINCT acc_name
                       FROM chart_acc
                      WHERE acc_no IN (
                               SELECT DISTINCT cost_acc_no
                                          FROM stores
                                         WHERE store_no =
                                                  sales_bill.store_no))
                                                                cost_acc_name,
           sales_bill.detailes, sales_bill.store_no, stores.store_name, net,
           discount, sales_detailes.sanf_no, sales_detailes.sanf_dno,
           sanfs.sanf_name, sanfs.part_no, unit_name, sanfs.cap,
           sales_detailes.qty, sales_detailes.qty * -1 p_qty,
           sales_detailes.pcs, sales_detailes.sanf_price,
           sales_detailes.sanf_cost, sales_detailes.stk_cost,
                                                             /*(SELECT MAX (buy_detailes.sanf_price)
                                                                FROM buy_detailes
                                                               WHERE buy_detailes.sanf_dno = sanfs_d.sanf_dno
                                                                 AND sales_detailes.sanf_dno = sanfs_d.sanf_dno
                                                                 AND sales_detailes.sanf_dno = buy_detailes.sanf_dno
                                                                 AND dat IN (
                                                                        SELECT MAX (dat)
                                                                          FROM buy_detailes
                                                                         WHERE buy_detailes.sanf_dno = sanfs_d.sanf_dno
                                                                           AND sales_detailes.sanf_dno = sanfs_d.sanf_dno
                                                                           AND sales_detailes.sanf_dno = buy_detailes.sanf_dno))
                                                                                                                       stk_cost,*/
                                                             sanfs.CATEGORY,
           sanfs_d.len, sanfs_d.wid, sanfs_d.wid || '*' || sanfs_d.len sa,
           sales_detailes.color_no, sanfs.notes, sanfs.styl_no, sanfs.type_no,
           sanfs.groupno, sanfs.cat_no, 'sales', inout
      FROM sales_bill,
           stores,
           sales_detailes,
           sanfs,
           units,
           sanfs sanfs_d,
           trans_type
     WHERE sales_bill.store_no = stores.store_no
       AND sales_bill.bill_no = sales_detailes.bill_no
       AND sales_bill.YEAR = sales_detailes.YEAR
       AND sanfs.unit_no = units.unit_no
       AND sanfs.sanf_no = sanfs_d.sanf_no
       AND sales_detailes.sanf_no = sanfs.sanf_no
       AND sales_detailes.sanf_no = sanfs_d.sanf_no
       AND trans_type.type_no = 2
       AND cutting_or_slaes = 2
       AND NVL (bills_kinds, 1) = 1
    ----------------------- INVENTORY_RECEIVE---------------
    UNION ALL
    SELECT inventory_receive.YEAR || inventory_receive.bill_no bseq,
           inventory_receive.bill_no, inventory_receive.bill_no,
           DECODE (bill_type, 1, '???', 2, '???', '') bill_type,
           trans_type.tr_type_id, trans_type.type_no, trans_type.type_name,
           inventory_receive.total, inventory_receive.YEAR,
           inventory_receive.dat dat, NULL, NULL, inventory_receive.prov_no,
           inventory_receive.prov_name,
           DECODE (bill_type, 1, acc_no, NULL) box_acc_no,
