                   (SELECT DISTINCT discount_acc
                               FROM stores
                              WHERE store_no = inventory_receive.store_no)
                  ) discount_acc_no,
           DECODE
              (NVL (discount, 0),
               0, NULL,
               (SELECT DISTINCT acc_name
