           (SELECT DISTINCT inv_acc_no
                       FROM stores
                      WHERE store_no = buy_bill.store_no) inv_acc_no,
           (SELECT DISTINCT acc_name
                       FROM chart_acc
                      WHERE acc_no IN (
                               SELECT DISTINCT inv_acc_no
                                          FROM stores
                                         WHERE store_no =
                                                  buy_bill.store_no))
                                                                 inv_acc_name,
           (SELECT DISTINCT cost_acc_no
                       FROM stores
                      WHERE store_no = buy_bill.store_no) cost_acc_no,
           (SELECT DISTINCT acc_name
                       FROM chart_acc
                      WHERE acc_no IN (
                               SELECT DISTINCT cost_acc_no
                                          FROM stores
                                         WHERE store_no =
                                                  buy_bill.store_no))
                                                                cost_acc_name,
           buy_bill.note detailes, buy_bill.store_no, stores.store_name,
           0 net, 0, buy_detailes.sanf_no, buy_detailes.sanf_dno,
           sanfs.sanf_name, sanfs.part_no, unit_name, sanfs.cap,
           buy_detailes.qty, buy_detailes.qty p_qty, buy_detailes.pcs,
           buy_detailes.buy_price, buy_detailes.buy_price,
           buy_detailes.stk_cost, sanfs.CATEGORY, buy_detailes.size_frm,
           buy_detailes.size_to,
           buy_detailes.size_to || '*' || buy_detailes.size_frm sa,
           buy_detailes.color_no, sanfs.notes, sanfs.styl_no, sanfs.type_no,
           sanfs.groupno, sanfs.cat_no, '??? ??? ???', inout
      FROM gard buy_bill,
           stores,
           gard_detailes buy_detailes,
           sanfs,
           units,
           sanfs sanfs_d,
           trans_type
     WHERE buy_bill.store_no = stores.store_no
       AND buy_bill.gard_no = buy_detailes.gard_no
       AND buy_bill.YEAR = buy_detailes.YEAR
       -- AND cutting_or_slaes = 2
       AND sanfs.unit_no = units.unit_no
       AND sanfs.sanf_no = sanfs_d.sanf_no
       AND buy_detailes.sanf_no = sanfs.sanf_no
       AND buy_detailes.sanf_no = sanfs_d.sanf_no
       AND trans_type.type_no = 6
---------------------------------------RETURN_BUY-------------------------
    UNION ALL
    SELECT buy_bill.YEAR || buy_bill.return_no bseq, buy_bill.return_no,
           buy_bill.manual_return_no,
           DECODE (bill_type, 1, '???', 2, '???', '') bill_type,
           trans_type.tr_type_id, trans_type.type_no, trans_type.type_name,
           buy_bill.return_total, buy_bill.YEAR, buy_bill.ret_date dat, NULL,
           NULL, buy_bill.prov_no, buy_bill.prov_name,
           DECODE (bill_type, 1, acc_no, NULL) box_acc_no,
           DECODE (bill_type,
                   1, (SELECT DISTINCT acc_name
                                  FROM chart_acc
                                 WHERE acc_no = buy_bill.acc_no
                                   AND buy_bill.acc_no IS NOT NULL),
                   NULL
                  ) box_acc_name,
           DECODE (bill_type, 1, NULL, acc_no) dr_acc_no,
           DECODE (bill_type,
                   1, NULL,
                   (SELECT DISTINCT acc_name
                               FROM chart_acc
                              WHERE acc_no = buy_bill.acc_no)
                  ) dr_acc_name,
           DECODE (NVL (discount, 0),
                   0, NULL,
                   (SELECT DISTINCT discount_acc
                               FROM stores
                              WHERE store_no = buy_bill.store_no)
                  ) discount_acc_no,
           DECODE
              (NVL (discount, 0),
               0, NULL,
               (SELECT DISTINCT acc_name
                           FROM chart_acc
                          WHERE acc_no IN (SELECT DISTINCT discount_acc
                                                      FROM stores
                                                     WHERE store_no =
                                                              buy_bill.store_no))
              ) discount_acc_name,
           acc_no1 cr_acc_no, (SELECT DISTINCT acc_name
                                          FROM chart_acc
                                         WHERE acc_no =
                                                  buy_bill.acc_no1)
                                                                  cr_acc_name,
           (SELECT DISTINCT inv_acc_no
                       FROM stores
                      WHERE store_no = buy_bill.store_no) inv_acc_no,
           (SELECT DISTINCT acc_name
                       FROM chart_acc
                      WHERE acc_no IN (
                               SELECT DISTINCT inv_acc_no
                                          FROM stores
                                         WHERE store_no =
                                                  buy_bill.store_no))
                                                                 inv_acc_name,
           (SELECT DISTINCT cost_acc_no
                       FROM stores
                      WHERE store_no = buy_bill.store_no) cost_acc_no,
           (SELECT DISTINCT acc_name
                       FROM chart_acc
                      WHERE acc_no IN (
                               SELECT DISTINCT cost_acc_no
                                          FROM stores
                                         WHERE store_no =
                                                  buy_bill.store_no))
                                                                cost_acc_name,
           buy_bill.detailes, buy_bill.store_no, stores.store_name, net,
           discount, buy_detailes.sanf_no, buy_detailes.sanf_dno,
           sanfs.sanf_name, sanfs.part_no, unit_name, sanfs.cap,
           buy_detailes.ret_qty, buy_detailes.ret_qty * -1 p_qty,
           buy_detailes.pcs, buy_detailes.sanf_price, buy_detailes.sanf_cost,
           buy_detailes.stk_cost, sanfs.CATEGORY, buy_detailes.size_frm,
           buy_detailes.size_to,
           buy_detailes.size_to || '*' || buy_detailes.size_frm sa,
           buy_detailes.color_no, sanfs.notes, sanfs.styl_no, sanfs.type_no,
           sanfs.groupno, sanfs.cat_no, '????? ???????', inout
      FROM return_buy buy_bill,
           stores,
           return_buy_detailes buy_detailes,
           sanfs,
           units,
           sanfs sanfs_d,
           trans_type
     WHERE buy_bill.store_no = stores.store_no
       AND buy_bill.return_no = buy_detailes.return_no
       AND buy_bill.YEAR = buy_detailes.YEAR
       -- AND cutting_or_slaes = 2
       AND sanfs.unit_no = units.unit_no
       AND sanfs.sanf_no = sanfs_d.sanf_no
       AND buy_detailes.sanf_no = sanfs.sanf_no
       AND buy_detailes.sanf_no = sanfs_d.sanf_no
       AND trans_type.type_no = 3
---------------------------------------RETURN_SALES--------------------
    UNION ALL
    SELECT buy_bill.YEAR || buy_bill.return_no bseq, buy_bill.return_no,
           buy_bill.manual_return_no,
           DECODE (bill_type, 1, '???', 2, '???', '') bill_type,
           trans_type.tr_type_id, trans_type.type_no, trans_type.type_name,
           buy_bill.return_total, buy_bill.YEAR, buy_bill.ret_date dat,
           buy_bill.cust_no, buy_bill.cust_name, NULL, NULL,
           DECODE (bill_type, 1, acc_no, NULL) box_acc_no,
           DECODE (bill_type,
                   1, (SELECT DISTINCT acc_name
                                  FROM chart_acc
                                 WHERE acc_no = buy_bill.acc_no
                                   AND buy_bill.acc_no IS NOT NULL),
                   NULL
                  ) box_acc_name,
           DECODE (bill_type, 1, NULL, acc_no) dr_acc_no,
           DECODE (bill_type,
                   1, NULL,
                   (SELECT DISTINCT acc_name
                               FROM chart_acc
                              WHERE acc_no = buy_bill.acc_no)
                  ) dr_acc_name,
           DECODE (NVL (discount, 0),
                   0, NULL,
                   (SELECT DISTINCT discount_acc
                               FROM stores
                              WHERE store_no = buy_bill.store_no)
                  ) discount_acc_no,
           DECODE
              (NVL (discount, 0),
               0, NULL,
               (SELECT DISTINCT acc_name
                           FROM chart_acc
                          WHERE acc_no IN (SELECT DISTINCT discount_acc
                                                      FROM stores
                                                     WHERE store_no =
                                                              buy_bill.store_no))
              ) discount_acc_name,
           acc_no1 cr_acc_no, (SELECT DISTINCT acc_name
                                          FROM chart_acc
                                         WHERE acc_no =
                                                  buy_bill.acc_no1)
                                                                  cr_acc_name,
           (SELECT DISTINCT inv_acc_no
                       FROM stores
                      WHERE store_no = buy_bill.store_no) inv_acc_no,
           (SELECT DISTINCT acc_name
                       FROM chart_acc
                      WHERE acc_no IN (
                               SELECT DISTINCT inv_acc_no
                                          FROM stores
                                         WHERE store_no =
                                                  buy_bill.store_no))
                                                                 inv_acc_name,
           (SELECT DISTINCT cost_acc_no
                       FROM stores
                      WHERE store_no = buy_bill.store_no) cost_acc_no,
           (SELECT DISTINCT acc_name
                       FROM chart_acc
                      WHERE acc_no IN (
                               SELECT DISTINCT cost_acc_no
                                          FROM stores
                                         WHERE store_no =
                                                  buy_bill.store_no))
                                                                cost_acc_name,
           buy_bill.detailes, buy_bill.store_no, stores.store_name, net,
           discount, buy_detailes.sanf_no, buy_detailes.sanf_dno,
           sanfs.sanf_name, sanfs.part_no, unit_name, sanfs.cap,
           buy_detailes.ret_qty, buy_detailes.ret_qty p_qty, buy_detailes.pcs,
           buy_detailes.sanf_price, buy_detailes.sanf_cost,
           buy_detailes.stk_cost, sanfs.CATEGORY, buy_detailes.size_frm,
           buy_detailes.size_to,
           buy_detailes.size_to || '*' || buy_detailes.size_frm sa,
           buy_detailes.color_no, sanfs.notes, sanfs.styl_no, sanfs.type_no,
           sanfs.groupno, sanfs.cat_no, '????? ??????', inout
      FROM return_sales buy_bill,
           stores,
           return_sales_detailes buy_detailes,
           sanfs,
           units,
           sanfs sanfs_d,
           trans_type
     WHERE buy_bill.store_no = stores.store_no
       AND buy_bill.return_no = buy_detailes.return_no
       AND buy_bill.YEAR = buy_detailes.YEAR
       -- AND cutting_or_slaes = 2
       AND sanfs.unit_no = units.unit_no
       AND sanfs.sanf_no = sanfs_d.sanf_no
       AND buy_detailes.sanf_no = sanfs.sanf_no
       AND buy_detailes.sanf_no = sanfs_d.sanf_no
       AND trans_type.type_no = 1);


DROP VIEW ACCOUNTS.ITEM_DEFF;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.ITEM_DEFF
(TR_INV_M_ID, DOC_TYPE, BILL_DOC_TYPE, DOC_NO, INVOIC_ID, 
 I_CODE, I_QTY, P_CODE, WID, LEN, 
 COLOR_NO, FROM_W, FROM_L, MCOLOR_REQ, CAT, 
 PART_NO, P_SIZE, GROUPNO, GROUP_NAME, TYPE_NO, 
 TYPE_NAME, STYL_NO, STYLE_NAME, P_QTY, PP_QTY, 
 GOOD_QYT, DAMG_QYT, BAD_QYT, I_DATE, SANF_PRICE, 
 I_COST, W_CODE, COST_CNTR_NO, SANF_COST, STK_COST, 
 A_DESC, I_CURR, GR_NO, EXPIRE_DATE, BATCH_NO, 
 FREE_QTY, PF_QTY, RCRD_NO, SERIAL, UOM_ID, 
 UOM_CODE, DEBIT_ACCOUNT, ACC_NAME, PROV_NO, PROV_NAME, 
 BOX_ACC_NO, BOX_ACC_NAME, DR_ACC_NO, DR_ACC_NAME, DISCOUNT_ACC_NO, 
 DISCOUNT_ACC_NAME, CR_ACC_NO, CR_ACC_NAME, INV_ACC_NO, INV_ACC_NAME, 
 COST_ACC_NO, COST_ACC_NAME, INV_NAME, PRICE_SALE, IT_NAME, 
 UOM_ID_SALES, MC_ID, TR_INV_TYPE_NAME, CAT_NAME, SALE_TOTAL, 
 INV_ID, CAT_ID, BC_ID, ISPROD, UOM_VAL, 
 T_QTY_SALES, GLH_ID, MAIN_NAME, PQTY, SALETOTAL, 
 CE_ID, CE_NAME, CE_CODE, SALETOT, SALE, 
 DESCS, NOTSS, ENAMEE, FALG_CANCEL, FLAG_POSTED, 
 INOUT, CUR_NO)
AS 
(SELECT bseq tr_inv_m_id, tr_type_id, item_move_m.typeno,
           manual_bill_no doc_no, bill_no invoic_id, sanfs.sanf_no item_id,
           NVL (qty, 0) i_qty,
                              --+nvl(tr_inv_d.DAMG_QTY,0)+nvl(tr_inv_d.BAD_QTY,0)) i_QTY,
                              item_move_m.sanf_d_no item_id, item_move_m.wid,
           item_move_m.len, NVL (item_move_m.color_no, 0), style.from_w,
           style.from_l, style.dcolor_req, sanfs.CATEGORY, sanfs.part_no,
           item_move_m.cap, sanfs.groupno, group1.group_name, sanfs.type_no,
           TYPES.type_name, style.styl_code, style.style_name,
           NVL (p_qty, 0) p_qty, NVL (p_qty, 0) pp_qty, 0, 0 damg_qty,
           0 bad_qty, dat trans_date, item_move_m.sanf_price sanf_price,
           item_move_m.stk_cost, store_no inv_id, 1 costcn_id,
           item_move_m.sanf_cost, item_move_m.stk_cost,
           sanfs.sanf_name item_name, 1, bseq tr_inv_m_id, NULL, 0, 0, 0, 0,
           bseq tr_inv_d_id, sanfs.unit_no uom_id, unit_name uom_code,
           DECODE (inout, 1, cr_acc_no, dr_acc_no),
           DECODE (inout,
                   1, NVL (cr_acc_name, prov_name),
                   NVL (cust_name, dr_acc_name)
                  ) acc_name,
           prov_no, prov_name, box_acc_no, box_acc_name, dr_acc_no,
           dr_acc_name, discount_acc_no, discount_acc_name, cr_acc_no,
           cr_acc_name, inv_acc_no, inv_acc_name, cost_acc_no, cost_acc_name,
           store_name w_name, item_move_m.sanf_price price_sale,
              sanfs.sanf_name
           || DECODE (item_move_m.wid,
                      1, TO_CHAR ('-' || item_move_m.color_no),
                      item_move_m.len || '*' || item_move_m.wid
                     ),
           sanfs.unit_no uom_id_sales, sanfs.groupno main_cat_id,
           tr_type_name type_name, source_name cat_name,
           (item_move_m.sanf_price * NVL (qty, 0)) sale_total,
           store_no inv_id, 1 cat_id, sanfs.type_no branch_cat_id, 0 isprod,
           psc wgram, qty t_qty_sales, bseq glh_id, 'GOODS' main_name, p_qty,
           (p_qty * item_move_m.sanf_price), 1 ceid, NULL cename, 1 cecode,
           total sale_total, (item_move_m.sanf_price * NVL (qty, 0)),
           detailes description, detailes notes, store_name namee,
           0 falg_cancel, 0 flag_posted, inout, sanfs.cur_no
      FROM item_move_m, sanfs, group1, TYPES, style
     WHERE sanfs.sanf_no = item_move_m.sanf_no
       AND item_move_m.sanf_d_no IS NULL
       AND sanfs.groupno <> 6
       AND sanfs.groupno = group1.group_no
       AND sanfs.type_no = TYPES.type_no
       AND sanfs.styl_no = style.shape_style_no);


DROP VIEW ACCOUNTS.SANFS_PAL;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.SANFS_PAL
(SANF_NAME, SANF_NO, CAP, YEAR, TYPE_NO, 
 STORE_NO, CUR_NO, PAL, S_COST)
AS 
SELECT   sanfs.sanf_name, sanfs.sanf_no, 1 cap, MAX (YEAR), sanfs.type_no,
            item_move_d.store_no, NVL (sanfs.cur_no, 1) cur_no,
            NVL (SUM (p_qty), 0) pal, NVL (AVG (item_move_d.sanf_price), 0)
       FROM item_move_d, sanfs
      WHERE
            -- AND (tr_date between :date1 and :date2)
            -- AND SANF_NO=:SANF_NO AND CAP=:CAP AND TRANS_DETAILES.PCS>0
            --  AND TRANS_DETAILES.TRANS_NO=:TRANS_NO
            item_move_d.sanf_no = sanfs.sanf_no
   -- AND TRANS_DETAILES.YEAR=:YEAR
   --  AND TRANS_DETAILES.SEQ_NO=:SEQ_NO;
   GROUP BY sanfs.sanf_name,
            sanfs.sanf_no,
            --trans_detailes.YEAR,
            sanfs.type_no,
            NVL (sanfs.cur_no, 1),
            item_move_d.store_no;


