           cr_acc_name, inv_acc_no, inv_acc_name, cost_acc_no, cost_acc_name,
           store_name w_name, item_move_d.sanf_price price_sale,
              sanfs_d.sanf_name
           || DECODE (sanfs_d.wid,
                      1, TO_CHAR ('-' || sanfs_d.color_no),
                      sanfs_d.len || '*' || sanfs_d.wid
                     ),
           sanfs.unit_no uom_id_sales, sanfs.groupno main_cat_id,
           tr_type_name type_name, source_name cat_name,
           (item_move_d.sanf_price * NVL (qty, 0)) sale_total,
           store_no inv_id, 1 cat_id, sanfs.type_no branch_cat_id, 0 isprod,
           psc wgram, qty t_qty_sales, bseq glh_id, 'GOODS' main_name, p_qty,
           (p_qty * item_move_d.sanf_price), 1 ceid, NULL cename, 1 cecode,
           total sale_total, (item_move_d.sanf_price * NVL (qty, 0)),
           detailes description, detailes notes, store_name namee,
           0 falg_cancel, 0 flag_posted, inout, sanfs.cur_no
      FROM item_move_d, sanfs_d, sanfs, group1, TYPES, style
     WHERE sanfs_d.sanf_no = item_move_d.sanf_no
       AND sanfs.sanf_no = item_move_d.sanf_no
       AND sanfs_d.sanf_dno(+) = item_move_d.sanf_d_no
       AND sanfs.sanf_no = sanfs_d.sanf_no
       AND sanfs.groupno = group1.group_no
       AND sanfs.type_no = TYPES.type_no
       AND sanfs.styl_no = style.shape_style_no);


DROP VIEW ACCOUNTS.ITEM_MOVEMENT;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.ITEM_MOVEMENT
(TR_INV_M_ID, DOC_TYPE, BILL_DOC_TYPE, DOC_NO, INVOIC_ID, 
 I_CODE, I_QTY, P_CODE, WID, LEN, 
 COLOR_NO, CAT, PART_NO, P_SIZE, GROUPNO, 
 GROUP_NAME, TYPE_NO, TYPE_NAME, STYL_NO, STYLE_NAME, 
 P_QTY, PP_QTY, GOOD_QYT, DAMG_QYT, BAD_QYT, 
 I_DATE, I_COST, TOTAL, SANF_PRICE, NET, 
 W_CODE, COST_CNTR_NO, STK_COST, A_DESC, I_CURR, 
 GR_NO, EXPIRE_DATE, BATCH_NO, FREE_QTY, PF_QTY, 
 RCRD_NO, SERIAL, UOM_ID, UOM_CODE, DISCOUNT, 
 DEBIT_ACCOUNT, ACC_NAME, PROV_NO, PROV_NAME, BOX_ACC_NO, 
 BOX_ACC_NAME, DR_ACC_NO, DR_ACC_NAME, DISCOUNT_ACC_NO, DISCOUNT_ACC_NAME, 
 CR_ACC_NO, CR_ACC_NAME, INV_ACC_NO, INV_ACC_NAME, COST_ACC_NO, 
 COST_ACC_NAME, INV_NAME, PRICE_SALE, IT_NAME, UOM_ID_SALES, 
 MC_ID, TR_INV_TYPE_NAME, CAT_NAME, SALE_TOTAL, INV_ID, 
 CAT_ID, BC_ID, ISPROD, UOM_VAL, T_QTY_SALES, 
 GLH_ID, MAIN_NAME, PQTY, SALETOTAL, CE_ID, 
 CE_NAME, CE_CODE, SALETOT, SALE, DESCS, 
 NOTSS, ENAMEE, FALG_CANCEL, FLAG_POSTED, INOUT, 
 CUR_NO)
AS 
(SELECT bseq tr_inv_m_id, tr_type_id, item_move_d.typeno,
           manual_bill_no doc_no, bill_no invoic_id, sanfs_d.sanf_no item_id,
           NVL (qty, 0) i_qty,
                              --+nvl(tr_inv_d.DAMG_QTY,0)+nvl(tr_inv_d.BAD_QTY,0)) i_QTY,
                              sanfs_d.sanf_dno item_id, sanfs_d.wid,
           sanfs_d.len, NVL (item_move_d.color_no, 0), sanfs.CATEGORY,
           sanfs.part_no, item_move_d.cap, sanfs.groupno, group1.group_name,
           sanfs.type_no, TYPES.type_name, style.styl_code, style.style_name,
           NVL (p_qty, 0) p_qty, NVL (p_qty, 0) pp_qty, 0, 0 damg_qty,
           0 bad_qty, dat trans_date, item_move_d.sanf_cost, total,
           NVL (item_move_d.sanf_cost, item_move_d.sanf_price), net,
           store_no inv_id, 1 costcn_id, item_move_d.sanf_cost,
           sanfs_d.sanf_name item_name, 1, bseq tr_inv_m_id, NULL, 0, 0, 0, 0,
           bseq tr_inv_d_id, sanfs.unit_no uom_id, unit_name uom_code,
           discount, DECODE (inout, 1, cr_acc_no, dr_acc_no),
           DECODE (inout,
                   1, NVL (cr_acc_name, prov_name),
                   NVL (cust_name, dr_acc_name)
                  ) acc_name,
           prov_no, prov_name, box_acc_no, box_acc_name, dr_acc_no,
           dr_acc_name, discount_acc_no, discount_acc_name, cr_acc_no,
           cr_acc_name, inv_acc_no, inv_acc_name, cost_acc_no, cost_acc_name,
           store_name w_name, item_move_d.sanf_price price_sale,
              sanfs_d.sanf_name
           || DECODE (sanfs_d.wid,
                      1, TO_CHAR ('-' || sanfs_d.color_no),
                      sanfs_d.len || '*' || sanfs_d.wid
                     ),
           sanfs.unit_no uom_id_sales, sanfs.groupno main_cat_id,
           tr_type_name type_name, source_name cat_name,
           (item_move_d.sanf_price * NVL (qty, 0)) sale_total,
           store_no inv_id, 1 cat_id, sanfs.type_no branch_cat_id, 0 isprod,
           psc wgram, qty t_qty_sales, bseq glh_id, 'GOODS' main_name, p_qty,
           (p_qty * item_move_d.sanf_price), 1 ceid, NULL cename, 1 cecode,
           total sale_total, (item_move_d.sanf_price * NVL (qty, 0)),
           detailes description, detailes notes, store_name namee,
           0 falg_cancel, 0 flag_posted, inout, sanfs.cur_no
      FROM item_move_d, sanfs_d, sanfs, group1, TYPES, style
     WHERE sanfs_d.sanf_no = item_move_d.sanf_no
       AND sanfs.sanf_no = item_move_d.sanf_no
       AND sanfs_d.sanf_dno(+) = item_move_d.sanf_d_no
       AND sanfs.sanf_no = sanfs_d.sanf_no
       AND sanfs.groupno = group1.group_no
       AND sanfs.type_no = TYPES.type_no
       AND sanfs.styl_no = style.shape_style_no);


DROP VIEW ACCOUNTS.SANFS_D_PAL;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.SANFS_D_PAL
(SANF_NAME, SANF_NO, SANF_DNO, CAP, YEAR, 
 TYPE_NO, STORE_NO, CUR_NO, PAL, S_COST)
AS 
SELECT   sanfs.sanf_name, sanfs.sanf_no, sanf_dno, 1 cap, MAX (YEAR),
            sanfs.type_no, item_move_d.store_no, NVL (sanfs.cur_no, 1) cur_no,
            NVL (SUM (p_qty), 0) pal, NVL (AVG (item_move_d.sanf_price), 0)
       FROM item_move_d, sanfs_d sanfs
      WHERE
            -- AND (tr_date between :date1 and :date2)
            -- AND SANF_NO=:SANF_NO AND CAP=:CAP AND TRANS_DETAILES.PCS>0
            --  AND TRANS_DETAILES.TRANS_NO=:TRANS_NO
            item_move_d.sanf_no = sanfs.sanf_no
        AND item_move_d.sanf_d_no = sanfs.sanf_dno
   -- AND TRANS_DETAILES.YEAR=:YEAR
   --  AND TRANS_DETAILES.SEQ_NO=:SEQ_NO;
   GROUP BY sanfs.sanf_name,
            sanfs.sanf_no,
            sanfs.sanf_dno,
            --trans_detailes.YEAR,
            sanfs.type_no,
            NVL (sanfs.cur_no, 1),
            item_move_d.store_no;


DROP VIEW ACCOUNTS.RASED;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.RASED
(I_CODE, ITEM_ID, ITEM_NAME, INV_ID, INVNAME, 
 SUM_TP, SUM_I_TP, SUM_GOOD_QTY, SUM_BAD_QTY, SUM_DAMG_QTY, 
 UOM_CODE, UOM_ID, PSIZE, COUNT, DATE_END, 
 BARACODE, BRANCH_NAME, BRANCH_CAT_ID, G_SIZE, DESC_PERS, 
 COLOR_NO)
AS 
SELECT DISTINCT i_code, p_code item_id, it_name item_name, inv_id,
                   inv_name, ROUND (SUM (p_qty), 0) qty,
                   ROUND (SUM (p_qty), 0), 0 sum_good_qty, 0 sum_bad_qty,
                   0 sum_damg_qty, uom_code, uom_id, 1 psize, 1 COUNT,
                   NULL date_end, NULL baracode, NULL branch_name,
                   NULL branch_cat_id, NULL g_size, NULL desc_pers,COLOR_NO
              FROM item_movement_d
             WHERE 1 = 1
            HAVING SUM (p_qty) > 0 --AND SUM (p_qty * i_cost) > 0
          GROUP BY i_code, p_code, it_name, uom_code, uom_id, inv_id,
                   inv_name,COLOR_NO;


DROP VIEW ACCOUNTS.STRG_WCHILD;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.STRG_WCHILD
(I_CODE, P_CODE, P_SIZE, W_CODE, AVL_QTY, 
 EXPIRE_DATE, BATCH_NO)
AS 
SELECT rased.item_id, rased.item_id, psize, rased.inv_id, sum_i_tp, NULL,
          NULL
     FROM rased;


DROP VIEW ACCOUNTS.AVVG;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.AVVG
(I_CODE, ITEM_ID, PART_NO, ITEM_NAME, SNAF_NAME, 
 UOM_CODE, UOM_ID, COUNT, INV_ID, INVNAME, 
 SUM_PRICE, SUM_TP, AV1, GROUPNO, GROUP_NAME, 
 TYPE_NO, TYPE_NAME, STYL_NO, STYLE_NAME, CAT, 
 CUR_NO, STK_COST)
AS 
SELECT DISTINCT i_code, p_code item_id, part_no, it_name item_name, a_desc,
                   uom_code, uom_id, 1 COUNT, inv_id, inv_name,
                   ROUND (SUM (p_qty * i_cost), 0) sum_price,
                   ROUND (SUM (p_qty), 0) qty,
                   DECODE (SUM (NVL (p_qty, 1)),
                           0, 0,
                           (SUM (p_qty * i_cost)) / SUM (NVL (p_qty, 1))
                          ) average,
                   groupno, group_name, type_no, type_name, styl_no,
                   style_name, cat, cur_no,max(stk_cost)
              FROM item_movement_d
             WHERE 1 = 1
            HAVING SUM (p_qty) > 0 AND SUM (p_qty * i_cost) > 0
                                                              --AND  TR_TYPE=1
          --having  NVL(SUM(b.P_QTY),0) > 0
   GROUP BY        i_code,
                   p_code,
                   part_no,
                   it_name,
                   a_desc,
                   uom_code,
                   uom_id,
                   inv_id,
                   inv_name,
                   groupno,
                   group_name,
                   type_no,
                   type_name,
                   styl_no,
                   style_name,
                   cat,
                   cur_no
--,TR_TYPE;;;;;;


DROP VIEW ACCOUNTS.CUTTER_FROM_UNCALC;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUTTER_FROM_UNCALC
(CUTTER_NO, CUTTER_NAME, CUTTER_ACC, DDATE, CUTTING_DATE, 
 STYLE_NO, STYLE_NAME, SQTY, POST, UN, 
 AMT)
AS 
SELECT   cutter_no1, cutting_bill_in_cut_n.cutter_name, cutter.acc_no,
            MAX (ddate) ddate, cutting_date, shape_style_no, style_name,
            SUM (cutting_bill_in_cut_n.qty) sqty, SUM (POST) POST,
            SUM (cutting_bill_in_cut_n.qty) - SUM (POST) un,
            (SUM (cutting_bill_in_cut_n.cutter_pcs_price1 * POST)) amt
       FROM cutting_bill_in_cut_N, cutter
      WHERE
-- AND TO_CHAR(CUTING_TRANSD.DDATE,'DD/MM/YYYY')=:DDATE
      --  AND multi_cloths.ohid = cutting_bill_in_cut.ohid
            ordsid = 2
        AND calc_cutter = 0
        AND cutting_bill_in_cut_n.cutter_no1 = cutter.cutter_no
   --  AND POST=1
   GROUP BY cutter_no1,
            cutting_bill_in_cut_n.cutter_name,
            cutting_date,
            style_name,
            cutter.acc_no, shape_style_no;


DROP VIEW ACCOUNTS.RASED_GARD;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.RASED_GARD
(I_CODE, ITEM_ID, ITEM_NAME, INV_ID, INVNAME, 
 SUM_TP, SUM_I_TP, SUM_GOOD_QTY, SUM_BAD_QTY, SUM_DAMG_QTY, 
 UOM_CODE, UOM_ID, PSIZE, COUNT, DATE_END, 
 BARACODE, BRANCH_NAME, BRANCH_CAT_ID, G_SIZE, DESC_PERS, 
 WID, LEN, COLOR_NO)
AS 
SELECT DISTINCT i_code, p_code item_id, it_name item_name, inv_id,
                   inv_name, ROUND (SUM (p_qty), 0) qty,
                   ROUND (SUM (p_qty), 0), 0 sum_good_qty, 0 sum_bad_qty,
                   0 sum_damg_qty, uom_code, uom_id, 1 psize, 1 COUNT,
                   NULL date_end, NULL baracode, NULL branch_name,
                   NULL branch_cat_id, NULL g_size, NULL desc_pers, WID,len, color_no
              FROM item_movement_d
             WHERE 1 = 1
          --- HAVING SUM (p_qty) > 0              --AND SUM (p_qty * i_cost) > 0
   GROUP BY        i_code,
                   p_code,
                   it_name,
                   uom_code,
                   uom_id,
                   inv_id,
