                   color_no;


DROP VIEW ACCOUNTS.TAILOR_FROM_UNCALC_GABZOR;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.TAILOR_FROM_UNCALC_GABZOR
(TAILOR_NO, TAILOR_NAME, TAILOR_ACC, TAILOR_DATE, G_POST, 
 G_AMT)
AS 
SELECT   tailor_no, tailor_name, tailor_acc, tailor_date,
            SUM (g_post) g_post, (SUM (g_post * g_amt)) g_amt
       FROM tailor_gabzor
      WHERE 1 = 1
   GROUP BY tailor_no, tailor_name, tailor_date, tailor_acc;


DROP VIEW ACCOUNTS.CUST_ALL_AMOUNT_LA_2026;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUST_ALL_AMOUNT_LA_2026
(CUST_NO, CUST_NAME, FAX, C_B_N_H, OLD_BALANCE, 
 BALANCE, PHONE_NUM)
AS 
SELECT DISTINCT cust.cust_no, cust.cust_name cust_name, FAX, 
                   NVL (MAX (c_balance), 0),
                   NVL (MAX (pal_amt), 0) - NVL (MAX (c_balance), 0),
                   NVL (MAX (pal_amt), 0), MAX (phone_num)
              FROM cust,
                   accounts.cust_all_pal_amt,
                   cust_cloths_not_handing_amount
             WHERE cust.cust_no = cust_all_pal_amt.cust_no
               AND cust_cloths_not_handing_amount.cust_no = cust.cust_no
               AND cust_cloths_not_handing_amount.cust_no =
                                                      cust_all_pal_amt.cust_no
               AND SUBSTR (cust_all_pal_amt.acc_no, 1, 3) = 123
          GROUP BY cust.cust_name, cust.cust_no, FAX;


DROP VIEW ACCOUNTS.CUST_PAL_AMT_ELSE;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUST_PAL_AMT_ELSE
(CUST_NO, CUST_NAME, PAL_AMT)
AS 
SELECT   cust.cust_no, cust.cust_name, SUM (entry_sub.entry_mnt) pal_amt
       FROM cust, entry_sub
      WHERE entry_sub.giving = cust.cust_no AND cust.acc_no = entry_sub.acc_no 
      and cust.cust_no not in (select cust_no from CUST_ALL_AMOUNT_LA_2026 where 1=1) 
   GROUP BY cust.cust_no, cust.cust_name
     HAVING SUM (entry_sub.entry_mnt) <> 0;


DROP VIEW ACCOUNTS.TAILOR_FROM_UNCALC_SUM;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.TAILOR_FROM_UNCALC_SUM
(TAILOR_NO, TAILOR_NAME, TAILOR_ACC, TAILOR_DATE, SUM_AMT, 
 G_POST, G_AMT, ADDCOST2, ADDCOST3, SUM_ALL)
AS 
SELECT   tailor_from_uncalc.tailor_no, tailor_from_uncalc.tailor_name,
            tailor_from_uncalc.tailor_acc, tailor_from_uncalc.tailor_date,
            SUM (NVL (amt, 0)) sum_amt, tailor_from_uncalc_gabzor.g_post,
            NVL (tailor_from_uncalc_gabzor.g_amt, 0), sum(NVL (addcost2, 0)),
            sum(NVL (addcost3, 0)),
            (  SUM (NVL (amt, 0))
             + NVL (g_amt, 0)
             + sum(NVL (addcost2, 0))
             + sum(NVL (addcost3, 0))
            ) sum_all
       FROM tailor_from_uncalc, tailor_from_uncalc_gabzor
      WHERE tailor_from_uncalc.tailor_no = tailor_from_uncalc_gabzor.tailor_no
        AND tailor_from_uncalc.tailor_date =
                                         tailor_from_uncalc_gabzor.tailor_date
   GROUP BY tailor_from_uncalc.tailor_no,
            tailor_from_uncalc.tailor_name,
            tailor_from_uncalc.tailor_acc,
            tailor_from_uncalc.tailor_date,
            tailor_from_uncalc_gabzor.g_post,
            tailor_from_uncalc_gabzor.g_amt;


DROP VIEW ACCOUNTS.CUTTER_FROM_UNCALC_SUM;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUTTER_FROM_UNCALC_SUM
(CUTTER_NO, CUTTER_NAME, CUTTER_ACC, CUTTING_DATE, SUM_AMT)
AS 
SELECT   cutter_no,cutter_name,cutter_acc,
            cutting_date,sum(amt)
       FROM cutter_from_uncalc
      WHERE 1=1
   GROUP BY cutter_no,
            cutter_name,
            cutting_date,
            cutter_acc;


DROP VIEW ACCOUNTS.CUTTER_FROM_QTY_N;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.CUTTER_FROM_QTY_N
(CUTTER_NO, CUTTER_NAME, DDATE, CUTTING_DATE, STYLE_NAME, 
 SQTY, POST, UN, AMT)
AS 
SELECT   cutter_no1, cutter_name, MAX (ddate) ddate,
            TO_CHAR(NVL (cutting_date, MAX (ddate)),'DD/MM/YYYY'), style_name,
            SUM (cutting_bill_in_cut_n.qty) sqty, SUM (POST) POST,
            SUM (cutting_bill_in_cut_n.qty) - SUM (POST) un,
            (SUM (cutting_bill_in_cut_n.cutter_pcs_price1 * POST)) amt
       FROM cutting_bill_in_cut_n
      WHERE
-- AND TO_CHAR(CUTING_TRANSD.DDATE,'DD/MM/YYYY')=:DDATE
      --  AND multi_cloths.ohid = cutting_bill_in_cut.ohid
            ordsid = 2
   --  AND POST=1
   GROUP BY cutter_no1, cutter_name, cutting_date, style_name, POST;


DROP VIEW ACCOUNTS.LAST_DATE;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.LAST_DATE
(I_CODE, ITEM_NAME, SNAF_NAME, UOM_CODE, UOM_ID, 
 COUNT, MAXDATE)
AS 
SELECT DISTINCT i_code, a_desc item_name, a_desc, uom_code, uom_id,
                   1 COUNT,                               -- inv_id, inv_name,
                           MAX (i_date)
              FROM item_movement_d
             WHERE 1 = 1
                        --  HAVING SUM (p_qty) > 0 AND SUM (p_qty * i_cost) > 0
                   AND p_qty > 0 AND inv_id <> 11
                   AND BILL_DOC_TYPE <> 1
          -- having   max(i_date)  in (select MAX (i_date) from item_movement_d
           --    WHERE 1 = 1
                          --  HAVING SUM (p_qty) > 0 AND SUM (p_qty * i_cost) > 0
                 --    AND p_qty > 0 AND inv_id <> 11
                 -----    group by i_code )
   GROUP BY        i_code,
                   -- stk_cost,
                   a_desc,
                   a_desc,
                   uom_code,
                   uom_id                                 --, inv_id, inv_name
--,TR_TYPE;;;;;;;;;;;;;;;


