DROP PACKAGE ACCOUNTS.SUM_ALL_PCS2;

CREATE OR REPLACE PACKAGE ACCOUNTS.sum_all_pcs2
AS
 FUNCTION sum_all_pcs_with_linked_sanfs2(SANF_NO_IN in number , store_no_in in number ,TRANS_DATE_IN IN DATE) RETURN NUMBER ;

END sum_all_pcs2;
/

SHOW ERRORS;


DROP PACKAGE ACCOUNTS.SUM_ALL_PCS;

CREATE OR REPLACE PACKAGE ACCOUNTS.sum_all_pcs
AS
 FUNCTION sum_all_pcs_with_linked_sanfs(SANF_NO_IN in number , store_no_in in number) RETURN NUMBER ;

END sum_all_pcs;
/

SHOW ERRORS;


DROP PACKAGE BODY ACCOUNTS.SUM_ALL_PCS2;

CREATE OR REPLACE PACKAGE BODY ACCOUNTS.sum_all_pcs2 
AS
  FUNCTION sum_all_pcs_with_linked_sanfs2(SANF_NO_IN number , store_no_in number, TRANS_DATE_IN DATE) RETURN NUMBER IS

cursor c(FATHERNO number)is select SANF_NO  from ACCOUNTS.SANF_CHILDS where FATHER_NO=FATHERNO;
 num number(30,2);
 sum_pcs  number(30,2):=0;
 count1 number(10);
sanffather  number(10);
sanfno  number(10);
begin

  SELECT nvl(COUNT(ACCOUNTS.SANF_FATHER.FATHER_NO),0) into count1
FROM ACCOUNTS.SANF_FATHER
WHERE ACCOUNTS.SANF_FATHER.SANF_NO=SANF_NO_IN ;

if count1=0 then


	SELECT  COUNT(ACCOUNTS.SANF_CHILDS.FATHER_NO)into  count1
FROM ACCOUNTS.SANF_CHILDS
WHERE ACCOUNTS.SANF_CHILDS.SANF_NO=SANF_NO_IN;


if count1=0 then
begin

SELECT  NVL(SUM(ACCOUNTS.TRANS_DETAILES.PCS),0) into num
FROM ACCOUNTS.TRANS_DETAILES, ACCOUNTS.TRANS
WHERE (ACCOUNTS.TRANS.STORE_NO=store_no_in
