 AND  (ACCOUNTS.TRANS_DETAILES.YEAR=ACCOUNTS.TRANS.YEAR
 AND ACCOUNTS.TRANS_DETAILES.TRANS_NO=ACCOUNTS.TRANS.TRNS_NO)
 AND ACCOUNTS.TRANS.TR_DATE<=TRANS_DATE_IN;
 sum_pcs:=num;

 EXCEPTION WHEN NO_DATA_FOUND THEN
