 AND ACCOUNTS.TRANS.TR_DATE<=TRANS_DATE_IN;

 EXCEPTION WHEN NO_DATA_FOUND THEN
	 num:= 0;
end;
sum_pcs:=sum_pcs+num;


end loop;
--------------------------------------------------------------

end if;

else

SELECT FATHER_NO into sanffather
FROM ACCOUNTS.SANF_FATHER
