--pcs of father--------------------------------
SELECT ACCOUNTS.SANF_FATHER.sanf_no into sanfno
FROM ACCOUNTS.SANF_FATHER
WHERE ACCOUNTS.SANF_FATHER.FATHER_NO=sanffather;

begin
 SELECT  NVL(SUM(ACCOUNTS.TRANS_DETAILES.PCS),0) INTO  num
FROM ACCOUNTS.TRANS_DETAILES, ACCOUNTS.TRANS
WHERE (ACCOUNTS.TRANS.STORE_NO=store_no_in
 AND ACCOUNTS.TRANS_DETAILES.SANF_NO=sanfno)
 AND  (ACCOUNTS.TRANS_DETAILES.YEAR=ACCOUNTS.TRANS.YEAR
 AND ACCOUNTS.TRANS_DETAILES.TRANS_NO=ACCOUNTS.TRANS.TRNS_NO)
 AND ACCOUNTS.TRANS.TR_DATE<=TRANS_DATE_IN;


 EXCEPTION WHEN NO_DATA_FOUND THEN
 num:=0;
 end;

sum_pcs:=num;
-------end pcs of father------------------------




--------------------------------------------------------------
for x in c(sanffather)
loop


begin

 SELECT  NVL(SUM(ACCOUNTS.TRANS_DETAILES.PCS),0) into num
FROM ACCOUNTS.TRANS_DETAILES, ACCOUNTS.TRANS
WHERE (ACCOUNTS.TRANS.STORE_NO=store_no_in
 AND ACCOUNTS.TRANS_DETAILES.SANF_NO=x.sanf_no)
 AND  (ACCOUNTS.TRANS_DETAILES.YEAR=ACCOUNTS.TRANS.YEAR
 AND ACCOUNTS.TRANS_DETAILES.TRANS_NO=ACCOUNTS.TRANS.TRNS_NO)
 AND ACCOUNTS.TRANS.TR_DATE<=TRANS_DATE_IN;

 EXCEPTION WHEN NO_DATA_FOUND THEN
	 num:= 0;
end;
sum_pcs:=sum_pcs+num;


end loop;
--------------------------------------------------------------

end if;


return sum_pcs;



END;

END sum_all_pcs2;
/

