AS
  FUNCTION sum_all_pcs_with_linked_sanfs(SANF_NO_IN number , store_no_in number) RETURN NUMBER IS

cursor c(FATHERNO number)is select SANF_NO  from ACCOUNTS.SANF_CHILDS where FATHER_NO=FATHERNO;
 num number(30,2);
 sum_pcs  number(30,2):=0;
 count1 number(10);
sanffather  number(10);
sanfno  number(10);
