  SELECT nvl(COUNT(ACCOUNTS.SANF_FATHER.FATHER_NO),0) into count1
FROM ACCOUNTS.SANF_FATHER
WHERE ACCOUNTS.SANF_FATHER.SANF_NO=SANF_NO_IN ;

if count1=0 then


	SELECT  COUNT(ACCOUNTS.SANF_CHILDS.FATHER_NO)into  count1
