 EXCEPTION WHEN NO_DATA_FOUND THEN
 num:=0;
 end;

sum_pcs:=num;
-------end pcs of father------------------------




--------------------------------------------------------------
for x in c(sanffather)
loop


begin

 SELECT  NVL(SUM(ACCOUNTS.TRANS_DETAILES.PCS),0) into num
