DROP FUNCTION ACCOUNTS.GET_OB_ITEMSS4;

CREATE OR REPLACE FUNCTION ACCOUNTS.GET_OB_itemss4(item_no VARCHAR,inv_no  VARCHAR,uom_no VARCHAR,tdate  date ) RETURN NUMBER IS
A NUMBER;
B NUMBER;
CP NUMBER;
BEGIN
/*select     nvl(round(sum(B.P_QTY),0),0)     Into  A
from items A ,tr_inv_d  B  ,TR_INV_M m
WHERE A.item_id=B.item_id 
  and A.item_id=item_no
AND b.TR_INV_M_ID=m.TR_INV_M_ID
and m.FALG_CANCEL<>1 
and    b.item_id=item_no
   and  m.TRANS_DATE  < tdate  and  m.inv_id=inv_no and b.uom_id=uom_no ;
   
   */
   select     nvl(sum(P_QTY),0)    Into  b
from  ITEM_MOVE_D  
WHERE  SANF_D_NO= SANF_D_NO
  
 
 
and     SANF_D_NO=item_no
   and   DAT  < tdate  and  STORE_NO=inv_no  ;
   -- and m.TR_INV_TYPE_ID <> 13 
  
  CP:=b;
  return(CP);
  Exception when others then
  return(null);
END;
/

SHOW ERRORS;


DROP VIEW ACCOUNTS.AVVG_ALL;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.AVVG_ALL
(I_CODE, ITEM_ID, PART_NO, ITEM_NAME, SNAF_NAME, 
 UOM_CODE, UOM_ID, COUNT, INV_ID, INVNAME, 
 SUM_PRICE, STK_COST, SUM_TP, AV1, GROUPNO, 
 GROUP_NAME, TYPE_NO, TYPE_NAME, STYL_NO, STYLE_NAME, 
 CAT, CUR_NO)
AS 
SELECT DISTINCT i_code, p_code item_id, part_no, it_name item_name, a_desc,
                   uom_code, uom_id, 1 COUNT, inv_id, inv_name,
                   ROUND (SUM (p_qty * i_cost), 0) sum_price,max(stk_cost),
                   ROUND (SUM (p_qty), 0) qty,
                   DECODE (SUM (NVL (p_qty, 1)),
                           0, 0,
                           (SUM (p_qty * i_cost)) / SUM (NVL (p_qty, 1))
                          ) average,
                   groupno, group_name, type_no, type_name, styl_no,
                   style_name, cat, cur_no
              FROM item_movement_d
             WHERE 1 = 1
           -- HAVING SUM (p_qty) > 0 AND SUM (p_qty * i_cost) > 0
                                                              --AND  TR_TYPE=1
          --having  NVL(SUM(b.P_QTY),0) > 0
   GROUP BY        i_code,
                   p_code,
                   part_no,
                   it_name,
                   a_desc,
                   uom_code,
                   uom_id,
                   inv_id,
                   inv_name,
                   groupno,
                   group_name,
                   type_no,
                   type_name,
                   styl_no,
                   style_name,
                   cat,
                   cur_no
--,TR_TYPE;;;;;;


DROP VIEW ACCOUNTS.RASED111;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.RASED111
(I_CODE, ITEM_ID, ITEM_NAME, INV_ID, INVNAME, 
 SUM_TP, SUM_I_TP, SUM_GOOD_QTY, SUM_BAD_QTY, SUM_DAMG_QTY, 
 UOM_CODE, UOM_ID, PSIZE, COUNT, DATE_END, 
 BARACODE, BRANCH_NAME, BRANCH_CAT_ID, G_SIZE, DESC_PERS)
AS 
SELECT DISTINCT i_code, p_code item_id, it_name item_name, inv_id,
                   inv_name, ROUND (SUM (p_qty), 0) qty,
                   ROUND (SUM (p_qty), 0), 0 sum_good_qty, 0 sum_bad_qty,
                   0 sum_damg_qty, uom_code, uom_id, 1 psize, 1 COUNT,
                   NULL date_end, NULL baracode, NULL branch_name,
                   NULL branch_cat_id, NULL g_size, NULL desc_pers
              FROM item_movement_d
             WHERE 1 = 1 AND inv_id <> 11
          --HAVING SUM (p_qty) > 0 AND SUM (p_qty * i_cost) > 0
   GROUP BY        i_code, p_code, it_name, uom_code, uom_id, inv_id,
                   inv_name;


DROP VIEW ACCOUNTS.RASED222;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.RASED222
(I_CODE, ITEM_ID, ITEM_NAME, SUM_TP, SUM_I_TP, 
 SUM_GOOD_QTY, SUM_BAD_QTY, SUM_DAMG_QTY, UOM_CODE, UOM_ID, 
 PSIZE, COUNT, DATE_END, BARACODE, BRANCH_NAME, 
 BRANCH_CAT_ID, G_SIZE, DESC_PERS)
AS 
SELECT DISTINCT i_code, p_code item_id, it_name item_name,
                   ROUND (SUM (p_qty), 0) qty, ROUND (SUM (p_qty), 0),
                   0 sum_good_qty, 0 sum_bad_qty, 0 sum_damg_qty, uom_code,
                   uom_id, 1 psize, 1 COUNT, NULL date_end, NULL baracode,
                   NULL branch_name, NULL branch_cat_id, NULL g_size,
                   NULL desc_pers
              FROM item_movement_d
             WHERE 1 = 1 AND inv_id <> 11
          --HAVING SUM (p_qty) > 0 AND SUM (p_qty * i_cost) > 0
   GROUP BY        i_code, p_code, it_name, uom_code, uom_id;


DROP VIEW ACCOUNTS.RASED__;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.RASED__
(I_CODE, ITEM_ID, ITEM_NAME, SUM_TP, SUM_I_TP, 
 SUM_GOOD_QTY, SUM_BAD_QTY, SUM_DAMG_QTY, UOM_CODE, UOM_ID, 
 PSIZE, COUNT, DATE_END, BARACODE, BRANCH_NAME, 
 BRANCH_CAT_ID, G_SIZE, DESC_PERS)
AS 
SELECT DISTINCT i_code, p_code item_id, it_name item_name,
                   ROUND (SUM (p_qty), 0) qty, ROUND (SUM (p_qty), 0),
                   0 sum_good_qty, 0 sum_bad_qty, 0 sum_damg_qty, uom_code,
                   uom_id, 1 psize, 1 COUNT, NULL date_end, NULL baracode,
                   NULL branch_name, NULL branch_cat_id, NULL g_size,
                   NULL desc_pers
              FROM item_movement_d
             WHERE 1 = 1 AND inv_id <> 11
            HAVING ROUND (SUM (p_qty)) < 0      --AND SUM (p_qty * i_cost) < 0
          GROUP BY i_code, p_code, it_name, uom_code, uom_id;


DROP VIEW ACCOUNTS.LAST_COST;

CREATE OR REPLACE FORCE VIEW ACCOUNTS.LAST_COST
(I_CODE, ITEM_ID, PART_NO, ITEM_NAME, SNAF_NAME, 
 UOM_CODE, UOM_ID, COUNT, SUM_PRICE, SUM_TP, 
 AV1, GROUPNO, GROUP_NAME, TYPE_NO, TYPE_NAME, 
 STYL_NO, STYLE_NAME, CAT, CUR_NO, STK_COST, 
 MAXDATE)
AS 
SELECT DISTINCT maxd.i_code, MAX (p_code) item_id, part_no,
                   a_desc item_name, a_desc, maxd.uom_code, maxd.uom_id,
                   1 COUNT,                       --maxd.inv_id, maxd.invname,
                           ROUND (SUM (p_qty * i_cost), 0) sum_price,
                   ROUND (SUM (p_qty), 0) qty,
                   DECODE (SUM (NVL (p_qty, 1)),
                           0, 0,
                           (SUM (p_qty * i_cost)) / SUM (NVL (p_qty, 1))
                          ) average,
                   groupno, group_name, type_no, type_name, styl_no,
                   style_name, cat, cur_no, MAX (stk_cost), MAX (i_date)
              FROM item_movement_d itd, last_date maxd
             WHERE 1 = 1
               --  HAVING SUM (p_qty) > 0 AND SUM (p_qty * i_cost) > 0
               AND p_qty > 0
               AND itd.inv_id <> 11
               AND itd.i_date = maxd.maxdate
               AND itd.i_code = maxd.i_code
               AND BILL_DOC_TYPE <> 1
          --  AND itd.inv_id = maxd.inv_id
   GROUP BY        maxd.i_code,
                   part_no,
                   a_desc,
                   a_desc,
                   maxd.uom_code,
                   maxd.uom_id,
                   --   maxd.inv_id,
                     -- maxd.invname,
                   groupno,
                   group_name,
                   type_no,
                   type_name,
                   styl_no,
                   style_name,
                   cat,
                   cur_no
--,TR_TYPE;;;;;;;;;;;;;;;;


