     AS LANGUAGE JAVA NAME 'SendMessage.Send(java.lang.String, java.lang.String,java.lang.String, java.lang.String, java.lang.String)return java.lang.String';
 
 FUNCTION SEND_NOTIFICATION(
    P_SERVER_KEY VARCHAR2
  , P_DEVICE_TOKEN VARCHAR2
  , P_TITLE VARCHAR2
  , P_BODY VARCHAR2) RETURN NUMBER  
  AS LANGUAGE JAVA NAME 'FirebaseSender.sendNotification(java.lang.String, java.lang.String, java.lang.String, java.lang.String)return java.lang.int' ;

FUNCTION SEND_WHATSAPP(
    P_SERVER_KEY VARCHAR2
  , P_DEVICE_TOKEN VARCHAR2
  , P_TITLE VARCHAR2
  , P_BODY VARCHAR2) RETURN NUMBER  
  AS LANGUAGE JAVA NAME 'WhatsappSender.sendWhatsapp(java.lang.String, java.lang.String, java.lang.String, java.lang.String)return java.lang.int' ;
PROCEDURE PUSH_QUEUE ; 
 PROCEDURE SET_SEND_ATTEMPT(P_ID NUMBER);  
END MSG_QUEUE_TAPI;
/

