DROP PACKAGE BODY ACCOUNTS.MSG_QUEUE_TAPI;

CREATE OR REPLACE PACKAGE BODY ACCOUNTS.MSG_QUEUE_TAPI IS
V_SEND_ATTEMPT_CNT      NUMBER:=10;
V_TITLE                 VARCHAR2(50):='TITLE';
  PROCEDURE INS_MSG_QUEUE
    (
     P_ID         IN MSG_QUEUE.ID%TYPE
    ,P_MSG_TEXT   IN MSG_QUEUE.MSG_TEXT%TYPE
    ,P_MOBILE_NO  IN MSG_QUEUE.MOBILE_NO%TYPE
    ,P_IS_SENT    IN MSG_QUEUE.IS_SENT%TYPE
    ,P_CREATED_AT IN MSG_QUEUE.CREATED_AT%TYPE
    ,P_CREATED_BY IN MSG_QUEUE.CREATED_BY%TYPE
    ,P_UPDATED_AT IN MSG_QUEUE.UPDATED_AT%TYPE
    ,P_UPDATED_BY IN MSG_QUEUE.UPDATED_BY%TYPE
    ,P_SERVICE_ID IN MSG_QUEUE.SERVICE_ID%TYPE
    ,P_PROVIDER_ID IN MSG_QUEUE.PROVIDER_ID%TYPE
    ,P_CUSTOMER_NAME IN MSG_QUEUE.CUSTOMER_NAME%TYPE DEFAULT NULL
    ) IS
    V_ID NUMBER;
  BEGIN
  SELECT NVL(MAX(ID),0)+1 INTO V_ID FROM MSG_QUEUE;
    INSERT INTO MSG_QUEUE
      (
       ID
      ,MSG_TEXT
      ,MOBILE_NO
      ,IS_SENT
      ,CREATED_AT
      ,CREATED_BY
      ,UPDATED_AT
      ,UPDATED_BY
      ,SERVICE_ID 
      ,PROVIDER_ID
      ,CUSTOMER_NAME
      )
    VALUES
      (
       V_ID
      ,P_MSG_TEXT
      ,P_MOBILE_NO
      ,P_IS_SENT
      ,P_CREATED_AT
      ,P_CREATED_BY
      ,P_UPDATED_AT
      ,P_UPDATED_BY
      ,P_SERVICE_ID 
      ,P_PROVIDER_ID
      ,P_CUSTOMER_NAME
      );
  END INS_MSG_QUEUE;

  PROCEDURE MERGE_MSG_QUEUE
    (
     P_ID         IN MSG_QUEUE.ID%TYPE
    ,P_MSG_TEXT   IN MSG_QUEUE.MSG_TEXT%TYPE
    ,P_MOBILE_NO  IN MSG_QUEUE.MOBILE_NO%TYPE
    ,P_IS_SENT    IN MSG_QUEUE.IS_SENT%TYPE
    ,P_CREATED_AT IN MSG_QUEUE.CREATED_AT%TYPE
    ,P_CREATED_BY IN MSG_QUEUE.CREATED_BY%TYPE
    ,P_UPDATED_AT IN MSG_QUEUE.UPDATED_AT%TYPE
    ,P_UPDATED_BY IN MSG_QUEUE.UPDATED_BY%TYPE
    ,P_SERVICE_ID IN MSG_QUEUE.SERVICE_ID%TYPE
    ,P_PROVIDER_ID IN MSG_QUEUE.PROVIDER_ID%TYPE
    ,P_CUSTOMER_NAME IN MSG_QUEUE.CUSTOMER_NAME%TYPE DEFAULT NULL
    ) IS
  BEGIN
    MERGE INTO MSG_QUEUE A USING
      (SELECT
       P_ID as ID
      ,P_MSG_TEXT as MSG_TEXT
      ,P_MOBILE_NO as MOBILE_NO
      ,P_IS_SENT as IS_SENT
      ,P_CREATED_AT as CREATED_AT
      ,P_CREATED_BY as CREATED_BY
      ,P_UPDATED_AT as UPDATED_AT
      ,P_UPDATED_BY as UPDATED_BY
      ,P_SERVICE_ID  AS SERVICE_ID
      ,P_PROVIDER_ID AS PROVIDER_ID
      ,P_CUSTOMER_NAME AS CUSTOMER_NAME
      FROM DUAL) B
    ON (A.ID= B.ID)
    WHEN NOT MATCHED THEN
      INSERT (
       ID
      ,MSG_TEXT
      ,MOBILE_NO
      ,IS_SENT
      ,CREATED_AT
      ,CREATED_BY
      ,UPDATED_AT
      ,UPDATED_BY
      ,SERVICE_ID 
      ,PROVIDER_ID
      ,CUSTOMER_NAME
      )
      VALUES
      (P_ID
      ,P_MSG_TEXT
      ,P_MOBILE_NO
      ,P_IS_SENT
      ,P_CREATED_AT
      ,P_CREATED_BY
      ,P_UPDATED_AT
      ,P_UPDATED_BY
      ,P_SERVICE_ID 
      ,P_PROVIDER_ID
      ,P_CUSTOMER_NAME
      )
    WHEN MATCHED THEN
      UPDATE SET
         A.MSG_TEXT = B.MSG_TEXT
        ,A.MOBILE_NO = B.MOBILE_NO
        ,A.IS_SENT = B.IS_SENT
        ,A.CREATED_AT = B.CREATED_AT
        ,A.CREATED_BY = B.CREATED_BY
        ,A.UPDATED_AT = B.UPDATED_AT
        ,A.UPDATED_BY = B.UPDATED_BY
        ,A.SERVICE_ID =B.SERVICE_ID
        ,A.PROVIDER_ID=B.PROVIDER_ID
        ,A.CUSTOMER_NAME=B.CUSTOMER_NAME
        ;
  END MERGE_MSG_QUEUE;

  PROCEDURE UPD_MSG_QUEUE
    (
     P_ID         IN MSG_QUEUE.ID%TYPE
    ,P_MSG_TEXT   IN MSG_QUEUE.MSG_TEXT%TYPE
    ,P_MOBILE_NO  IN MSG_QUEUE.MOBILE_NO%TYPE
    ,P_IS_SENT    IN MSG_QUEUE.IS_SENT%TYPE
    ,P_CREATED_AT IN MSG_QUEUE.CREATED_AT%TYPE
    ,P_CREATED_BY IN MSG_QUEUE.CREATED_BY%TYPE
    ,P_UPDATED_AT IN MSG_QUEUE.UPDATED_AT%TYPE
    ,P_UPDATED_BY IN MSG_QUEUE.UPDATED_BY%TYPE
    ,P_SERVICE_ID IN MSG_QUEUE.SERVICE_ID%TYPE
    ,P_PROVIDER_ID IN MSG_QUEUE.PROVIDER_ID%TYPE
    ,P_CUSTOMER_NAME IN MSG_QUEUE.CUSTOMER_NAME%TYPE DEFAULT NULL
    ) IS
  BEGIN
    UPDATE MSG_QUEUE
    SET 
        MSG_TEXT    = P_MSG_TEXT
       ,MOBILE_NO   = P_MOBILE_NO
       ,IS_SENT     = P_IS_SENT
       ,CREATED_AT  = P_CREATED_AT
       ,CREATED_BY  = P_CREATED_BY
       ,UPDATED_AT  = P_UPDATED_AT
       ,UPDATED_BY  = P_UPDATED_BY
       ,SERVICE_ID  = P_SERVICE_ID 
       ,PROVIDER_ID = P_PROVIDER_ID
       ,CUSTOMER_NAME =P_CUSTOMER_NAME
       
    WHERE
        ID          = P_ID;
  END UPD_MSG_QUEUE;

  PROCEDURE DEL_MSG_QUEUE
    (
     P_ID         IN MSG_QUEUE.ID%TYPE
    ) IS
  BEGIN
    DELETE FROM MSG_QUEUE
    WHERE
        ID          = P_ID;
  END DEL_MSG_QUEUE;
PROCEDURE SET_MSG_SENT
    (
     P_ID         IN MSG_QUEUE.ID%TYPE
    ,P_UPDATED_AT IN MSG_QUEUE.UPDATED_AT%TYPE
    ,P_UPDATED_BY IN MSG_QUEUE.UPDATED_BY%TYPE
    )AS 
    V_ARCHIVE NUMBER;
    BEGIN
        UPDATE MSG_QUEUE
    SET 
        IS_SENT     = 'Y'
       ,UPDATED_AT  = P_UPDATED_AT
       ,UPDATED_BY  = P_UPDATED_BY
    WHERE
        ID          = P_ID;
    COMMIT;
    
    END;

   
    PROCEDURE PUSH_QUEUE AS
    V_FIREBASE_RETURN_VALUE     NUMBER;
    V_WHATSAPP_RETURN_VALUE     NUMBER;
    V_URL                       VARCHAR2(4000);
    V_SMS_RETURN_VALUE          VARCHAR2(1000);
    BEGIN
    
        FOR I IN (SELECT ID ,MSG_TEXT ,MOBILE_NO ,PROVIDER_ID,SERVICE_ID ,SEND_ATTEMPT FROM MSG_QUEUE WHERE UPPER(IS_SENT) ='N' 
            --AND SEND_ATTEMPT <= V_SEND_ATTEMPT_CNT 
            ) LOOP
        
            FOR P IN (SELECT PROVIDER_ID ,USER_NAME,PASSWORD ,URL,TOKEN,
            (SELECT SERVICE_TYPE FROM SERVICES WHERE SERVICE_ID=D.SERVICE_ID) SERVICE_TYPE 
                FROM PROVIDERS_DTL D 
                WHERE  STATUS =1 AND I.SEND_ATTEMPT <= D.SEND_ATTEMPT_CNT
                AND PROVIDER_ID =NVL(I.PROVIDER_ID,D.PROVIDER_ID) AND SERVICE_ID=NVL(I.SERVICE_ID,SERVICE_ID) )LOOP
            V_URL:=REPLACE(P.URL,'#USERNAME#',P.USER_NAME);
            V_URL:=REPLACE(V_URL,'#PASSWORD#',P.PASSWORD);
            V_URL:=REPLACE(V_URL,'#MESSAGE#',I.MSG_TEXT);
            V_URL:=REPLACE(V_URL,'#PHONE_NO#',I.MOBILE_NO);
           
            DBMS_OUTPUT.PUT_LINE(V_URL);
        
            IF P.SERVICE_TYPE ='URL' THEN
            V_SMS_RETURN_VALUE:='';
            V_SMS_RETURN_VALUE:= SEND_MSG
                (
                 P_MSG_TEXT   =>I.MSG_TEXT
                ,P_MOBILE_NO  =>TO_CHAR(I.MOBILE_NO)
                ,P_USER_NAME  =>P.USER_NAME
                ,P_PASSWORD   =>P.PASSWORD
                ,P_URL        =>V_URL); 
                DBMS_OUTPUT.PUT_LINE(V_SMS_RETURN_VALUE);   
            ELSIF P.SERVICE_TYPE ='FIREBASE' THEN  -- FOR FIREBASE 
                  V_FIREBASE_RETURN_VALUE:=0;
                  V_FIREBASE_RETURN_VALUE:=  SEND_NOTIFICATION(P.USER_NAME , NVL(P.TOKEN,P.PASSWORD),I.MOBILE_NO, I.MSG_TEXT);
                  DBMS_OUTPUT.PUT_LINE(V_FIREBASE_RETURN_VALUE);   
            ELSIF P.SERVICE_TYPE ='WHATSAPP' THEN  -- FOR WHATSAPP
                  V_WHATSAPP_RETURN_VALUE:=0;
                  V_WHATSAPP_RETURN_VALUE:=  SEND_WHATSAPP(P.USER_NAME , NVL(P.TOKEN,P.PASSWORD),I.MOBILE_NO, I.MSG_TEXT);
                  DBMS_OUTPUT.PUT_LINE(V_WHATSAPP_RETURN_VALUE);   
            END IF;
            SET_SEND_ATTEMPT(P_ID =>I.ID);
           IF V_WHATSAPP_RETURN_VALUE = 200 OR V_FIREBASE_RETURN_VALUE = 200 OR ( INSTR(LOWER(V_SMS_RETURN_VALUE),'0000' )>0 
                OR INSTR(LOWER(V_SMS_RETURN_VALUE),'success' )>0  
                OR INSTR(LOWER(V_SMS_RETURN_VALUE),'duplicated' )>0)
           THEN
                        SET_MSG_SENT(
                             P_ID         =>I.ID
                            ,P_UPDATED_AT =>SYSDATE
                            ,P_UPDATED_BY =>USER
                            );
            END IF;
             
            END LOOP; --END PROVIDERS LOOP
            MSG_ARCHIVE_TAPI.ARCHIVE_MSG
                    (
                     P_ID         =>I.ID
                    ,P_UPDATED_AT =>SYSDATE
                    ,P_UPDATED_BY =>USER
                    );
            
        END LOOP; --END MSQ QUEUE LOOP
    END PUSH_QUEUE;
    
    
 FUNCTION SEND_MSG
    (
     P_ID         IN MSG_QUEUE.ID%TYPE
    ,P_MSG_TEXT   IN MSG_QUEUE.MSG_TEXT%TYPE
    ,P_MOBILE_NO  IN MSG_QUEUE.MOBILE_NO%TYPE
    ,P_URL        IN VARCHAR2
    ) RETURN BOOLEAN AS
    BEGIN
        RETURN TRUE;
    END SEND_MSG;
    
 PROCEDURE SET_SEND_ATTEMPT(P_ID NUMBER)AS
 BEGIN
    UPDATE MSG_QUEUE SET SEND_ATTEMPT=NVL(SEND_ATTEMPT,0)+1 WHERE ID=P_ID;
 END ;
END MSG_QUEUE_TAPI;
/

SHOW ERRORS;


DROP PACKAGE BODY ACCOUNTS.MSG_ARCHIVE_TAPI;

CREATE OR REPLACE PACKAGE BODY ACCOUNTS.MSG_ARCHIVE_TAPI IS

  PROCEDURE INS_MSG_ARCHIVE
    (
     P_ID            IN MSG_ARCHIVE.ID%TYPE
    ,P_MSG_TEXT      IN MSG_ARCHIVE.MSG_TEXT%TYPE
    ,P_MOBILE_NO     IN MSG_ARCHIVE.MOBILE_NO%TYPE
    ,P_IS_SENT       IN MSG_ARCHIVE.IS_SENT%TYPE
    ,P_CREATED_AT    IN MSG_ARCHIVE.CREATED_AT%TYPE
    ,P_CREATED_BY    IN MSG_ARCHIVE.CREATED_BY%TYPE
    ,P_UPDATED_AT    IN MSG_ARCHIVE.UPDATED_AT%TYPE
    ,P_UPDATED_BY    IN MSG_ARCHIVE.UPDATED_BY%TYPE
    ,P_SERVICE_ID    IN MSG_ARCHIVE.SERVICE_ID%TYPE
    ,P_PROVIDER_ID   IN MSG_ARCHIVE.PROVIDER_ID%TYPE
    ,P_CUSTOMER_NAME IN MSG_ARCHIVE.CUSTOMER_NAME%TYPE
    ,P_SEND_ATTEMPT  IN MSG_ARCHIVE.SEND_ATTEMPT%TYPE
    ) IS
  BEGIN
    INSERT INTO MSG_ARCHIVE
      (
       ID
      ,MSG_TEXT
      ,MOBILE_NO
      ,IS_SENT
      ,CREATED_AT
      ,CREATED_BY
      ,UPDATED_AT
      ,UPDATED_BY
      ,SERVICE_ID
      ,PROVIDER_ID
      ,CUSTOMER_NAME
      ,SEND_ATTEMPT
      )
    VALUES
      (
       P_ID
      ,P_MSG_TEXT
      ,P_MOBILE_NO
      ,P_IS_SENT
      ,P_CREATED_AT
      ,P_CREATED_BY
      ,P_UPDATED_AT
      ,P_UPDATED_BY
      ,P_SERVICE_ID
      ,P_PROVIDER_ID
      ,P_CUSTOMER_NAME
      ,P_SEND_ATTEMPT
      );
  END INS_MSG_ARCHIVE;

  PROCEDURE MERGE_MSG_ARCHIVE
    (
     P_ID            IN MSG_ARCHIVE.ID%TYPE
    ,P_MSG_TEXT      IN MSG_ARCHIVE.MSG_TEXT%TYPE
    ,P_MOBILE_NO     IN MSG_ARCHIVE.MOBILE_NO%TYPE
    ,P_IS_SENT       IN MSG_ARCHIVE.IS_SENT%TYPE
    ,P_CREATED_AT    IN MSG_ARCHIVE.CREATED_AT%TYPE
    ,P_CREATED_BY    IN MSG_ARCHIVE.CREATED_BY%TYPE
    ,P_UPDATED_AT    IN MSG_ARCHIVE.UPDATED_AT%TYPE
    ,P_UPDATED_BY    IN MSG_ARCHIVE.UPDATED_BY%TYPE
    ,P_SERVICE_ID    IN MSG_ARCHIVE.SERVICE_ID%TYPE
    ,P_PROVIDER_ID   IN MSG_ARCHIVE.PROVIDER_ID%TYPE
    ,P_CUSTOMER_NAME IN MSG_ARCHIVE.CUSTOMER_NAME%TYPE
    ,P_SEND_ATTEMPT  IN MSG_ARCHIVE.SEND_ATTEMPT%TYPE
    ) IS
  BEGIN
    MERGE INTO MSG_ARCHIVE A USING
      (SELECT
       P_ID as ID
      ,P_MSG_TEXT as MSG_TEXT
      ,P_MOBILE_NO as MOBILE_NO
      ,P_IS_SENT as IS_SENT
      ,P_CREATED_AT as CREATED_AT
      ,P_CREATED_BY as CREATED_BY
      ,P_UPDATED_AT as UPDATED_AT
      ,P_UPDATED_BY as UPDATED_BY
      ,P_SERVICE_ID as SERVICE_ID
      ,P_PROVIDER_ID as PROVIDER_ID
      ,P_CUSTOMER_NAME as CUSTOMER_NAME
      ,P_SEND_ATTEMPT as SEND_ATTEMPT
      FROM DUAL) B
    ON (A.ID= B.ID)
    WHEN NOT MATCHED THEN
      INSERT (
       ID
      ,MSG_TEXT
      ,MOBILE_NO
      ,IS_SENT
      ,CREATED_AT
      ,CREATED_BY
      ,UPDATED_AT
      ,UPDATED_BY
      ,SERVICE_ID
      ,PROVIDER_ID
      ,CUSTOMER_NAME
      ,SEND_ATTEMPT)
      VALUES
      (P_ID
      ,P_MSG_TEXT
      ,P_MOBILE_NO
      ,P_IS_SENT
      ,P_CREATED_AT
      ,P_CREATED_BY
      ,P_UPDATED_AT
      ,P_UPDATED_BY
      ,P_SERVICE_ID
      ,P_PROVIDER_ID
      ,P_CUSTOMER_NAME
      ,P_SEND_ATTEMPT)
    WHEN MATCHED THEN
      UPDATE SET
         A.MSG_TEXT = B.MSG_TEXT
        ,A.MOBILE_NO = B.MOBILE_NO
        ,A.IS_SENT = B.IS_SENT
        ,A.CREATED_AT = B.CREATED_AT
        ,A.CREATED_BY = B.CREATED_BY
        ,A.UPDATED_AT = B.UPDATED_AT
        ,A.UPDATED_BY = B.UPDATED_BY
        ,A.SERVICE_ID = B.SERVICE_ID
        ,A.PROVIDER_ID = B.PROVIDER_ID
        ,A.CUSTOMER_NAME = B.CUSTOMER_NAME
        ,A.SEND_ATTEMPT = B.SEND_ATTEMPT;
  END MERGE_MSG_ARCHIVE;

  PROCEDURE UPD_MSG_ARCHIVE
    (
     P_ID            IN MSG_ARCHIVE.ID%TYPE
    ,P_MSG_TEXT      IN MSG_ARCHIVE.MSG_TEXT%TYPE
    ,P_MOBILE_NO     IN MSG_ARCHIVE.MOBILE_NO%TYPE
    ,P_IS_SENT       IN MSG_ARCHIVE.IS_SENT%TYPE
    ,P_CREATED_AT    IN MSG_ARCHIVE.CREATED_AT%TYPE
    ,P_CREATED_BY    IN MSG_ARCHIVE.CREATED_BY%TYPE
    ,P_UPDATED_AT    IN MSG_ARCHIVE.UPDATED_AT%TYPE
    ,P_UPDATED_BY    IN MSG_ARCHIVE.UPDATED_BY%TYPE
    ,P_SERVICE_ID    IN MSG_ARCHIVE.SERVICE_ID%TYPE
    ,P_PROVIDER_ID   IN MSG_ARCHIVE.PROVIDER_ID%TYPE
    ,P_CUSTOMER_NAME IN MSG_ARCHIVE.CUSTOMER_NAME%TYPE
    ,P_SEND_ATTEMPT  IN MSG_ARCHIVE.SEND_ATTEMPT%TYPE
    ) IS
  BEGIN
    UPDATE MSG_ARCHIVE
    SET 
        MSG_TEXT       = P_MSG_TEXT
       ,MOBILE_NO      = P_MOBILE_NO
       ,IS_SENT        = P_IS_SENT
       ,CREATED_AT     = P_CREATED_AT
       ,CREATED_BY     = P_CREATED_BY
       ,UPDATED_AT     = P_UPDATED_AT
       ,UPDATED_BY     = P_UPDATED_BY
       ,SERVICE_ID     = P_SERVICE_ID
       ,PROVIDER_ID    = P_PROVIDER_ID
       ,CUSTOMER_NAME  = P_CUSTOMER_NAME
       ,SEND_ATTEMPT   = P_SEND_ATTEMPT
    WHERE
        ID             = P_ID;
  END UPD_MSG_ARCHIVE;

  PROCEDURE DEL_MSG_ARCHIVE
    (
     P_ID            IN MSG_ARCHIVE.ID%TYPE
    ) IS
  BEGIN
    DELETE FROM MSG_ARCHIVE
    WHERE
        ID             = P_ID;
  END DEL_MSG_ARCHIVE;
PROCEDURE ARCHIVE_MSG
    (
     P_ID         IN MSG_QUEUE.ID%TYPE
    ,P_UPDATED_AT IN MSG_QUEUE.UPDATED_AT%TYPE
    ,P_UPDATED_BY IN MSG_QUEUE.UPDATED_BY%TYPE
    )AS 
    V_ARCHIVE NUMBER;
    BEGIN
    
    SELECT COUNT(*) INTO V_ARCHIVE FROM PROVIDERS_DTL D 
        WHERE NVL(SENT_ARCHIVE,0)=1 AND PROVIDER_ID IN (SELECT NVL(Q.PROVIDER_ID,D.PROVIDER_ID) FROM MSG_QUEUE Q WHERE ID =P_ID AND IS_SENT ='Y'
        AND NVL(Q.SERVICE_ID ,D.SERVICE_ID)=D.SERVICE_ID
        --SEND_ATTEMPT >= D.SEND_ATTEMPT_CNT
        );
    IF V_ARCHIVE >=1 THEN

       INSERT INTO MSG_ARCHIVE (
           ID, MSG_TEXT, MOBILE_NO, 
           IS_SENT, CREATED_AT, CREATED_BY, 
           UPDATED_AT, UPDATED_BY, SERVICE_ID, 
           PROVIDER_ID, CUSTOMER_NAME, SEND_ATTEMPT) 
        SELECT 
           ID, MSG_TEXT, MOBILE_NO, 
           IS_SENT, CREATED_AT, CREATED_BY, 
           UPDATED_AT, UPDATED_BY, SERVICE_ID, 
           PROVIDER_ID, CUSTOMER_NAME, SEND_ATTEMPT
           FROM MSG_QUEUE WHERE ID=P_ID; 
           MSG_QUEUE_TAPI.DEL_MSG_QUEUE (P_ID =>P_ID) ;
            COMMIT;
    END IF;
 END ARCHIVE_MSG; 
   
    
END MSG_ARCHIVE_TAPI;
/

